p\":\"0\"}}}} --><p style=\"color:#5E7580;font-size:14px;margin-top:0\">Typical quote turnaround</p><!-- /wp:paragraph -->\n</div><!-- /wp:column -->\n</div><!-- /wp:columns -->\n</div>\n<!-- /wp:group -->\n\n\n<!-- wp:group {\"align\":\"full\",\"className\":\"hydra-sp-section\",\"style\":{\"color\":{\"background\":\"#ffffff\"},\"spacing\":{\"padding\":{\"top\":\"80px\",\"bottom\":\"80px\",\"left\":\"5%\",\"right\":\"5%\"}}},\"layout\":{\"type\":\"constrained\",\"contentSize\":\"1280px\"}} -->\n<div class=\"wp-block-group alignfull hydra-sp-section has-background\" style=\"background-color:#ffffff;padding-top:80px;padding-bottom:80px;padding-left:5%;padding-right:5%\">\n\n<!-- wp:html -->\n<div class=\"hydra-sp-inner\">\n\n  <div class=\"hydra-sp-label\">SERVICES &amp; PRODUCTS &mdash; 10 PAGES</div>\n\n  <h2 class=\"hydra-sp-h2\">Everything HYDRA offers</h2>\n\n  <p class=\"hydra-sp-sub\">Each page targets one primary keyword. Click any card to view the full page.</p>\n\n  <div class=\"hydra-sp-grid\">\n\n    <!-- Card 1: Temperature Mapping -->\n    <a href=\"/services/temperature-mapping-saudi-arabia/\" class=\"hydra-sp-card\">\n      <div class=\"hydra-sp-img\" style=\"background:#E8F4F8\">\n        <svg width=\"48\" height=\"48\" viewBox=\"0 0 48 48\" fill=\"none\" stroke=\"#016B7A\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><rect x=\"5\" y=\"28\" width=\"9\" height=\"13\" rx=\"1.5\"/><rect x=\"19.5\" y=\"18\" width=\"9\" height=\"23\" rx=\"1.5\"/><circle cx=\"37\" cy=\"15\" r=\"8\"/><polyline points=\"37,11 37,15 40,17\"/></svg>      </div>\n      <div class=\"hydra-sp-body\">\n        <h3>Temperature Mapping</h3>\n        <div class=\"hydra-sp-chips\">\n          <span class=\"hydra-chip hydra-chip--h1\"><span class=\"hydra-chip-dot\"></span>temperature mapping services Saudi Arabia</span>\n          <span class=\"hydra-chip hydra-chip--h2\"><span class=\"hydra-chip-dot hydra-chip-dot--gray\"></span>warehouse temperature mapping</span>\n        </div>\n        <p>Warehouse, cold room, reefer vehicle and freezer mapping — SFDA and WHO GDP compliant.</p>\n        <span class=\"hydra-sp-cta\">View page &rarr;</span>\n      </div>\n    </a>\n\n    <!-- Card 2: Validation & Qualification -->\n    <a href=\"/services/validation-qualification-services/\" class=\"hydra-sp-card\">\n      <div class=\"hydra-sp-img\" style=\"background:#EAF4EA\">\n        <svg width=\"48\" height=\"48\" viewBox=\"0 0 48 48\" fill=\"none\" stroke=\"#1D7A4F\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><rect x=\"10\" y=\"8\" width=\"28\" height=\"34\" rx=\"3\"/><rect x=\"17\" y=\"4\" width=\"14\" height=\"7\" rx=\"2\"/><path d=\"M17 22l3.5 3.5L29 17\"/><path d=\"M17 32l3.5 3.5L29 27\"/></svg>      </div>\n      <div class=\"hydra-sp-body\">\n        <h3>Validation &amp; Qualification</h3>\n        <div class=\"hydra-sp-chips\">\n          <span class=\"hydra-chip hydra-chip--h1\"><span class=\"hydra-chip-dot\"></span>validation and qualification services Saudi Arabia</span>\n          <span class=\"hydra-chip hydra-chip--h2\"><span class=\"hydra-chip-dot hydra-chip-dot--gray\"></span>cold chain validation services</span>\n        </div>\n        <p>IQ/OQ/PQ for cold storage, pharma equipment and warehouses.</p>\n        <span class=\"hydra-sp-cta\">View page &rarr;</span>\n      </div>\n    </a>\n\n    <!-- Card 3: GDP & Regulatory Compliance -->\n    <a href=\"/services/gdp-compliance-saudi-arabia/\" class=\"hydra-sp-card\">\n      <div class=\"hydra-sp-img\" style=\"background:#E8EEF8\">\n        <svg width=\"48\" height=\"48\" viewBox=\"0 0 48 48\" fill=\"none\" stroke=\"#185FA5\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M24 4 L40 14 L40 34 Q40 42 24 44 Q8 42 8 34 L8 14 Z\"/><path d=\"M17 24l4.5 4.5L32 18\"/></svg>      </div>\n      <div class=\"hydra-sp-body\">\n        <h3>GDP &amp; Regulatory Compliance</h3>\n        <div class=\"hydra-sp-chips\">\n  