-column\" style=\"padding-left:32px\">\n<!-- wp:heading {\"level\":3,\"style\":{\"color\":{\"text\":\"#016B7A\"},\"typography\":{\"fontSize\":\"44px\",\"fontFamily\":\"\'DM Serif Display\',serif\",\"fontWeight\":\"400\",\"lineHeight\":\"1\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"6px\"}}}} --><h3 class=\"wp-block-heading\" style=\"color:#016B7A;font-family:\'DM Serif Display\',serif;font-size:44px;font-weight:400;line-height:1;margin-top:0;margin-bottom:6px\">48hr</h3><!-- /wp:heading -->\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#5E7580\"},\"typography\":{\"fontSize\":\"14px\"},\"spacing\":{\"margin\":{\"top\":\"0\"}}}} --><p style=\"color:#5E7580;font-size:14px;margin-top:0\">Typical quote turnaround</p><!-- /wp:paragraph -->\n</div><!-- /wp:column -->\n</div><!-- /wp:columns -->\n</div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"align\":\"full\",\"style\":{\"color\":{\"background\":\"#F5F8F9\"},\"spacing\":{\"padding\":{\"top\":\"80px\",\"bottom\":\"80px\",\"left\":\"24px\",\"right\":\"24px\"}}},\"layout\":{\"type\":\"constrained\",\"contentSize\":\"1100px\"}} -->\n<div class=\"wp-block-group alignfull has-background\" style=\"background-color:#F5F8F9;padding-top:80px;padding-bottom:80px;padding-left:24px;padding-right:24px\">\n<!-- wp:heading {\"level\":2,\"textAlign\":\"center\",\"style\":{\"color\":{\"text\":\"#0C1E28\"},\"typography\":{\"fontSize\":\"clamp(28px,4vw,40px)\",\"fontFamily\":\"\'DM Serif Display\',serif\",\"fontWeight\":\"400\",\"lineHeight\":\"1.2\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"12px\"}}}} -->\n<h2 class=\"wp-block-heading has-text-align-center\" style=\"color:#0C1E28;font-family:\'DM Serif Display\',serif;font-size:clamp(28px,4vw,40px);font-weight:400;line-height:1.2;margin-top:0;margin-bottom:12px\">Everything your compliance programme needs</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"color\":{\"text\":\"#5E7580\"},\"typography\":{\"fontSize\":\"15px\",\"lineHeight\":\"1.7\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"56px\"}}}} -->\n<p class=\"has-text-align-center\" style=\"color:#5E7580;font-size:15px;line-height:1.7;margin-top:0;margin-bottom:56px\">Nine specialist services. One Jeddah-based team. No international consultant fees.</p>\n<!-- /wp:paragraph -->\n<!-- wp:html -->\n<div class=\"hydra-services-grid\">\n\n<div class=\"hydra-card\">\n<div class=\"hydra-card-icon\">🌡️</div>\n<h3>Temperature Mapping</h3>\n<p>Validated chamber, warehouse, vehicle mapping per SFDA/WHO GDP</p>\n<a href=\"/services/temperature-mapping-saudi-arabia/\">Learn more →</a>\n</div>\n\n<div class=\"hydra-card\">\n<div class=\"hydra-card-icon\">✅</div>\n<h3>Validation &amp; Qualification</h3>\n<p>IQ/OQ/PQ for equipment, utilities, facilities</p>\n<a href=\"/services/validation-qualification-services/\">Learn more →</a>\n</div>\n\n<div class=\"hydra-card\">\n<div class=\"hydra-card-icon\">📋</div>\n<h3>GDP Compliance</h3>\n<p>Full WHO/EU GDP consulting for distributors and 3PL</p>\n<a href=\"/services/gdp-compliance-saudi-arabia/\">Learn more →</a>\n</div>\n\n<div class=\"hydra-card\">\n<div class=\"hydra-card-icon\">🏥</div>\n<h3>Pharma Consulting</h3>\n<p>Regulatory strategy and SFDA dossier support</p>\n<a href=\"/services/pharmaceutical-consulting-saudi-arabia/\">Learn more →</a>\n</div>\n\n<div class=\"hydra-card\">\n<div class=\"hydra-card-icon\">🏭</div>\n<h3>Cold Storage Compliance</h3>\n<p>Qualification and compliance for pharma cold stores</p>\n<a href=\"/services/cold-storage-compliance/\">Learn more →</a>\n</div>\n\n<div class=\"hydra-card\">\n<div class=\"hydra-card-icon\">📊</div>\n<h3>Pharma QMS</h3>\n<p>QMS design, SOP writing, CAPA, internal audits</p>\n<a href=\"/services/pharmaceutical-quality-management-system/\">Learn more →</a>\n</div>\n\n<div class=\"hydra-card\">\n<div class=\"hydra-card-icon\">📦</div>\n<h3>Thermal Packaging</h3>\n<p>GDP-qualified thermal packaging validation</p>\n<a href=\"/services/thermal-packaging-validation/\">Learn more →</a>\n</div>\n\n<div class=\"hydra-card\">\n<div class=\"hydra-card-icon\">💻</div>\n<h3>Computer System Validation</h3>\n<p>GAMP 5, 21 CFR Part 11, EU Annex 11</p>\n<a href=\"/services/computer-system-validation-saudi-arabia/\">Learn more →</a>\n</div>\n\n<div class=\"hydra-card\">\n<div class=\"hydra-card-icon\">❄️</div>\n<h3>Cold Chain Solutions</h3>\n<p>End-to-end GDP transport and cold chain compliance</p>\n<a href=\"/services/cold-chain-solutions-saudi-arabia/\">Learn more →</a>\n</div>\n\n</div>\n<!-- /wp:html -->\n</div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"align\":\"full\",\"style\":{\"color\":{\"background\":\"#E0F4F7\"},\"spacing\":{\"padding\":{\"top\":\"80px\",\"bottom\":\"80px\",\"left\":\"24px\",\"right\":\"24px\"}}},\"layout\":{\"type\":\"constrained\",\"contentSize\":\"1100px\"}} -->\n<div class=\"wp-block-group alignfull has-background\" style=\"background-color:#E0F4F7;padding-top:80px;padding-bottom:80px;padding-left:24px;padding-right:24px\">\n<!-- wp:heading {\"level\":2,\"textAlign\":\"center\",\"style\":{\"color\":{\"text\":\"#014F59\"},\"typography\":{\"fontSize\":\"clamp(24px,3.5vw,36px)\",\"fontFamily\":\"\'DM Serif Display\',serif\",\"fontWeight\":\"400\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"48px\"}}}} -->\n<h2 class=\"wp-block-heading has-text-align-center\" style=\"color:#014F59;font-family:\'DM Serif Display\',serif;font-size:clamp(24px,3.5vw,36px);font-weight:400;margin-top:0;margin-bottom:48px\">Serving every pharma sector in KSA</h2>\n<!-- /wp:heading -->\n<!-- wp:html -->\n<div class=\"hydra-industries\">\n<div class=\"hydra-industry\"><span>🏗️</span><p>Manufacturers</p></div>\n<div class=\"hydra-industry\"><span>🚚</span><p>Distributors &amp; 3PL</p></div>\n<div class=\"hydra-industry\"><span>🏥</span><p>Hospitals &amp; Pharma</p></div>\n<div class=\"hydra-industry\"><span>🏭</span><p>Cold Storage</p></div>\n<div class=\"hydra-industry\"><span>🔬</span><p>Clinical Research</p></div>\n<div class=\"hydra-industry\"><span>🩺</span><p>MedTech</p></div>\n</div>\n<!-- /wp:html -->\n</div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"align\":\"full\",\"style\":{\"color\":{\"background\":\"#ffffff\"},\"spacing\":{\"padding\":{\"top\":\"80px\",\"bottom\":\"80px\",\"left\":\"24px\",\"right\":\"24px\"}}},\"layout\":{\"type\":\"constrained\",\"contentSize\":\"800px\"}} -->\n<div class=\"wp-block-group alignfull has-white-background-color has-background\" style=\"background-color:#ffffff;padding-top:80px;padding-bottom:80px;padding-left:24px;padding-right:24px\">\n<!-- wp:heading {\"level\":2,\"textAlign\":\"center\",\"style\":{\"color\":{\"text\":\"#0C1E28\"},\"typography\":{\"fontSize\":\"clamp(24px,3.5vw,36px)\",\"fontFamily\":\"\'DM Serif Display\',serif\",\"fontWeight\":\"400\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"40px\"}}}} -->\n<h2 class=\"wp-block-heading has-text-align-center\" style=\"color:#0C1E28;font-family:\'DM Serif Display\',serif;font-size:clamp(24px,3.5vw,36px);font-weight:400;margin-top:0;margin-bottom:40px\">Common questions</h2>\n<!-- /wp:heading -->\n<!-- wp:details {\"style\":{\"border\":{\"bottom\":{\"color\":\"#E0EAF0\",\"style\":\"solid\",\"width\":\"1px\"}},\"spacing\":{\"padding\":{\"top\":\"20px\",\"bottom\":\"20px\"}}}} -->\n<details class=\"wp-block-details\" style=\"border-bottom:1px solid #E0EAF0;padding-top:20px;padding-bottom:20px\"><summary style=\"font-family:\'DM Sans\',sans-serif;font-size:16px;font-weight:600;color:#0C1E28;cursor:pointer\">What is temperature mapping and why do I need it?</summary><!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#5E7580\"},\"typography\":{\"fontSize\":\"15px\",\"lineHeight\":\"1.7\"},\"spacing\":{\"margin\":{\"top\":\"12px\"}}}} --><p style=\"color:#5E7580;font-size:15px;line-height:1.7;margin-top:12px\">Temperature mapping is a validated study that proves your storage or transport environment stays within required limits (typically 2–8 °C or 15–25 °C) under real-world conditions. SFDA and WHO GDP require mapped, qualified storage for all pharmaceutical products.</p><!-- /wp:paragraph --></details>\n<!-- /wp:details -->\n<!-- wp:details {\"style\":{\"border\":{\"bottom\":{\"color\":\"#E0EAF0\",\"style\":\"solid\",\"width\":\"1px\"}},\"spacing\":{\"padding\":{\"top\":\"20px\",\"bottom\":\"20px\"}}}} -->\n<details class=\"wp-block-details\" style=\"border-bottom:1px solid #E0EAF0;padding-top:20px;padding-bottom:20px\"><summary style=\"font-family:\'DM Sans\',sans-serif;font-size:16px;font-weight:600;color:#0C1E28;cursor:pointer\">How long does a temperature mapping study take?</summary><!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#5E7580\"},\"typography\":{\"fontSize\":\"15px\",\"lineHeight\":\"1.7\"},\"spacing\":{\"margin\":{\"top\":\"12px\"}}}} --><p style=\"color:#5E7580;font-size:15px;line-height:1.7;margin-top:12px\">A standard warehouse study takes 5–15 days of data collection plus 3–5 days for the report. Chamber mapping is typically 3–7 days. HYDRA delivers a complete validated report ready for SFDA submission.</p><!-- /wp:paragraph --></details>\n<!-- /wp:details -->\n<!-- wp:details {\"style\":{\"border\":{\"bottom\":{\"color\":\"#E0EAF0\",\"style\":\"solid\",\"width\":\"1px\"}},\"spacing\":{\"padding\":{\"top\":\"20px\",\"bottom\":\"20px\"}}}} -->\n<details class=\"wp-block-details\" style=\"border-bottom:1px solid #E0EAF0;padding-top:20px;padding-bottom:20px\"><summary style=\"font-family:\'DM Sans\',sans-serif;font-size:16px;font-weight:600;color:#0C1E28;cursor:pointer\">Do you serve companies outside Jeddah?</summary><!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#5E7580\"},\"typography\":{\"fontSize\":\"15px\",\"lineHeight\":\"1.7\"},\"spacing\":{\"margin\":{\"top\":\"12px\"}}}} --><p style=\"color:#5E7580;font-size:15px;line-height:1.7;margin-top:12px\">Yes. HYDRA operates across all of Saudi Arabia — Riyadh, Dammam, Mecca, Medina, and all regions. We also serve UAE-based companies with KSA operations.</p><!-- /wp:paragraph --></details>\n<!-- /wp:details -->\n<!-- wp:details {\"style\":{\"border\":{\"bottom\":{\"color\":\"#E0EAF0\",\"style\":\"solid\",\"width\":\"1px\"}},\"spacing\":{\"padding\":{\"top\":\"20px\",\"bottom\":\"20px\"}}}} -->\n<details class=\"wp-block-details\" style=\"border-bottom:1px solid #E0EAF0;padding-top:20px;padding-bottom:20px\"><summary style=\"font-family:\'DM Sans\',sans-serif;font-size:16px;font-weight:600;color:#0C1E28;cursor:pointer\">What is the difference between GDP and GMP?</summary><!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#5E7580\"},\"typography\":{\"fontSize\":\"15px\",\"lineHeight\":\"1.7\"},\"spacing\":{\"margin\":{\"top\":\"12px\"}}}} --><p style=\"color:#5E7580;font-size:15px;line-height:1.7;margin-top:12px\">GMP (Good Manufacturing Practice) covers pharmaceutical manufacturing. GDP (Good Distribution Practice) covers storage, handling, and transport of finished pharmaceutical products. HYDRA specialises in GDP — the compliance framework for distributors, 3PL operators, and hospital pharmacies.</p><!-- /wp:paragraph --></details>\n<!-- /wp:details -->\n<!-- wp:details {\"style\":{\"border\":{\"bottom\":{\"color\":\"#E0EAF0\",\"style\":\"solid\",\"width\":\"1px\"}},\"spacing\":{\"padding\":{\"top\":\"20px\",\"bottom\":\"20px\"}}}} -->\n<details class=\"wp-block-details\" style=\"border-bottom:1px solid #E0EAF0;padding-top:20px;padding-bottom:20px\"><summary style=\"font-family:\'DM Sans\',sans-serif;font-size:16px;font-weight:600;color:#0C1E28;cursor:pointer\">How quickly can you start?</summary><!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#5E7580\"},\"typography\":{\"fontSize\":\"15px\",\"lineHeight\":\"1.7\"},\"spacing\":{\"margin\":{\"top\":\"12px\"}}}} --><p style=\"color:#5E7580;font-size:15px;line-height:1.7;margin-top:12px\">We typically respond to enquiries within 24 hours and can mobilise within 3–5 business days depending on service type. Contact us for an urgent requirement.</p><!-- /wp:paragraph --></details>\n<!-- /wp:details -->\n</div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"align\":\"full\",\"className\":\"hydra-cta-banner\",\"style\":{\"color\":{\"background\":\"#016B7A\"},\"spacing\":{\"padding\":{\"top\":\"80px\",\"bottom\":\"80px\",\"left\":\"24px\",\"right\":\"24px\"}}},\"layout\":{\"type\":\"constrained\",\"contentSize\":\"800px\"}} -->\n<div class=\"wp-block-group alignfull hydra-cta-banner has-background\" style=\"background-color:#016B7A;padding-top:80px;padding-bottom:80px;padding-left:24px;padding-right:24px;text-align:center\">\n<!-- wp:heading {\"level\":2,\"textAlign\":\"center\",\"style\":{\"color\":{\"text\":\"#ffffff\"},\"typography\":{\"fontSize\":\"clamp(26px,4vw,40px)\",\"fontFamily\":\"\'DM Serif Display\',serif\",\"fontWeight\":\"400\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"12px\"}}}} -->\n<h2 class=\"wp-block-heading has-text-align-center\" style=\"color:#ffffff;font-family:\'DM Serif Display\',serif;font-size:clamp(26px,4vw,40px);font-weight:400;margin-top:0;margin-bottom:12px\">Ready to start your compliance programme?</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"color\":{\"text\":\"rgba(255,255,255,0.8)\"},\"typography\":{\"fontSize\":\"15px\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"32px\"}}}} -->\n<p class=\"has-text-align-center\" style=\"color:rgba(255,255,255,0.8);font-size:15px;margin-top:0;margin-bottom:32px\">Free consultation · Jeddah · Riyadh · Dammam · all of KSA</p>\n<!-- /wp:paragraph -->\n<!-- wp:buttons {\"layout\":{\"type\":\"flex\",\"justifyContent\":\"center\"}} -->\n<div class=\"wp-block-buttons\">\n<!-- wp:button {\"style\":{\"color\":{\"background\":\"#ffffff\",\"text\":\"#016B7A\"},\"border\":{\"radius\":\"6px\"},\"spacing\":{\"padding\":{\"top\":\"16px\",\"bottom\":\"16px\",\"left\":\"40px\",\"right\":\"40px\"}},\"typography\":{\"fontWeight\":\"700\",\"fontSize\":\"15px\"}}} -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"/contact/\" style=\"background-color:#ffffff;color:#016B7A;border-radius:6px;padding:16px 40px;font-weight:700;font-size:15px\">Get a free quote →</a></div>\n<!-- /wp:button -->\n</div>\n<!-- /wp:buttons -->\n</div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"align\":\"full\",\"className\":\"hydra-footer\",\"style\":{\"color\":{\"background\":\"#0C1E28\"},\"spacing\":{\"padding\":{\"top\":\"64px\",\"bottom\":\"0\",\"left\":\"24px\",\"right\":\"24px\"}}},\"layout\":{\"type\":\"constrained\",\"contentSize\":\"1100px\"}} -->\n<div class=\"wp-block-group alignfull hydra-footer has-background\" style=\"background-color:#0C1E28;padding-top:64px;padding-bottom:0;padding-left:24px;padding-right:24px\">\n<!-- wp:columns {\"style\":{\"spacing\":{\"blockGap\":\"48px\",\"margin\":{\"bottom\":\"48px\"}}}} -->\n<div class=\"wp-block-columns\">\n<!-- wp:column {\"width\":\"40%\"} -->\n<div class=\"wp-block-column\" style=\"flex-basis:40%\">\n<!-- wp:html --><div class=\"hydra-footer-logo\"><span class=\"hydra-logo-hy\">hy</span><span class=\"hydra-logo-text\">Hydra.</span></div><!-- /wp:html -->\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"rgba(255,255,255,0.45)\"},\"typography\":{\"fontSize\":\"13px\",\"lineHeight\":\"1.7\"},\"spacing\":{\"margin\":{\"top\":\"12px\"}}}} -->\n<p style=\"color:rgba(255,255,255,0.45);font-size:13px;line-height:1.7;margin-top:12px\">© 2026 HYDRA Quality &amp; Compliance<br>Jeddah, Saudi Arabia</p>\n<!-- /wp:paragraph -->\n</div><!-- /wp:column -->\n<!-- wp:column {\"width\":\"30%\"} -->\n<div class=\"wp-block-column\" style=\"flex-basis:30%\">\n<!-- wp:heading {\"level\":4,\"style\":{\"color\":{\"text\":\"rgba(255,255,255,0.5)\"},\"typography\":{\"fontSize\":\"11px\",\"fontWeight\":\"700\",\"letterSpacing\":\"0.1em\",\"textTransform\":\"uppercase\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"16px\"}}}} --><h4 class=\"wp-block-heading\" style=\"color:rgba(255,255,255,0.5);font-size:11px;font-weight:700;letter-spacing:0.1em;text-transform:uppercase;margin-top:0;margin-bottom:16px\">Services</h4><!-- /wp:heading -->\n<!-- wp:html -->\n<ul class=\"hydra-footer-links\">\n<li><a href=\"/services/temperature-mapping-saudi-arabia/\">Temperature Mapping</a></li>\n<li><a href=\"/services/validation-qualification-services/\">Validation &amp; Qualification</a></li>\n<li><a href=\"/services/gdp-compliance-saudi-arabia/\">GDP Compliance</a></li>\n<li><a href=\"/services/pharmaceutical-consulting-saudi-arabia/\">Pharma Consulting</a></li>\n<li><a href=\"/services/cold-storage-compliance/\">Cold Storage Compliance</a></li>\n<li><a href=\"/services/pharmaceutical-quality-management-system/\">Pharma QMS</a></li>\n<li><a href=\"/services/thermal-packaging-validation/\">Thermal Packaging</a></li>\n<li><a href=\"/services/computer-system-validation-saudi-arabia/\">Computer System Validation</a></li>\n<li><a href=\"/services/cold-chain-solutions-saudi-arabia/\">Cold Chain Solutions</a></li>\n</ul>\n<!-- /wp:html -->\n</div><!-- /wp:column -->\n<!-- wp:column {\"width\":\"30%\"} -->\n<div class=\"wp-block-column\" style=\"flex-basis:30%\">\n<!-- wp:heading {\"level\":4,\"style\":{\"color\":{\"text\":\"rgba(255,255,255,0.5)\"},\"typography\":{\"fontSize\":\"11px\",\"fontWeight\":\"700\",\"letterSpacing\":\"0.1em\",\"textTransform\":\"uppercase\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"16px\"}}}} --><h4 class=\"wp-block-heading\" style=\"color:rgba(255,255,255,0.5);font-size:11px;font-weight:700;letter-spacing:0.1em;text-transform:uppercase;margin-top:0;margin-bottom:16px\">Company</h4><!-- /wp:heading -->\n<!-- wp:html -->\n<ul class=\"hydra-footer-links\">\n<li><a href=\"/about/\">About</a></li>\n<li><a href=\"/contact/\">Contact</a></li>\n</ul>\n<!-- /wp:html -->\n</div><!-- /wp:column -->\n</div><!-- /wp:columns -->\n<!-- wp:html -->\n<div class=\"hydra-footer-bar\">\n<span>hydracompliance.com</span><span>info@hydratl.com</span><span>+966 — — — — —</span>\n</div>\n<!-- /wp:html -->\n</div>\n<!-- /wp:group -->','Home','','inherit','closed','closed','','5-revision-v1','','','2026-05-14 13:48:14','2026-05-14 13:48:14','',5,'http://hydra-compliance.local/?p=41',0,'revision','',0),(42,0,'2026-05-14 13:48:14','2026-05-14 13:48:14','@import url(\'https://fonts.googleapis.com/css2?family=DM+Sans:wght@400;500;600;700&family=DM+Serif+Display:ital@0;1&display=swap\');\n\n:root {\n  --hc-teal:    #016B7A;\n  --hc-dark:    #014F59;\n  --hc-gold:    #C8922A;\n  --hc-navy:    #0C1E28;\n  --hc-muted:   #5E7580;\n  --hc-offwhite:#F5F8F9;\n  --hc-border:  #E0EAF0;\n}\n\n/* ── Global ── */\nbody { font-family: \'DM Sans\', sans-serif; color: var(--hc-navy); }\nh1,h2,h3,h4,h5,h6 { font-family: \'DM Serif Display\', serif; }\n.hydra-gold-italic { color: var(--hc-gold); font-style: italic; }\n\n/* ── Pill tag ── */\n.hydra-pill {\n  display: inline-flex;\n  align-items: center;\n  gap: 8px;\n  background: rgba(200,146,42,0.15);\n  color: var(--hc-gold);\n  border: 1px solid rgba(200,146,42,0.3);\n  border-radius: 100px;\n  padding: 6px 16px;\n  font-size: 13px;\n  font-weight: 500;\n  letter-spacing: 0.02em;\n}\n.hydra-dot {\n  width: 8px;\n  height: 8px;\n  background: var(--hc-gold);\n  border-radius: 50%;\n  flex-shrink: 0;\n  animation: hydra-pulse 2s ease-in-out infinite;\n}\n@keyframes hydra-pulse {\n  0%,100% { box-shadow: 0 0 0 0 rgba(200,146,42,0.6); }\n  50%      { box-shadow: 0 0 0 6px rgba(200,146,42,0); }\n}\n\n/* ── Hero badges ── */\n.hydra-badges {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 8px;\n}\n.hydra-badges span {\n  border: 1px solid rgba(255,255,255,0.2);\n  color: rgba(255,255,255,0.65);\n  border-radius: 4px;\n  padding: 4px 12px;\n  font-size: 12px;\n  letter-spacing: 0.04em;\n}\n\n/* ── Services grid ── */\n.hydra-services-grid {\n  display: grid;\n  grid-template-columns: repeat(3, 1fr);\n  gap: 24px;\n}\n@media (max-width: 768px) {\n  .hydra-services-grid { grid-template-columns: 1fr; }\n}\n@media (min-width: 769px) and (max-width: 1024px) {\n  .hydra-services-grid { grid-template-columns: repeat(2, 1fr); }\n}\n.hydra-card {\n  background: #fff;\n  border: 1px solid var(--hc-border);\n  border-radius: 12px;\n  padding: 28px;\n  transition: box-shadow 0.2s ease, border-color 0.2s ease;\n}\n.hydra-card:hover {\n  border-color: var(--hc-teal);\n  box-shadow: 0 8px 32px rgba(1,107,122,0.1);\n}\n.hydra-card-icon {\n  font-size: 32px;\n  line-height: 1;\n  margin-bottom: 14px;\n}\n.hydra-card h3 {\n  font-family: \'DM Serif Display\', serif;\n  font-size: 18px;\n  font-weight: 400;\n  color: var(--hc-navy);\n  margin: 0 0 8px;\n  line-height: 1.3;\n}\n.hydra-card p {\n  font-size: 14px;\n  color: var(--hc-muted);\n  line-height: 1.6;\n  margin: 0 0 16px;\n}\n.hydra-card a {\n  font-size: 14px;\n  font-weight: 600;\n  color: var(--hc-teal);\n  text-decoration: none;\n}\n.hydra-card a:hover { color: var(--hc-dark); }\n\n/* ── Industries ── */\n.hydra-industries {\n  display: grid;\n  grid-template-columns: repeat(6, 1fr);\n  gap: 16px;\n}\n@media (max-width: 768px) {\n  .hydra-industries { grid-template-columns: repeat(3, 1fr); }\n}\n@media (max-width: 480px) {\n  .hydra-industries { grid-template-columns: repeat(2, 1fr); }\n}\n.hydra-industry {\n  background: rgba(1,107,122,0.08);\n  border: 1px solid rgba(1,79,89,0.15);\n  border-radius: 10px;\n  padding: 20px 16px;\n  text-align: center;\n  transition: background 0.2s;\n}\n.hydra-industry:hover { background: rgba(1,107,122,0.14); }\n.hydra-industry span { font-size: 28px; display: block; margin-bottom: 8px; }\n.hydra-industry p { font-size: 13px; font-weight: 600; color: var(--hc-dark); margin: 0; }\n\n/* ── FAQ ── */\n.wp-block-details summary {\n  list-style: none;\n  font-size: 16px;\n  font-weight: 600;\n  color: var(--hc-navy);\n  cursor: pointer;\n  display: flex;\n  justify-content: space-between;\n  align-items: center;\n}\n.wp-block-details summary::after {\n  content: \'+\';\n  font-size: 20px;\n  color: var(--hc-teal);\n  font-weight: 300;\n  transition: transform 0.2s;\n}\n.wp-block-details[open] summary::after { content: \'−\'; }\n\n/* ── Header logo ── */\n.hydra-logo-hy {\n  font-family: \'DM Serif Display\', serif;\n  font-size: 22px;\n  color: var(--hc-gold);\n  font-style: italic;\n}\n.hydra-logo-text {\n  font-family: \'DM Sans\', sans-serif;\n  font-size: 20px;\n  font-weight: 700;\n  color: var(--hc-navy);\n  letter-spacing: -0.02em;\n}\n.hydra-footer-logo { display: flex; align-items: baseline; gap: 2px; }\n.hydra-footer-logo .hydra-logo-hy { color: var(--hc-gold); }\n.hydra-footer-logo .hydra-logo-text { color: #fff; }\n\n/* ── Footer ── */\n.hydra-footer-links {\n  list-style: none;\n  padding: 0;\n  margin: 0;\n}\n.hydra-footer-links li { margin-bottom: 10px; }\n.hydra-footer-links a {\n  color: rgba(255,255,255,0.6);\n  font-size: 14px;\n  text-decoration: none;\n  transition: color 0.15s;\n}\n.hydra-footer-links a:hover { color: #fff; }\n.hydra-footer-bar {\n  border-top: 1px solid rgba(255,255,255,0.08);\n  padding: 20px 0;\n  display: flex;\n  gap: 32px;\n  flex-wrap: wrap;\n  font-size: 13px;\n  color: rgba(255,255,255,0.35);\n}\n\n/* ── Kadence header overrides ── */\n.site-header .header-navigation .nav-menu > li > a {\n  font-family: \'DM Sans\', sans-serif;\n  font-size: 14px;\n  font-weight: 500;\n  color: var(--hc-navy);\n}\n.site-header {\n  border-bottom: 1px solid var(--hc-border);\n}\n\n/* ── Button outline fix ── */\n.wp-block-button.is-style-outline .wp-block-button__link {\n  background: transparent !important;\n}','Custom CSS','','inherit','closed','closed','','40-revision-v1','','','2026-05-14 13:48:14','2026-05-14 13:48:14','',40,'http://hydra-compliance.local/?p=42',0,'revision','',0),(43,0,'2026-05-14 13:48:37','2026-05-14 13:48:37','','HYDRA Logo','','inherit','open','closed','','hydra-logo','','','2026-05-14 13:48:37','2026-05-14 13:48:37','',0,'http://hydra-compliance.local/hydra-logo/',0,'attachment','image/svg+xml',0),(44,0,'2026-05-14 13:48:54','2026-05-14 13: