aphy\":{\"fontSize\":\"38px\",\"fontFamily\":\"\'DM Serif Display\',serif\",\"fontWeight\":\"400\",\"lineHeight\":\"1.2\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"16px\"}}}} -->\n<h1 class=\"wp-block-heading\" style=\"color:#ffffff;font-family:\'DM Serif Display\',serif;font-size:38px;font-weight:400;line-height:1.2;margin-top:0;margin-bottom:16px\">Temperature Mapping Saudi Arabia</h1>\n<!-- /wp:heading -->\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"rgba(255,255,255,0.62)\"},\"typography\":{\"fontSize\":\"15px\",\"lineHeight\":\"1.75\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"32px\"}}}} -->\n<p style=\"color:rgba(255,255,255,0.62);font-size:15px;line-height:1.75;margin-top:0;margin-bottom:32px\">ISPE and WHO GDP-compliant temperature mapping for warehouses, cold rooms, vehicles, and chambers. SFDA-ready validated reports delivered in 5–10 days.</p>\n<!-- /wp:paragraph -->\n<!-- wp:buttons {\"layout\":{\"type\":\"flex\",\"justifyContent\":\"left\"},\"style\":{\"spacing\":{\"blockGap\":\"14px\"}}} -->\n<div class=\"wp-block-buttons\">\n<!-- wp:button {\"style\":{\"color\":{\"background\":\"#016B7A\",\"text\":\"#ffffff\"},\"border\":{\"radius\":\"6px\"},\"spacing\":{\"padding\":{\"top\":\"12px\",\"bottom\":\"12px\",\"left\":\"28px\",\"right\":\"28px\"}},\"typography\":{\"fontSize\":\"14px\",\"fontWeight\":\"600\"}}} -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"/contact/\" style=\"background-color:#016B7A;color:#fff;border-radius:6px;padding:12px 28px;font-size:14px;font-weight:600\">Get a free quote</a></div>\n<!-- /wp:button -->\n<!-- wp:button {\"style\":{\"color\":{\"text\":\"#ffffff\"},\"border\":{\"color\":\"rgba(255,255,255,0.45)\",\"width\":\"2px\",\"radius\":\"6px\"},\"spacing\":{\"padding\":{\"top\":\"12px\",\"bottom\":\"12px\",\"left\":\"28px\",\"right\":\"28px\"}},\"typography\":{\"fontSize\":\"14px\"}}} -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"tel:+966\" style=\"color:#fff;border:2px solid rgba(255,255,255,0.45);border-radius:6px;padding:12px 28px;font-size:14px;background:transparent\">+966 — — — — —</a></div>\n<!-- /wp:button -->\n</div>\n<!-- /wp:buttons -->\n</div>\n<!-- /wp:group -->\n\n<!-- ── SECTION 3: CONTENT + SIDEBAR ─────────────────────────────────────── -->\n<!-- wp:group {\"align\":\"full\",\"style\":{\"color\":{\"background\":\"#F5F8F9\"},\"spacing\":{\"padding\":{\"top\":\"64px\",\"bottom\":\"64px\",\"left\":\"24px\",\"right\":\"24px\"}}},\"layout\":{\"type\":\"constrained\",\"contentSize\":\"1100px\"}} -->\n<div class=\"wp-block-group alignfull has-background\" style=\"background-color:#F5F8F9;padding-top:64px;padding-bottom:64px;padding-left:24px;padding-right:24px\">\n<!-- wp:columns {\"isStackedOnMobile\":true,\"style\":{\"spacing\":{\"blockGap\":\"48px\"}}} -->\n<div class=\"wp-block-columns\">\n\n<!-- LEFT: main content -->\n<!-- wp:column {\"width\":\"65%\"} -->\n<div class=\"wp-block-column hydra-svc-content\" style=\"flex-basis:65%\">\n<!-- wp:heading {\"level\":2,\"style\":{\"color\":{\"text\":\"#0C1E28\"},\"typography\":{\"fontSize\":\"clamp(22px,3vw,30px)\",\"fontFamily\":\"\'DM Serif Display\',serif\",\"fontWeight\":\"400\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"16px\"}}}} -->\n<h2 class=\"wp-block-heading\" style=\"color:#0C1E28;font-family:\'DM Serif Display\',serif;font-size:clamp(22px,3vw,30px);font-weight:400;margin-top:0;margin-bottom:16px\">Temperature mapping services in Saudi Arabia</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#3D5460\"},\"typography\":{\"fontSize\":\"15px\",\"lineHeight\":\"1.8\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"20px\"}}}} -->\n<p style=\"color:#3D5460;font-size:15px;line-height:1.8;margin-top:0;margin-bottom:20px\">Temperature mapping is a validated study that proves your pharmaceutical storage or transport environment maintains the required temperature range under real operating conditions. HYDRA Quality &amp; Compliance delivers ISPE-aligned temperature mapping studies for pharmaceutical warehouses, cold rooms, refrigerated vehicles, and controlled-temperature chambers across Saudi Arabia, with SFDA-ready validated reports typically delivered in 5–10 days.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#3D5460\"},\"typography\":{\"fontSize\":\"15px\",\"lineHeight\":\"1.8\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"32px\"}}}} -->\n<p style=\"color:#3D5460;font-size:15px;line-height:1.8;margin-top:0;margin-bottom:32px\">By placing calibrated data loggers at pre-defined locations throughout your facility or vehicle, our engineers record temperature profiles over a defined study period — capturing daily and seasonal variations, door-opening effects, and HVAC behaviour. The resulting report provides documentary evidence for SFDA audits and regulatory submissions.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":2,\"style\":{\"color\":{\"text\":\"#0C1E28\"},\"typography\":{\"fontSize\":\"clamp(20px,2.5vw,26px)\",\"fontFamily\":\"\'DM Serif Display\',serif\",\"fontWeight\":\"400\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"16px\"}}}} -->\n<h2 class=\"wp-block-heading\" style=\"color:#0C1E28;font-family:\'DM Serif Display\',serif;font-size:clamp(20px,2.5vw,26px);font-weight:400;margin-top:0;margin-bottom:16px\">Why Saudi pharma companies require temperature mapping</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#3D5460\"},\"typography\":{\"fontSize\":\"15px\",\"lineHeight\":\"1.8\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"16px\"}}}} -->\n<p style=\"color:#3D5460;font-size:15px;line-height:1.8;margin-top:0;margin-bottom:16px\">The Saudi Food and Drug Authority (SFDA) requires all pharmaceutical storage facilities and distribution vehicles to demonstrate validated temperature conditions before medicines can be stored or distributed. Failure to produce a temperature mapping report during an SFDA inspection is a critical finding that can result in suspension of distribution licences.</p>\n<!-- /wp:paragraph -->\n<!-- wp:html -->\n<ul class=\"hydra-checklist\">\n  <li>SFDA GDP Guidelines for pharmaceutical distribution and storage</li>\n  <li>WHO Technical Report Series 961 – Annex 9 (GDP requirements)</li>\n  <li>EU GDP Guidelines 2013/C 343/01 (adopted by many KSA multinationals)</li>\n  <li>ISPE Good Practice Guide: Cold Chain Management</li>\n  <li>USP &lt;1079&gt; Good Storage and Distribution Practices</li>\n  <li>ICH Q10 Pharmaceutical Quality System</li>\n</ul>\n<!-- /wp:html -->\n\n<!-- wp:spacer {\"height\":\"32px\"} --><div style=\"height:32px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div><!-- /wp:spacer -->\n\n<!-- wp:heading {\"level\":2,\"style\":{\"color\":{\"text\":\"#0C1E28\"},\"typography\":{\"fontSize\":\"clamp(20px,2.5vw,26px)\",\"fontFamily\":\"\'DM Serif Display\',serif\",\"fontWeight\":\"400\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"16px\"}}}} -->\n<h2 class=\"wp-block-heading\" style=\"color:#0C1E28;font-family:\'DM Serif Display\',serif;font-size:clamp(20px,2.5vw,26px);font-weight:400;margin-top:0;margin-bottom:16px\">Facilities and environments we map</h2>\n<!-- /wp:heading -->\n<!-- wp:html -->\n<ul class=\"hydra-checklist\">\n  <li>Pharmaceutical warehouses and distribution centres</li>\n  <li>Cold rooms and cold stores (2–8 °C)</li>\n  <li>Controlled room temperature zones (15–25 °C)</li>\n  <li>Ultra-low temperature freezers (−20 °C to −80 °C)</li>\n  <li>Refrigerated transport vehicles and trailers</li>\n  <li>Hospital pharmacy and clinical trial material stores</li>\n  <li>Environmental chambers and stability cabinets</li>\n  <li>Incubators and bio-safety cabinets</li>\n</ul>\n<!-- /wp:html -->\n\n<!-- wp:spacer {\"height\":\"32px\"} --><div style=\"height:32px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div><!-- /wp:spacer -->\n\n<!-- wp:heading {\"level\":2,\"style\":{\"color\":{\"text\":\"#0C1E28\"},\"typography\":{\"fontSize\":\"clamp(20px,2.5vw,26px)\",\"fontFamily\":\"\'DM Serif Display\',serif\",\"fontWeight\":\"400\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"16px\"}}}} -->\n<h2 class=\"wp-block-heading\" style=\"color:#0C1E28;font-family:\'DM Serif Display\',serif;font-size:clamp(20px,2.5vw,26px);font-weight:400;margin-top:0;margin-bottom:16px\">Our temperature mapping process</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#3D5460\"},\"typography\":{\"fontSize\":\"15px\",\"lineHeight\":\"1.8\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"16px\"}}}} -->\n<p style=\"color:#3D5460;font-size:15px;line-height:1.8;margin-top:0;margin-bottom:16px\">HYDRA follows a structured, risk-based methodology aligned with ISPE and WHO GDP guidance. Every study is preceded by a written protocol approved by the client before data collection begins.</p>\n<!-- /wp:paragraph -->\n<!-- wp:html -->\n<ol class=\"hydra-process-list\">\n  <li><strong>Site survey &amp; sensor placement plan</strong> — HYDRA engineers visit the facility, assess risk zones (near doors, air vents, outer walls), and define data logger positions in a written mapping plan.</li>\n  <li><strong>Protocol generation &amp; approval</strong> — A formal IQ/OQ protocol is issued for client signature before any loggers are deployed.</li>\n  <li><strong>Calibrated data logger deployment</strong> — NIST-traceable calibrated loggers are installed at all mapped locations.</li>\n  <li><strong>Monitoring period</strong> — Minimum 5 days for chambers; 10–15 days for warehouses. Studies run across normal operating days, including door openings and temperature fluctuations.</li>\n  <li><strong>Data collection &amp; statistical analysis</strong> — All logger data is downloaded and analysed. Hot spots, cold spots, and out-of-specification events are identified.</li>\n  <li><strong>Report preparation</strong> — A comprehensive SFDA-ready validation report with isotherm maps, statistical tables, and signed conclusions is prepared.</li>\n  <li><strong>Client review &amp; sign-off</strong> — Report is delivered for client QA review and countersigned.</li>\n</ol>\n<!-- /wp:html -->\n\n<!-- wp:spacer {\"height\":\"32px\"} --><div style=\"height:32px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div><!-- /wp:spacer -->\n\n<!-- wp:heading {\"level\":2,\"style\":{\"color\":{\"text\":\"#0C1E28\"},\"typography\":{\"fontSize\":\"clamp(20px,2.5vw,26px)\",\"fontFamily\":\"\'DM Serif Display\',serif\",\"fontWeight\":\"400\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"16px\"}}}} -->\n<h2 class=\"wp-block-heading\" style=\"color:#0C1E28;font-family:\'DM Serif Display\',serif;font-size:clamp(20px,2.5vw,26px);font-weight:400;margin-top:0;margin-bottom:16px\">What is included in every HYDRA temperature mapping report</h2>\n<!-- /wp:heading -->\n<!-- wp:html -->\n<ul class=\"hydra-checklist\">\n  <li>Installation Qualification (IQ) documentation</li>\n  <li>Operational Qualification (OQ) protocol and execution report</li>\n  <li>Temperature distribution maps and isotherm diagrams</li>\n  <li>Hot spot and cold spot identification with coordinates</li>\n  <li>Calibration certificates for all deployed data loggers</li>\n  <li>Statistical analysis of temperature excursions and MKT calculations</li>\n  <li>Summary of findings and risk assessment</li>\n  <li>Corrective action recommendations where required</li>\n  <li>SFDA-submission-ready final report (PDF + editable formats)</li>\n</ul>\n<!-- /wp:html -->\n\n<!-- wp:spacer {\"height\":\"32px\"} --><div style=\"height:32px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div><!-- /wp:spacer -->\n\n<!-- wp:heading {\"level\":2,\"style\":{\"color\":{\"text\":\"#0C1E28\"},\"typography\":{\"fontSize\":\"clamp(20px,2.5vw,26px)\",\"fontFamily\":\"\'DM Serif Display\',serif\",\"fontWeight\":\"400\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"16px\"}}}} -->\n<h2 class=\"wp-block-heading\" style=\"color:#0C1E28;font-family:\'DM Serif Display\',serif;font-size:clamp(20px,2.5vw,26px);font-weight:400;margin-top:0;margin-bottom:16px\">Temperature mapping across Saudi Arabia</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#3D5460\"},\"typography\":{\"fontSize\":\"15px\",\"lineHeight\":\"1.8\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"20px\"}}}} -->\n<p style=\"color:#3D5460;font-size:15px;line-height:1.8;margin-top:0;margin-bottom:20px\">HYDRA operates from our Jeddah base with nationwide coverage. We routinely mobilise to Riyadh, Dammam, Al Khobar, Jubail, Mecca, Medina, Yanbu, Tabuk, and Abha. For multi-site clients, we coordinate simultaneous studies across multiple locations to minimise downtime.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#3D5460\"},\"typography\":{\"fontSize\":\"15px\",\"lineHeight\":\"1.8\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"0\"}}}} -->\n<p style=\"color:#3D5460;font-size:15px;line-height:1.8;margin-top:0;margin-bottom:0\">Typical mobilisation time: 3–5 business days from enquiry. Standard report delivery: 5–7 days after study completion. Contact us for urgent or same-week requirements.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- RIGHT: sidebar -->\n<!-- wp:column {\"width\":\"35%\",\"className\":\"hydra-svc-sidebar\"} -->\n<div class=\"wp-block-column hydra-svc-sidebar\" style=\"flex-basis:35%\">\n\n<!-- Quote card -->\n<!-- wp:group {\"className\":\"hydra-quote-card\",\"style\":{\"color\":{\"background\":\"#ffffff\"},\"border\":{\"radius\":\"12px\"},\"spacing\":{\"padding\":{\"top\":\"28px\",\"bottom\":\"28px\",\"left\":\"28px\",\"right\":\"28px\"}},\"shadow\":\"0 4px 24px rgba(12,30,40,0.10)\"}} -->\n<div class=\"wp-block-group hydra-quote-card has-background\" style=\"background-color:#ffffff;border-radius:12px;padding:28px;box-shadow:0 4px 24px rgba(12,30,40,0.10)\">\n<!-- wp:heading {\"level\":3,\"style\":{\"color\":{\"text\":\"#0C1E28\"},\"typography\":{\"fontSize\":\"20px\",\"fontFamily\":\"\'DM Serif Display\',serif\",\"fontWeight\":\"400\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"6px\"}}}} -->\n<h3 class=\"wp-block-heading\" style=\"color:#0C1E28;font-family:\'DM Serif Display\',serif;font-size:20px;font-weight:400;margin-top:0;margin-bottom:6px\">Get a free quote</h3>\n<!-- /wp:heading -->\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#5E7580\"},\"typography\":{\"fontSize\":\"13px\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"20px\"}}}} -->\n<p style=\"color:#5E7580;font-size:13px;margin-top:0;margin-bottom:20px\">Tell us about your facility. Quote within 24 hours.</p>\n<!-- /wp:paragraph -->\n<!-- wp:shortcode -->[wpforms id=\"45\"]<!-- /wp:shortcode -->\n</div>\n<!-- /wp:group -->\n\n<!-- wp:spacer {\"height\":\"24px\"} --><div style=\"height:24px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div><!-- /wp:spacer -->\n\n<!-- Contact card -->\n<!-- wp:group {\"className\":\"hydra-contact-card\",\"style\":{\"color\":{\"background\":\"#ffffff\"},\"border\":{\"radius\":\"12px\",\"color\":\"#E0EAF0\",\"style\":\"solid\",\"width\":\"1px\"},\"spacing\":{\"padding\":{\"top\":\"24px\",\"bottom\":\"24px\",\"left\":\"24px\",\"right\":\"24px\"}}}} -->\n<div class=\"wp-block-group hydra-contact-card has-background\" style=\"background-color:#ffffff;border-radius:12px;border:1px solid #E0EAF0;padding:24px\">\n<!-- wp:html -->\n<ul class=\"hydra-contact-list\">\n  <li><span>📍</span> Jeddah, Saudi Arabia</li>\n  <li><span>📞</span> +966 — — — — —</li>\n  <li><span>✉️</span> info@hydratl.com</li>\n  <li><span>⏱</span> Response within 24 hours</li>\n</ul>\n<!-- /wp:html -->\n</div>\n<!-- /wp:group -->\n\n</div>\n<!-- /wp:column -->\n\n</div>\n<!-- /wp:columns -->\n</div>\n<!-- /wp:group -->\n\n<!-- ── SECTION 4: RELATED SERVICES ───────────────────────────────────────── -->\n<!-- wp:group {\"align\":\"full\",\"style\":{\"color\":{\"background\":\"#ffffff\"},\"spacing\":{\"padding\":{\"top\":\"64px\",\"bottom\":\"64px\",\"left\":\"24px\",\"right\":\"24px\"}}},\"layout\":{\"type\":\"constrained\",\"contentSize\":\"1100px\"}} -->\n<div class=\"wp-block-group alignfull has-white-background-color has-background\" style=\"background-color:#ffffff;padding-top:64px;padding-bottom:64px;padding-left:24px;padding-right:24px\">\n<!-- wp:heading {\"level\":2,\"style\":{\"color\":{\"text\":\"#0C1E28\"},\"typography\":{\"fontSize\":\"clamp(22px,3vw,32px)\",\"fontFamily\":\"\'DM Serif Display\',serif\",\"fontWeight\":\"400\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"40px\"}}}} -->\n<h2 class=\"wp-block-heading\" style=\"color:#0C1E28;font-family:\'DM Serif Display\',serif;font-size:clamp(22px,3vw,32px);font-weight:400;margin-top:0;margin-bottom:40px\">You may also need</h2>\n<!-- /wp:heading -->\n<!-- wp:html -->\n<div class=\"hydra-related-grid\">\n<div class=\"hydra-related-card\">\n  <div class=\"hydra-related-icon\">✅</div>\n  <h3>Validation &amp; Qualification</h3>\n  <p>IQ/OQ/PQ for equipment, utilities, and facilities</p>\n  <a href=\"/services/validation-qualification-services/\">Learn more →</a>\n</div>\n<div class=\"hydra-related-card\">\n  <div class=\"hydra-related-icon\">📋</div>\n  <h3>GDP Compliance</h3>\n  <p>Full WHO/EU GDP consulting for distributors and 3PL</p>\n  <a href=\"/services/gdp-compliance-saudi-arabia/\">Learn more →</a>\n</div>\n<div class=\"hydra-related-card\">\n  <div class=\"hydra-related-icon\">❄️</div>\n  <h3>Cold Chain Solutions</h3>\n  <p>End-to-end GDP transport and cold chain compliance</p>\n  <a href=\"/services/cold-chain-solutions-saudi-arabia/\">Learn more →</a>\n</div>\n</div>\n<!-- /wp:html -->\n</div>\n<!-- /wp:group -->\n\n<!-- ── SECTION 5: CTA BANNER ─────────────────────────────────────────────── -->\n<!-- wp:group {\"align\":\"full\",\"style\":{\"color\":{\"background\":\"#016B7A\"},\"spacing\":{\"padding\":{\"top\":\"72px\",\"bottom\":\"72px\",\"left\":\"24px\",\"right\":\"24px\"}}},\"layout\":{\"type\":\"constrained\",\"contentSize\":\"800px\"}} -->\n<div class=\"wp-block-group alignfull has-background\" style=\"background-color:#016B7A;padding-top:72px;padding-bottom:72px;padding-left:24px;padding-right:24px;text-align:center\">\n<!-- wp:heading {\"level\":2,\"textAlign\":\"center\",\"style\":{\"color\":{\"text\":\"#ffffff\"},\"typography\":{\"fontSize\":\"clamp(24px,4vw,36px)\",\"fontFamily\":\"\'DM Serif Display\',serif\",\"fontWeight\":\"400\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"12px\"}}}} -->\n<h2 class=\"wp-block-heading has-text-align-center\" style=\"color:#ffffff;font-family:\'DM Serif Display\',serif;font-size:clamp(24px,4vw,36px);font-weight:400;margin-top:0;margin-bottom:12px\">Ready to get started?</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"color\":{\"text\":\"rgba(255,255,255,0.8)\"},\"typography\":{\"fontSize\":\"15px\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"32px\"}}}} -->\n<p class=\"has-text-align-center\" style=\"color:rgba(255,255,255,0.8);font-size:15px;margin-top:0;margin-bottom:32px\">Free consultation · Jeddah · Riyadh · Dammam · all of KSA</p>\n<!-- /wp:paragraph -->\n<!-- wp:buttons {\"layout\":{\"type\":\"flex\",\"justifyContent\":\"center\"}} -->\n<div class=\"wp-block-buttons\">\n<!-- wp:button {\"style\":{\"color\":{\"background\":\"#ffffff\",\"text\":\"#016B7A\"},\"border\":{\"radius\":\"6px\"},\"spacing\":{\"padding\":{\"top\":\"16px\",\"bottom\":\"16px\",\"left\":\"40px\",\"right\":\"40px\"}},\"typography\":{\"fontWeight\":\"700\",\"fontSize\":\"15px\"}}} -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"/contact/\" style=\"background-color:#fff;color:#016B7A;border-radius:6px;padding:16px 40px;font-weight:700;font-size:15px\">Get a free quote →</a></div>\n<!-- /wp:button -->\n</div>\n<!-- /wp:buttons -->\n</div>\n<!-- /wp:group -->\n\n<!-- ── FOOTER (global – rendered by theme) ───────────────────────────────── -->','Temperature Mapping','','inherit','closed','closed','','6-revision-v1','','','2026-05-14 13:56:45','2026-05-14 13:56:45','',6,'http://hydra-compliance.local/?p=46',0,'revision','',0),(47,0,'2026-05-14 13:56:45','2026-05-14 13:56:45','@import url(\'https://fonts.googleapis.com/css2?family=DM+Sans:wght@400;500;600;700&family=DM+Serif+Display:ital@0;1&display=swap\');\n\n:root {\n  --hc-teal:    #016B7A;\n  --hc-dark:    #014F59;\n  --hc-gold:    #C8922A;\n  --hc-navy:    #0C1E28;\n  --hc-muted:   #5E7580;\n  --hc-offwhite:#F5F8F9;\n  --hc-border:  #E0EAF0;\n}\n\n/* ── Global ── */\nbody { font-family: \'DM Sans\', sans-serif; color: var(--hc-navy); }\nh1,h2,h3,h4,h5,h6 { font-family: \'DM Serif Display\', serif; }\n.hydra-gold-italic { color: var(--hc-gold); font-style: italic; }\n\n/* ── Pill tag ── */\n.hydra-pill {\n  display: inline-flex;\n  align-items: center;\n  gap: 8px;\n  background: rgba(200,146,42,0.15);\n  color: var(--hc-gold);\n  border: 1px solid rgba(200,146,42,0.3);\n  border-radius: 100px;\n  padding: 6px 16px;\n  font-size: 13px;\n  font-weight: 500;\n  letter-spacing: 0.02em;\n}\n.hydra-dot {\n  width: 8px;\n  height: 8px;\n  background: var(--hc-gold);\n  border-radius: 50%;\n  flex-shrink: 0;\n  animation: hydra-pulse 2s ease-in-out infinite;\n}\n@keyframes hydra-pulse {\n  0%,100% { box-shadow: 0 0 0 0 rgba(200,146,42,0.6); }\n  50%      { box-shadow: 0 0 0 6px rgba(200,146,42,0); }\n}\n\n/* ── Hero badges ── */\n.hydra-badges {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 8px;\n}\n.hydra-badges span {\n  border: 1px solid rgba(255,255,255,0.2);\n  color: rgba(255,255,255,0.65);\n  border-radius: 4px;\n  padding: 4px 12px;\n  font-size: 12px;\n  letter-spacing: 0.04em;\n}\n\n/* ── Services grid ── */\n.hydra-services-grid {\n  display: grid;\n  grid-template-columns: repeat(3, 1fr);\n  gap: 24px;\n}\n@media (max-width: 768px) {\n  .hydra-services-grid { grid-template-columns: 1fr; }\n}\n@media (min-width: 769px) and (max-width: 1024px) {\n  .hydra-services-grid { grid-template-columns: repeat(2, 1fr); }\n}\n.hydra-card {\n  background: #fff;\n  border: 1px solid var(--hc-border);\n  border-radius: 12px;\n  padding: 28px;\n  transition: box-shadow 0.2s ease, border-color 0.2s ease;\n}\n.hydra-card:hover {\n  border-color: var(--hc-teal);\n  box-shadow: 0 8px 32px rgba(1,107,122,0.1);\n}\n.hydra-card-icon {\n  font-size: 32px;\n  line-height: 1;\n  margin-bottom: 14px;\n}\n.hydra-card h3 {\n  font-family: \'DM Serif Display\', serif;\n  font-size: 18px;\n  font-weight: 400;\n  color: var(--hc-navy);\n  margin: 0 0 8px;\n  line-height: 1.3;\n}\n.hydra-card p {\n  font-size: 14px;\n  color: var(--hc-muted);\n  line-height: 1.6;\n  margin: 0 0 16px;\n}\n.hydra-card a {\n  font-size: 14px;\n  font-weight: 600;\n  color: var(--hc-teal);\n  text-decoration: none;\n}\n.hydra-card a:hover { color: var(--hc-dark); }\n\n/* ── Industries ── */\n.hydra-industries {\n  display: grid;\n  grid-template-columns: repeat(6, 1fr);\n  gap: 16px;\n}\n@media (max-width: 768px) {\n  .hydra-industries { grid-template-columns: repeat(3, 1fr); }\n}\n@media (max-width: 480px) {\n  .hydra-industries { grid-template-columns: repeat(2, 1fr); }\n}\n.hydra-industry {\n  background: rgba(1,107,122,0.08);\n  border: 1px solid rgba(1,79,89,0.15);\n  border-radius: 10px;\n  padding: 20px 16px;\n  text-align: center;\n  transition: background 0.2s;\n}\n.hydra-industry:hover { background: rgba(1,107,122,0.14); }\n.hydra-industry span { font-size: 28px; display: block; margin-bottom: 8px; }\n.hydra-industry p { font-size: 13px; font-weight: 600; color: var(--hc-dark); margin: 0; }\n\n/* ── FAQ ── */\n.wp-block-details summary {\n  list-style: none;\n  font-size: 16px;\n  font-weight: 600;\n  color: var(--hc-navy);\n  cursor: pointer;\n  display: flex;\n  justify-content: space-between;\n  align-items: center;\n}\n.wp-block-details summary::after {\n  content: \'+\';\n  font-size: 20px;\n  color: var(--hc-teal);\n  font-weight: 300;\n  transition: transform 0.2s;\n}\n.wp-block-details[open] summary::after { content: \'−\'; }\n\n/* ── Header logo ── */\n.hydra-logo-hy {\n  font-family: \'DM Serif Display\', serif;\n  font-size: 22px;\n  color: var(--hc-gold);\n  font-style: italic;\n}\n.hydra-logo-text {\n  font-family: \'DM Sans\', sans-serif;\n  font-size: 20px;\n  font-weight: 700;\n  color: var(--hc-navy);\n  letter-spacing: -0.02em;\n}\n.hydra-footer-logo { display: flex; align-items: baseline; gap: 2px; }\n.hydra-footer-logo .hydra-logo-hy { color: var(--hc-gold); }\n.hydra-footer-logo .hydra-logo-text { color: #fff; }\n\n/* ── Footer ── */\n.hydra-footer-links {\n  list-style: none;\n  padding: 0;\n  margin: 0;\n}\n.hydra-footer-links li { margin-bottom: 10px; }\n.hydra-footer-links a {\n  color: rgba(255,255,255,0.6);\n  font-size: 14px;\n  text-decoration: none;\n  transition: color 0.15s;\n}\n.hydra-footer-links a:hover { color: #fff; }\n.hydra-footer-bar {\n  border-top: 1px solid rgba(255,255,255,0.08);\n  padding: 20px 0;\n  display: flex;\n  gap: 32px;\n  flex-wrap: wrap;\n  font-size: 13px;\n  color: rgba(255,255,255,0.35);\n}\n\n/* ── Kadence header overrides ── */\n.site-header .header-navigation .nav-menu > li > a {\n  font-family: \'DM Sans\', sans-serif;\n  font-size: 14px;\n  font-weight: 500;\n  color: var(--hc-navy);\n}\n.site-header {\n  border-bottom: 1px solid var(--hc-border);\n}\n\n/* ── Button outline fix ── */\n.wp-block-button.is-style-outline .wp-block-button__link {\n  background: transparent !important;\n}\n/* ── Site logo text fallback (if SVG does not render) ── */\n.custom-logo-link { text-decoration: none; }\n.site-branding { display: flex; align-items: center; }\n\n/* ── Fullwidth page: remove default padding ── */\n.content-style-unboxed .entry-content > * { max-width: none !important; padding-left: 0 !important; padding-right: 0 !important; }\n.page-template-default.page .entry-content .alignfull { margin-left: calc(-1 * var(--wp--style--root--padding-left, 0px)); margin-right: calc(-1 * var(--wp--style--root--padding-right, 0px)); width: calc(100% + var(--wp--style--root--padding-left, 0px) + var(--wp--style--root--padding-right, 0px)); }\n\n/* ── Remove Kadence default page hero/title area ── */\n.hide-title .entry-header { display: none; }\n\n/* ══ SERVICE PAGE STYLES ══════════════════════════════════════════════════ */\n\n/* Breadcrumb bar */\n.hydra-breadcrumb-bar .breadcrumbs,\n.hydra-breadcrumb-bar .rank-math-breadcrumb {\n  font-size: 13px;\n  color: rgba(255,255,255,0.5);\n  padding: 0;\n}\n.hydra-breadcrumb-bar .breadcrumbs a,\n.hydra-breadcrumb-bar .rank-math-breadcrumb a {\n  color: rgba(255,255,255,0.6);\n  text-decoration: none;\n}\n.hydra-breadcrumb-bar .breadcrumbs a:hover,\n.hydra-breadcrumb-bar .rank-math-breadcrumb a:hover { color: #fff; }\n\n/* Checkmark list */\n.hydra-checklist {\n  list-style: none;\n  padding: 0;\n  margin: 0 0 24px;\n}\n.hydra-checklist li {\n  position: relative;\n  padding-left: 24px;\n  font-size: 15px;\n  color: #3D5460;\n  line-height: 1.7;\n  margin-bottom: 8px;\n}\n.hydra-checklist li::before {\n  content: \'✓\';\n  position: absolute;\n  left: 0;\n  top: 0;\n  color: #016B7A;\n  font-weight: 700;\n}\n\n/* Process ordered list */\n.hydra-process-list {\n  padding-left: 0;\n  margin: 0 0 24px;\n  counter-reset: process-step;\n  list-style: none;\n}\n.hydra-process-list li {\n  counter-increment: process-step;\n  position: relative;\n  padding-left: 44px;\n  font-size: 15px;\n  color: #3D5460;\n  line-height: 1.7;\n  margin-bottom: 16px;\n}\n.hydra-process-list li::before {\n  content: counter(process-step);\n  position: absolute;\n  left: 0;\n  top: 0;\n  width: 28px;\n  height: 28px;\n  background: #016B7A;\n  color: #fff;\n  border-radius: 50%;\n  font-size: 13px;\n  font-weight: 700;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  line-height: 1;\n}\n.hydra-process-list li strong { color: #0C1E28; }\n\n/* Quote card */\n.hydra-quote-card {\n  position: sticky;\n  top: 100px;\n}\n.hydra-quote-card .wpforms-form .wpforms-field-label {\n  font-size: 13px;\n  font-weight: 600;\n  color: #5E7580;\n  margin-bottom: 4px;\n}\n.hydra-quote-card .wpforms-form input[type=\"text\"],\n.hydra-quote-card .wpforms-form input[type=\"email\"],\n.hydra-quote-card .wpforms-form select {\n  width: 100%;\n  border: 1px solid #E0EAF0;\n  border-radius: 6px;\n  padding: 10px 12px;\n  font-size: 14px;\n  font-family: \'DM Sans\', sans-serif;\n  color: #0C1E28;\n  background: #F5F8F9;\n  transition: border-color 0.15s;\n}\n.hydra-quote-card .wpforms-form input:focus,\n.hydra-quote-card .wpforms-form select:focus {\n  border-color: #016B7A;\n  outline: none;\n  background: #fff;\n}\n.hydra-quote-card .wpforms-form .wpforms-submit-container {\n  margin-top: 16px;\n}\n.hydra-quote-card .wpforms-form button[type=\"submit\"],\n.hydra-quote-card .wpforms-form .wpforms-submit {\n  width: 100%;\n  background: #C8922A;\n  color: #fff;\n  border: none;\n  border-radius: 6px;\n  padding: 12px 20px;\n  font-size: 14px;\n  font-weight: 700;\n  font-family: \'DM Sans\', sans-serif;\n  cursor: pointer;\n  transition: background 0.2s;\n}\n.hydra-quote-card .wpforms-form button[type=\"submit\"]:hover,\n.hydra-quote-card .wpforms-form .wpforms-submit:hover { background: #b07a22; }\n\n/* Contact card */\n.hydra-contact-list {\n  list-style: none;\n  padding: 0;\n  margin: 0;\n}\n.hydra-contact-list li {\n  display: flex;\n  align-items: flex-start;\n  gap: 10px;\n  font-size: 14px;\n  color: #3D5460;\n  line-height: 1.6;\n  margin-bottom: 10px;\n}\n.hydra-contact-list li:last-child { margin-bottom: 0; }\n.hydra-contact-list li span { font-size: 16px; flex-shrink: 0; margin-top: 1px; }\n\n/* Related services grid */\n.hydra-related-grid {\n  display: grid;\n  grid-template-columns: repeat(3, 1fr);\n  gap: 24px;\n}\n@media (max-width: 768px) {\n  .hydra-related-grid { grid-template-columns: 1fr; }\n}\n.hydra-related-card {\n  background: #F5F8F9;\n  border: 1px solid #E0EAF0;\n  border-radius: 12px;\n  padding: 24px;\n  transition: border-color 0.2s, box-shadow 0.2s;\n}\n.hydra-related-card:hover {\n  border-color: #016B7A;\n  box-shadow: 0 4px 20px rgba(1,107,122,0.08);\n}\n.hydra-related-icon { font-size: 28px; margin-bottom: 10px; }\n.hydra-related-card h3 {\n  font-family: \'DM Serif Display\', serif;\n  font-size: 17px;\n  font-weight: 400;\n  color: #0C1E28;\n  margin: 0 0 6px;\n}\n.hydra-related-card p {\n  font-size: 13px;\n  color: #5E7580;\n  line-height: 1.6;\n  margin: 0 0 12px;\n}\n.hydra-related-card a {\n  font-size: 13px;\n  font-weight: 600;\n  color: #016B7A;\n  text-decoration: none;\n}\n.hydra-related-card a:hover { color: #014F59; }\n\n/* Sidebar sticky on desktop */\n@media (min-width: 768px) {\n  .hydra-svc-sidebar { position: sticky; top: 90px; align-self: flex-start; }\n}','Custom CSS','','inherit','closed','closed','','40-revision-v1','','','2026-05-14 13:56:45','2026-05-14 13:56:45','',40,'http://hydra-compliance.local/?p=47',0,'revision','',0),(48,0,'2026-05-14 13:57:34','2026-05-14 13:57:34','<!-- ── SECTION 1: BREADCRUMB ──────────────────────────────────────────────── -->\n<!-- wp:group {\"align\":\"full\",\"style\":{\"color\":{\"background\":\"#132533\"},\"spacing\":{\"padding\":{\"top\":\"12px\",\"bottom\":\"12px\",\"left\":\"24px\",\"right\":\"24px\"}}},\"layout\":{\"type\":\"constrained\",\"contentSize\":\"1100px\"}} -->\n<div class=\"wp-block-group alignfull has-background hydra-breadcrumb-bar\" style=\"background-color:#132533;padding-top:12px;padding-bottom:12px;padding-left:24px;padding-right:24px\">\n<!-- wp:shortcode -->[rank_math_breadcrumb]<!-- /wp:shortcode -->\n</div>\n<!-- /wp:group -->\n\n<!-- ── SECTION 2: SERVICE HERO ───────────────────────────────────────────── -->\n<!-- wp:group {\"align\":\"full\",\"className\":\"hydra-svc-hero\",\"style\":{\"color\":{\"ba