i><a href=\"/services/cold-chain-solutions-saudi-arabia/\">Cold Chain Solutions</a></li>\n</ul>\n<!-- /wp:html -->\n</div><!-- /wp:column -->\n<!-- wp:column {\"width\":\"30%\"} -->\n<div class=\"wp-block-column\" style=\"flex-basis:30%\">\n<!-- wp:heading {\"level\":4,\"style\":{\"color\":{\"text\":\"rgba(255,255,255,0.5)\"},\"typography\":{\"fontSize\":\"11px\",\"fontWeight\":\"700\",\"letterSpacing\":\"0.1em\",\"textTransform\":\"uppercase\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"16px\"}}}} --><h4 class=\"wp-block-heading\" style=\"color:rgba(255,255,255,0.5);font-size:11px;font-weight:700;letter-spacing:0.1em;text-transform:uppercase;margin-top:0;margin-bottom:16px\">Company</h4><!-- /wp:heading -->\n<!-- wp:html -->\n<ul class=\"hydra-footer-links\">\n<li><a href=\"/about/\">About</a></li>\n<li><a href=\"/contact/\">Contact</a></li>\n</ul>\n<!-- /wp:html -->\n</div><!-- /wp:column -->\n</div><!-- /wp:columns -->\n<!-- wp:html -->\n<div class=\"hydra-footer-bar\">\n<span>hydracompliance.com</span><span>info@hydratl.com</span><span>+966 — — — — —</span>\n</div>\n<!-- /wp:html -->\n</div>\n<!-- /wp:group -->\n\n<!-- wp:html -->\n<script type=\"application/ld+json\">\n{\n  \"@context\":\"https://schema.org\",\n  \"@type\":\"ProfessionalService\",\n  \"@id\":\"https://hydracompliance.com/#organization\",\n  \"name\":\"HYDRA Quality & Compliance\",\n  \"url\":\"https://hydracompliance.com\",\n  \"telephone\":\"+966\",\n  \"email\":\"info@hydratl.com\",\n  \"logo\":\"https://hydracompliance.com/wp-content/uploads/hydra-logo.svg\",\n  \"image\":\"https://hydracompliance.com/wp-content/uploads/hydra-logo.svg\",\n  \"address\":{\n    \"@type\":\"PostalAddress\",\n    \"streetAddress\":\"3rd Floor, Alnankeel Business Center, Alhmra District\",\n    \"addressLocality\":\"Jeddah\",\n    \"addressRegion\":\"Makkah Province\",\n    \"addressCountry\":\"SA\"\n  },\n  \"geo\":{\n    \"@type\":\"GeoCoordinates\",\n    \"latitude\":21.5433,\n    \"longitude\":39.1728\n  },\n  \"openingHoursSpecification\":[{\n    \"@type\":\"OpeningHoursSpecification\",\n    \"dayOfWeek\":[\"Sunday\",\"Monday\",\"Tuesday\",\"Wednesday\",\"Thursday\"],\n    \"opens\":\"08:00\",\n    \"closes\":\"17:00\"\n  }],\n  \"sameAs\":[\"https://hydracompliance.com\"],\n  \"areaServed\":{\n    \"@type\":\"Country\",\n    \"name\":\"Saudi Arabia\"\n  },\n  \"knowsAbout\":[\"Pharmaceutical Compliance\",\"GDP\",\"GMP\",\"Temperature Mapping\",\"SFDA\",\"WHO GDP\",\"Cold Chain\",\"Validation\",\"QMS\"]\n}\n</script>\n<!-- /wp:html -->\n\n<!-- wp:html -->\n<script type=\"application/ld+json\">\n{\n  \"@context\":\"https://schema.org\",\n  \"@type\":\"FAQPage\",\n  \"mainEntity\":[\n    {\n      \"@type\":\"Question\",\n      \"name\":\"What is temperature mapping and why do I need it?\",\n      \"acceptedAnswer\":{\"@type\":\"Answer\",\"text\":\"Temperature mapping is a validated study that proves your storage or transport environment stays within required limits (typically 2–8 °C or 15–25 °C) under real-world conditions. SFDA and WHO GDP require mapped, qualified storage for all pharmaceutical products.\"}\n    },\n    {\n      \"@type\":\"Question\",\n      \"name\":\"How long does a temperature mapping study take?\",\n      \"acceptedAnswer\":{\"@type\":\"Answer\",\"text\":\"A standard warehouse study takes 5–15 days of data collection plus 3–5 days for the report. Chamber mapping is typically 3–7 days. HYDRA delivers a complete validated report ready for SFDA submission.\"}\n    },\n    {\n      \"@type\":\"Question\",\n      \"name\":\"Do you serve companies outside Jeddah?\",\n      \"acceptedAnswer\":{\"@type\":\"Answer\",\"text\":\"Yes. HYDRA operates across all of Saudi Arabia — Riyadh, Dammam, Mecca, Medina, and all regions. We also serve UAE-based companies with KSA operations.\"}\n    },\n    {\n      \"@type\":\"Question\",\n      \"name\":\"What is the difference between GDP and GMP?\",\n      \"acceptedAnswer\":{\"@type\":\"Answer\",\"text\":\"GMP (Good Manufacturing Practice) covers pharmaceutical manufacturing. GDP (Good Distribution Practice) covers storage, handling, and transport of finished pharmaceutical products. HYDRA specialises in GDP.\"}\n    },\n    {\n      \"@type\":\"Question\",\n      \"name\":\"How quickly can you start?\",\n      \"acceptedAnswer\":{\"@type\":\"Answer\",\"text\":\"We typically respond to enquiries within 24 hours and can mobilise within 3–5 business days. Contact us for an urgent requirement.\"}\n    }\n  ]\n}\n</script>\n<!-- /wp:html -->','Home','','inherit','closed','closed','','5-revision-v1','','','2026-05-14 14:07:11','2026-05-14 14:07:11','',5,'http://hydra-compliance.local/?p=56',0,'revision','',0),(57,0,'2026-05-14 14:07:18','2026-05-14 14:07:18','<!-- ── HERO ──────────────────────────────────────────────────────────────────── -->\n<!-- wp:group {\"align\":\"full\",\"style\":{\"color\":{\"background\":\"#0C1E28\"},\"spacing\":{\"padding\":{\"top\":\"80px\",\"bottom\":\"80px\",\"left\":\"24px\",\"right\":\"24px\"}}},\"layout\":{\"type\":\"constrained\",\"contentSize\":\"1100px\"}} -->\n<div class=\"wp-block-group alignfull has-background\" style=\"background-color:#0C1E28;padding-top:80px;padding-bottom:80px;padding-left:24px;padding-right:24px\">\n<!-- wp:html --><div class=\"hydra-pill\"><span class=\"hydra-dot\"></span> Jeddah-based · KSA-focused</div><!-- /wp:html -->\n<!-- wp:heading {\"level\":1,\"style\":{\"color\":{\"text\":\"#ffffff\"},\"typography\":{\"fontSize\":\"clamp(32px,5vw,52px)\",\"fontFamily\":\"\'DM Serif Display\',serif\",\"fontWeight\":\"400\",\"lineHeight\":\"1.2\"},\"spacing\":{\"margin\":{\"top\":\"28px\",\"bottom\":\"20px\"}}}} -->\n<h1 class=\"wp-block-heading\" style=\"color:#ffffff;font-family:\'DM Serif Display\',serif;font-size:clamp(32px,5vw,52px);font-weight:400;line-height:1.2;margin-top:28px;margin-bottom:20px\">Saudi Arabia\'s specialist pharma <em class=\"hydra-gold-italic\">compliance team</em></h1>\n<!-- /wp:heading -->\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"rgba(255,255,255,0.65)\"},\"typography\":{\"fontSize\":\"16px\",\"lineHeight\":\"1.75\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"0\"}}}} -->\n<p style=\"color:rgba(255,255,255,0.65);font-size:16px;line-height:1.75;margin:0\">SFDA-aligned consultants who understand the Kingdom\'s regulatory environment — not international generalists flying in from Dubai.</p>\n<!-- /wp:paragraph -->\n</div>\n<!-- /wp:group -->\n\n<!-- ── COMPANY STORY ───────────────────────────────────────────────────────────── -->\n<!-- wp:group {\"align\":\"full\",\"style\":{\"color\":{\"background\":\"#F5F8F9\"},\"spacing\":{\"padding\":{\"top\":\"72px\",\"bottom\":\"72px\",\"left\":\"24px\",\"right\":\"24px\"}}},\"layout\":{\"type\":\"constrained\",\"contentSize\":\"900px\"}} -->\n<div class=\"wp-block-group alignfull has-background\" style=\"background-color:#F5F8F9;padding-top:72px;padding-bottom:72px;padding-left:24px;padding-right:24px\">\n<!-- wp:heading {\"level\":2,\"textAlign\":\"center\",\"style\":{\"color\":{\"text\":\"#0C1E28\"},\"typography\":{\"fontSize\":\"clamp(24px,3.5vw,36px)\",\"fontFamily\":\"\'DM Serif Display\',serif\",\"fontWeight\":\"400\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"32px\"}}}} -->\n<h2 class=\"wp-block-heading has-text-align-center\" style=\"color:#0C1E28;font-family:\'DM Serif Display\',serif;font-size:clamp(24px,3.5vw,36px);font-weight:400;margin-top:0;margin-bottom:32px\">Why we founded HYDRA</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"color\":{\"text\":\"#3D5460\"},\"typography\":{\"fontSize\":\"16px\",\"lineHeight\":\"1.85\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"20px\"}}}} -->\n<p class=\"has-text-align-center\" style=\"color:#3D5460;font-size:16px;line-height:1.85;margin-top:0;margin-bottom:20px\">HYDRA Quality &amp; Compliance was founded in Jeddah to close a specific gap: Saudi pharmaceutical companies were paying international rates for consultants based in Dubai, London, or Europe — consultants who had limited direct knowledge of the SFDA regulatory framework, arrived for a few days, produced generic reports, and then disappeared.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"color\":{\"text\":\"#3D5460\"},\"typography\":{\"fontSize\":\"16px\",\"lineHeight\":\"1.85\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"20px\"}}}} -->\n<p class=\"has-text-align-center\" style=\"color:#3D5460;font-size:16px;line-height:1.85;margin-top:0;margin-bottom:20px\">Our team is permanently based in the Kingdom. We understand SFDA inspection expectations, GDP requirements in the Saudi market, and the practical realities of operating cold chains and distribution networks across the Kingdom\'s geography. We don\'t parachute in — we\'re here.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"color\":{\"text\":\"#3D5460\"},\"typography\":{\"fontSize\":\"16px\",\"lineHeight\":\"1.85\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"0\"}}}} -->\n<p class=\"has-text-align-center\" style=\"color:#3D5460;font-size:16px;line-height:1.85;margin-top:0;margin-bottom:0\">Every engagement is handled directly by experienced practitioners — not subcontracted to junior staff. When you work with HYDRA, you work with the same team from kick-off to signed report.</p>\n<!-- /wp:paragraph -->\n</div>\n<!-- /wp:group -->\n\n<!-- ── TEAM CREDENTIALS ───────────────────────────────────────────────────────── -->\n<!-- wp:group {\"align\":\"full\",\"style\":{\"color\":{\"background\":\"#ffffff\"},\"spacing\":{\"padding\":{\"top\":\"72px\",\"bottom\":\"72px\",\"left\":\"24px\",\"right\":\"24px\"}}},\"layout\":{\"type\":\"constrained\",\"contentSize\":\"1100px\"}} -->\n<div class=\"wp-block-group alignfull has-white-background-color has-background\" style=\"background-color:#ffffff;padding-top:72px;padding-bottom:72px;padding-left:24px;padding-right:24px\">\n<!-- wp:heading {\"level\":2,\"textAlign\":\"center\",\"style\":{\"color\":{\"text\":\"#0C1E28\"},\"typography\":{\"fontSize\":\"clamp(22px,3vw,32px)\",\"fontFamily\":\"\'DM Serif Display\',serif\",\"fontWeight\":\"400\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"48px\"}}}} -->\n<h2 class=\"wp-block-heading has-text-align-center\" style=\"color:#0C1E28;font-family:\'DM Serif Display\',serif;font-size:clamp(22px,3vw,32px);font-weight:400;margin-top:0;margin-bottom:48px\">The team behind your compliance programme</h2>\n<!-- /wp:heading -->\n<!-- wp:html -->\n<div class=\"hydra-creds-grid\">\n\n  <div class=\"hydra-cred-card\">\n    <div class=\"hydra-cred-number\">15+</div>\n    <h3>Years pharma QA experience</h3>\n    <p>Combined experience across pharmaceutical manufacturers, distributors, and 3PL operators in Saudi Arabia and the wider MENA region.</p>\n  </div>\n\n  <div class=\"hydra-cred-card\">\n    <div class=\"hydra-cred-number\">🇸🇦</div>\n    <h3>SFDA regulatory knowledge</h3>\n    <p>Deep, current knowledge of SFDA guidelines, inspection processes, and GDP requirements specific to the Kingdom — not generic European frameworks.</p>\n  </div>\n\n  <div class=\"hydra-cred-card\">\n    <div class=\"hydra-cred-number\">✓</div>\n    <h3>WHO/EU GDP certified practitioners</h3>\n    <p>All HYDRA practitioners hold relevant certifications in WHO GDP, EU GDP, and pharmaceutical quality systems. Continuous professional development is mandatory.</p>\n  </div>\n\n</div>\n<!-- /wp:html -->\n</div>\n<!-- /wp:group -->\n\n<!-- ── CERTIFICATIONS ─────────────────────────────────────────────────────────── -->\n<!-- wp:group {\"align\":\"full\",\"style\":{\"color\":{\"background\":\"#E0F4F7\"},\"spacing\":{\"padding\":{\"top\":\"64px\",\"bottom\":\"64px\",\"left\":\"24px\",\"right\":\"24px\"}}},\"layout\":{\"type\":\"constrained\",\"contentSize\":\"1100px\"}} -->\n<div class=\"wp-block-group alignfull has-background\" style=\"background-color:#E0F4F7;padding-top:64px;padding-bottom:64px;padding-left:24px;padding-right:24px\">\n<!-- wp:heading {\"level\":2,\"textAlign\":\"center\",\"style\":{\"color\":{\"text\":\"#014F59\"},\"typography\":{\"fontSize\":\"clamp(20px,2.5vw,28px)\",\"fontFamily\":\"\'DM Serif Display\',serif\",\"fontWeight\":\"400\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"36px\"}}}} -->\n<h2 class=\"wp-block-heading has-text-align-center\" style=\"color:#014F59;font-family:\'DM Serif Display\',serif;font-size:clamp(20px,2.5vw,28px);font-weight:400;margin-top:0;margin-bottom:36px\">Frameworks and standards we work to</h2>\n<!-- /wp:heading -->\n<!-- wp:html -->\n<div class=\"hydra-cert-row\">\n  <div class=\"hydra-cert\">WHO GDP</div>\n  <div class=\"hydra-cert\">EU GDP</div>\n  <div class=\"hydra-cert\">ISO 9001:2015</div>\n  <div class=\"hydra-cert\">SFDA Aligned</div>\n  <div class=\"hydra-cert\">GAMP 5</div>\n  <div class=\"hydra-cert\">ICH Q10</div>\n  <div class=\"hydra-cert\">ISPE</div>\n</div>\n<!-- /wp:html -->\n</div>\n<!-- /wp:group -->\n\n<!-- ── WHY HYDRA ───────────────────────────────────────────────────────────────── -->\n<!-- wp:group {\"align\":\"full\",\"style\":{\"color\":{\"background\":\"#ffffff\"},\"spacing\":{\"padding\":{\"top\":\"72px\",\"bottom\":\"72px\",\"left\":\"24px\",\"right\":\"24px\"}}},\"layout\":{\"type\":\"constrained\",\"contentSize\":\"1100px\"}} -->\n<div class=\"wp-block-group alignfull has-white-background-color has-background\" style=\"background-color:#ffffff;padding-top:72px;padding-bottom:72px;padding-left:24px;padding-right:24px\">\n<!-- wp:heading {\"level\":2,\"textAlign\":\"center\",\"style\":{\"color\":{\"text\":\"#0C1E28\"},\"typography\":{\"fontSize\":\"clamp(22px,3vw,32px)\",\"fontFamily\":\"\'DM Serif Display\',serif\",\"fontWeight\":\"400\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"48px\"}}}} -->\n<h2 class=\"wp-block-heading has-text-align-center\" style=\"color:#0C1E28;font-family:\'DM Serif Display\',serif;font-size:clamp(22px,3vw,32px);font-weight:400;margin-top:0;margin-bottom:48px\">Why companies across KSA choose HYDRA</h2>\n<!-- /wp:heading -->\n<!-- wp:html -->\n<div class=\"hydra-why-grid\">\n\n  <div class=\"hydra-why-item\">\n    <div class=\"hydra-why-icon\">📍</div>\n    <h3>Local team, local rates</h3>\n    <p>No international travel costs. No time-zone delays. No per-diem markups. Our team is permanently based in Jeddah and travels within KSA as needed.</p>\n  </div>\n\n  <div class=\"hydra-why-item\">\n    <div class=\"hydra-why-icon\">📋</div>\n    <h3>SFDA-specific knowledge</h3>\n    <p>We understand SFDA inspection priorities and GDP requirements as they are enforced in Saudi Arabia — not how they are interpreted in Europe or the UAE.</p>\n  </div>\n\n  <div class=\"hydra-why-item\">\n    <div class=\"hydra-why-icon\">🔗</div>\n    <h3>End-to-end service</h3>\n    <p>From gap assessment to final validated report and post-audit support, HYDRA handles the full compliance lifecycle under one roof.</p>\n  </div>\n\n  <div class=\"hydra-why-item\">\n    <div class=\"hydra-why-icon\">⚡</div>\n    <h3>48-hour response</h3>\n    <p>We quote within 48 hours of your enquiry and can mobilise within 3–5 business days. For urgent SFDA audit preparation, contact us directly.</p>\n  </div>\n\n</div>\n<!-- /wp:html -->\n</div>\n<!-- /wp:group -->\n\n<!-- ── CTA BANNER ─────────────────────────────────────────────────────────────── -->\n<!-- wp:group {\"align\":\"full\",\"style\":{\"color\":{\"background\":\"#016B7A\"},\"spacing\":{\"padding\":{\"top\":\"72px\",\"bottom\":\"72px\",\"left\":\"24px\",\"right\":\"24px\"}}},\"layout\":{\"type\":\"constrained\",\"contentSize\":\"800px\"}} -->\n<div class=\"wp-block-group alignfull has-background\" style=\"background-color:#016B7A;padding-top:72px;padding-bottom:72px;padding-left:24px;padding-right:24px;text-align:center\">\n<!-- wp:heading {\"level\":2,\"textAlign\":\"center\",\"style\":{\"color\":{\"text\":\"#ffffff\"},\"typography\":{\"fontSize\":\"clamp(24px,4vw,36px)\",\"fontFamily\":\"\'DM Serif Display\',serif\",\"fontWeight\":\"400\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"12px\"}}}} -->\n<h2 class=\"wp-block-heading has-text-align-center\" style=\"color:#ffffff;font-family:\'DM Serif Display\',serif;font-size:clamp(24px,4vw,36px);font-weight:400;margin-top:0;margin-bottom:12px\">Ready to talk compliance?</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"color\":{\"text\":\"rgba(255,255,255,0.8)\"},\"typography\":{\"fontSize\":\"15px\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"32px\"}}}} -->\n<p class=\"has-text-align-center\" style=\"color:rgba(255,255,255,0.8);font-size:15px;margin-top:0;margin-bottom:32px\">Free consultation · Jeddah · Riyadh · Dammam · all of KSA</p>\n<!-- /wp:paragraph -->\n<!-- wp:buttons {\"layout\":{\"type\":\"flex\",\"justifyContent\":\"center\"}} -->\n<div class=\"wp-block-buttons\">\n<!-- wp:button {\"style\":{\"color\":{\"background\":\"#ffffff\",\"text\":\"#016B7A\"},\"border\":{\"radius\":\"6px\"},\"spacing\":{\"padding\":{\"top\":\"16px\",\"bottom\":\"16px\",\"left\":\"40px\",\"right\":\"40px\"}},\"typography\":{\"fontWeight\":\"700\",\"fontSize\":\"15px\"}}} -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"/contact/\" style=\"background-color:#fff;color:#016B7A;border-radius:6px;padding:16px 40px;font-weight:700;font-size:15px\">Get a free quote →</a></div>\n<!-- /wp:button -->\n</div>\n<!-- /wp:buttons -->\n</div>\n<!-- /wp:group -->','About','','inherit','closed','closed','','15-revision-v1','','','2026-05-14 14:07:18','2026-05-14 14:07:18','',15,'http://hydra-compliance.local/?p=57',0,'revision','',0),(58,0,'2026-05-14 14:07:18','2026-05-14 14:07:18','@import url(\'https://fonts.googleapis.com/css2?family=DM+Sans:wght@400;500;600;700&family=DM+Serif+Display:ital@0;1&display=swap\');\n\n:root {\n  --hc-teal:    #016B7A;\n  --hc-dark:    #014F59;\n  --hc-gold:    #C8922A;\n  --hc-navy:    #0C1E28;\n  --hc-muted:   #5E7580;\n  --hc-offwhite:#F5F8F9;\n  --hc-border:  #E0EAF0;\n}\n\n/* ── Global ── */\nbody { font-family: \'DM Sans\', sans-serif; color: var(--hc-navy); }\nh1,h2,h3,h4,h5,h6 { font-family: \'DM Serif Display\', serif; }\n.hydra-gold-italic { color: var(--hc-gold); font-style: italic; }\n\n/* ── Pill tag ── */\n.hydra-pill {\n  display: inline-flex;\n  align-items: center;\n  gap: 8px;\n  background: rgba(200,146,42,0.15);\n  color: var(--hc-gold);\n  border: 1px solid rgba(200,146,42,0.3);\n  border-radius: 100px;\n  padding: 6px 16px;\n  font-size: 13px;\n  font-weight: 500;\n  letter-spacing: 0.02em;\n}\n.hydra-dot {\n  width: 8px;\n  height: 8px;\n  background: var(--hc-gold);\n  border-radius: 50%;\n  flex-shrink: 0;\n  animation: hydra-pulse 2s ease-in-out infinite;\n}\n@keyframes hydra-pulse {\n  0%,100% { box-shadow: 0 0 0 0 rgba(200,146,42,0.6); }\n  50%      { box-shadow: 0 0 0 6px rgba(200,146,42,0); }\n}\n\n/* ── Hero badges ── */\n.hydra-badges {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 8px;\n}\n.hydra-badges span {\n  border: 1px solid rgba(255,255,255,0.2);\n  color: rgba(255,255,255,0.65);\n  border-radius: 4px;\n  padding: 4px 12px;\n  font-size: 12px;\n  letter-spacing: 0.04em;\n}\n\n/* ── Services grid ── */\n.hydra-services-grid {\n  display: grid;\n  grid-template-columns: repeat(3, 1fr);\n  gap: 24px;\n}\n@media (max-width: 768px) {\n  .hydra-services-grid { grid-template-columns: 1fr; }\n}\n@media (min-width: 769px) and (max-width: 1024px) {\n  .hydra-services-grid { grid-template-columns: repeat(2, 1fr); }\n}\n.hydra-card {\n  background: #fff;\n  border: 1px solid var(--hc-border);\n  border-radius: 12px;\n  padding: 28px;\n  transition: box-shadow 0.2s ease, border-color 0.2s ease;\n}\n.hydra-card:hover {\n  border-color: var(--hc-teal);\n  box-shadow: 0 8px 32px rgba(1,107,122,0.1);\n}\n.hydra-card-icon {\n  font-size: 32px;\n  line-height: 1;\n  margin-bottom: 14px;\n}\n.hydra-card h3 {\n  font-family: \'DM Serif Display\', serif;\n  font-size: 18px;\n  font-weight: 400;\n  color: var(--hc-navy);\n  margin: 0 0 8px;\n  line-height: 1.3;\n}\n.hydra-card p {\n  font-size: 14px;\n  color: var(--hc-muted);\n  line-height: 1.6;\n  margin: 0 0 16px;\n}\n.hydra-card a {\n  font-size: 14px;\n  font-weight: 600;\n  color: var(--hc-teal);\n  text-decoration: none;\n}\n.hydra-card a:hover { color: var(--hc-dark); }\n\n/* ── Industries ── */\n.hydra-industries {\n  display: grid;\n  grid-template-columns: repeat(6, 1fr);\n  gap: 16px;\n}\n@media (max-width: 768px) {\n  .hydra-industries { grid-template-columns: repeat(3, 1fr); }\n}\n@media (max-width: 480px) {\n  .hydra-industries { grid-template-columns: repeat(2, 1fr); }\n}\n.hydra-industry {\n  background: rgba(1,107,122,0.08);\n  border: 1px solid rgba(1,79,89,0.15);\n  border-radius: 10px;\n  padding: 20px 16px;\n  text-align: center;\n  transition: background 0.2s;\n}\n.hydra-industry:hover { background: rgba(1,107,122,0.14); }\n.hydra-industry span { font-size: 28px; display: block; margin-bottom: 8px; }\n.hydra-industry p { font-size: 13px; font-weight: 600; color: var(--hc-dark); margin: 0; }\n\n/* ── FAQ ── */\n.wp-block-details summary {\n  list-style: none;\n  font-size: 16px;\n  font-weight: 600;\n  color: var(--hc-navy);\n  cursor: pointer;\n  display: flex;\n  justify-content: space-between;\n  align-items: center;\n}\n.wp-block-details summary::after {\n  content: \'+\';\n  font-size: 20px;\n  color: var(--hc-teal);\n  font-weight: 300;\n  transition: transform 0.2s;\n}\n.wp-block-details[open] summary::after { content: \'−\'; }\n\n/* ── Header logo ── */\n.hydra-logo-hy {\n  font-family: \'DM Serif Display\', serif;\n  font-size: 22px;\n  color: var(--hc-gold);\n  font-style: italic;\n}\n.hydra-logo-text {\n  font-family: \'DM Sans\', sans-serif;\n  font-size: 20px;\n  font-weight: 700;\n  color: var(--hc-navy);\n  letter-spacing: -0.02em;\n}\n.hydra-footer-logo { display: flex; align-items: baseline; gap: 2px; }\n.hydra-footer-logo .hydra-logo-hy { color: var(--hc-gold); }\n.hydra-footer-logo .hydra-logo-text { color: #fff; }\n\n/* ── Footer ── */\n.hydra-footer-links {\n  list-style: none;\n  padding: 0;\n  margin: 0;\n}\n.hydra-footer-links li { margin-bottom: 10px; }\n.hydra-footer-links a {\n  color: rgba(255,255,255,0.6);\n  font-size: 14px;\n  text-decoration: none;\n  transition: color 0.15s;\n}\n.hydra-footer-links a:hover { color: #fff; }\n.hydra-footer-bar {\n  border-top: 1px solid rgba(255,255,255,0.08);\n  padding: 20px 0;\n  display: flex;\n  gap: 32px;\n  flex-wrap: wrap;\n  font-size: 13px;\n  color: rgba(255,255,255,0.35);\n}\n\n/* ── Kadence header overrides ── */\n.site-header .header-navigation .nav-menu > li > a {\n  font-family: \'DM Sans\', sans-serif;\n  font-size: 14px;\n  font-weight: 500;\n  color: var(--hc-navy);\n}\n.site-header {\n  border-bottom: 1px solid var(--hc-border);\n}\n\n/* ── Button outline fix ── */\n.wp-block-button.is-style-outline .wp-block-button__link {\n  background: transparent !important;\n}\n/* ── Site logo text fallback (if SVG does not render) ── */\n.custom-logo-link { text-decoration: none; }\n.site-branding { display: flex; align-items: center; }\n\n/* ── Fullwidth page: remove default padding ── */\n.content-style-unboxed .entry-content > * { max-width: none !important; padding-left: 0 !important; padding-right: 0 !important; }\n.page-template-default.page .entry-content .alignfull { margin-left: calc(-1 * var(--wp--style--root--padding-left, 0px)); margin-right: calc(-1 * var(--wp--style--root--padding-right, 0px)); width: calc(100% + var(--wp--style--root--padding-left, 0px) + var(--wp--style--root--padding-right, 0px)); }\n\n/* ── Remove Kadence default page hero/title area ── */\n.hide-title .entry-header { display: none; }\n\n/* ══ SERVICE PAGE STYLES ══════════════════════════════════════════════════ */\n\n/* Breadcrumb bar */\n.hydra-breadcrumb-bar .breadcrumbs,\n.hydra-breadcrumb-bar .rank-math-breadcrumb {\n  font-size: 13px;\n  color: rgba(255,255,255,0.5);\n  padding: 0;\n}\n.hydra-breadcrumb-bar .breadcrumbs a,\n.hydra-breadcrumb-bar .rank-math-breadcrumb a {\n  color: rgba(255,255,255,0.6);\n  text-decoration: none;\n}\n.hydra-breadcrumb-bar .breadcrumbs a:hover,\n.hydra-breadcrumb-bar .rank-math-breadcrumb a:hover { color: #fff; }\n\n/* Checkmark list */\n.hydra-checklist {\n  list-style: none;\n  padding: 0;\n  margin: 0 0 24px;\n}\n.hydra-checklist li {\n  position: relative;\n  padding-left: 24px;\n  font-size: 15px;\n  color: #3D5460;\n  line-height: 1.7;\n  margin-bottom: 8px;\n}\n.hydra-checklist li::before {\n  content: \'✓\';\n  position: absolute;\n  left: 0;\n  top: 0;\n  color: #016B7A;\n  font-weight: 700;\n}\n\n/* Process ordered list */\n.hydra-process-list {\n  padding-left: 0;\n  margin: 0 0 24px;\n  counter-reset: process-step;\n  list-style: none;\n}\n.hydra-process-list li {\n  counter-increment: process-step;\n  position: relative;\n  padding-left: 44px;\n  font-size: 15px;\n  color: #3D5460;\n  line-height: 1.7;\n  margin-bottom: 16px;\n}\n.hydra-process-list li::before {\n  content: counter(process-step);\n  position: absolute;\n  left: 0;\n  top: 0;\n  width: 28px;\n  height: 28px;\n  background: #016B7A;\n  color: #fff;\n  border-radius: 50%;\n  font-size: 13px;\n  font-weight: 700;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  line-height: 1;\n}\n.hydra-process-list li strong { color: #0C1E28; }\n\n/* Quote card */\n.hydra-quote-card {\n  position: sticky;\n  top: 100px;\n}\n.hydra-quote-card .wpforms-form .wpforms-field-label {\n  font-size: 13px;\n  font-weight: 600;\n  color: #5E7580;\n  margin-bottom: 4px;\n}\n.hydra-quote-card .wpforms-form input[type=\"text\"],\n.hydra-quote-card .wpforms-form input[type=\"email\"],\n.hydra-quote-card .wpforms-form select {\n  width: 100%;\n  border: 1px solid #E0EAF0;\n  border-radius: 6px;\n  padding: 10px 12px;\n  font-size: 14px;\n  font-family: \'DM Sans\', sans-serif;\n  color: #0C1E28;\n  background: #F5F8F9;\n  transition: border-color 0.15s;\n}\n.hydra-quote-card .wpforms-form input:focus,\n.hydra-quote-card .wpforms-form select:focus {\n  border-color: #016B7A;\n  outline: none;\n  background: #fff;\n}\n.hydra-quote-card .wpforms-form .wpforms-submit-container {\n  margin-top: 16px;\n}\n.hydra-quote-card .wpforms-form button[type=\"submit\"],\n.hydra-quote-card .wpforms-form .wpforms-submit {\n  width: 100%;\n  background: #C8922A;\n  color: #fff;\n  border: none;\n  border-radius: 6px;\n  padding: 12px 20px;\n  font-size: 14px;\n  font-weight: 700;\n  font-family: \'DM Sans\', sans-serif;\n  cursor: pointer;\n  transition: background 0.2s;\n}\n.hydra-quote-card .wpforms-form button[type=\"submit\"]:hover,\n.hydra-quote-card .wpforms-form .wpforms-submit:hover { background: #b07a22; }\n\n/* Contact card */\n.hydra-contact-list {\n  list-style: none;\n  padding: 0;\n  margin: 0;\n}\n.hydra-contact-list li {\n  display: flex;\n  align-items: flex-start;\n  gap: 10px;\n  font-size: 14px;\n  color: #3D5460;\n  line-height: 1.6;\n  margin-bottom: 10px;\n}\n.hydra-contact-list li:last-child { margin-bottom: 0; }\n.hydra-contact-list li span { font-size: 16px; flex-shrink: 0; margin-top: 1px; }\n\n/* Related services grid */\n.hydra-related-grid {\n  display: grid;\n  grid-template-columns: repeat(3, 1fr);\n  gap: 24px;\n}\n@media (max-width: 768px) {\n  .hydra-related-grid { grid-template-columns: 1fr; }\n}\n.hydra-related-card {\n  background: #F5F8F9;\n  border: 1px solid #E0EAF0;\n  border-radius: 12px;\n  padding: 24px;\n  transition: border-color 0.2s, box-shadow 0.2s;\n}\n.hydra-related-card:hover {\n  border-color: #016B7A;\n  box-shadow: 0 4px 20px rgba(1,107,122,0.08);\n}\n.hydra-related-icon { font-size: 28px; margin-bottom: 10px; }\n.hydra-related-card h3 {\n  font-family: \'DM Serif Display\', serif;\n  font-size: 17px;\n  font-weight: 400;\n  color: #0C1E28;\n  margin: 0 0 6px;\n}\n.hydra-related-card p {\n  font-size: 13px;\n  color: #5E7580;\n  line-height: 1.6;\n  margin: 0 0 12px;\n}\n.hydra-related-card a {\n  font-size: 13px;\n  font-weight: 600;\n  color: #016B7A;\n  text-decoration: none;\n}\n.hydra-related-card a:hover { color: #014F59; }\n\n/* Sidebar sticky on desktop */\n@media (min-width: 768px) {\n  .hydra-svc-sidebar { position: sticky; top: 90px; align-self: flex-start; }\n}\n/* ══ ABOUT PAGE ══════════════════════════════════════════════════════════ */\n.hydra-creds-grid {\n  display: grid;\n  grid-template-columns: repeat(3, 1fr);\n  gap: 28px;\n}\n@media (max-width: 768px) {\n  .hydra-creds-grid { grid-template-columns: 1fr; }\n}\n.hydra-cred-card {\n  border: 1px solid #E0EAF0;\n  border-radius: 12px;\n  padding: 32px 28px;\n  text-align: center;\n  background: #fff;\n  transition: box-shadow 0.2s;\n}\n.hydra-cred-card:hover { box-shadow: 0 8px 32px rgba(1,107,122,0.08); }\n.hydra-cred-number {\n  font-family: \'DM Serif Display\', serif;\n  font-size: 40px;\n  color: #016B7A;\n  margin-bottom: 12px;\n  line-height: 1;\n}\n.hydra-cred-card h3 {\n  font-family: \'DM Serif Display\', serif;\n  font-size: 18px;\n  font-weight: 400;\n  color: #0C1E28;\n  margin: 0 0 10px;\n}\n.hydra-cred-card p { font-size: 14px; color: #5E7580; line-height: 1.7; margin: 0; }\n\n/* Certifications */\n.hydra-cert-row {\n  display: flex;\n  flex-wrap: wrap;\n  justify-content: center;\n  gap: 12px;\n}\n.hydra-cert {\n  background: rgba(1,107,122,0.1);\n  border: 1px solid rgba(1,79,89,0.2);\n  color: #014F59;\n  border-radius: 100px;\n  padding: 8px 20px;\n  font-size: 13px;\n  font-weight: 600;\n  letter-spacing: 0.03em;\n}\n\n/* Why HYDRA grid */\n.hydra-why-grid {\n  display: grid;\n  grid-template-columns: repeat(2, 1fr);\n  gap: 32px;\n}\n@media (max-width: 640px) {\n  .hydra-why-grid { grid-template-columns: 1fr; }\n}\n.hydra-why-item { display: flex; flex-direction: column; gap: 10px; }\n.hydra-why-icon { font-size: 28px; }\n.hydra-why-item h3 {\n  font-family: \'DM Serif Display\', serif;\n  font-size: 20px;\n  font-weight: 400;\n  color: #0C1E28;\n  margin: 0;\n}\n.hydra-why-item p { font-size: 15px; color: #5E7580; line-height: 1.7; margin: 0; }','Custom CSS','','inherit','closed','closed','','40-revision-v1','','','2026-05-14 14:07:18','2026-05-14 14:07:18','',40,'http://hydra-compliance.local/?p=58',0,'revision','',0),(59,0,'2026-05-14 14:07:23','2026-05-14 14:07:23','{\"id\":0,\"field_id\":7,\"fields\":{\"1\":{\"id\":\"1\",\"type\":\"text\",\"label\":\"Full Name\",\"required\":\"1\",\"size\":\"medium\",\"placeholder\":\"Your full name\"},\"2\":{\"id\":\"2\",\"type\":\"email\",\"label\":\"Email Address\",\"required\":\"1\",\"size\":\"medium\",\"placeholder\":\"you@company.com\"},\"3\":{\"id\":\"3\",\"type\":\"text\",\"label\":\"Phone \\/ WhatsApp\",\"required\":\"1\",\"size\":\"medium\",\"placeholder\":\"+966 xx xxx xxxx\"},\"4\":{\"id\":\"4\",\"type\":\"text\",\"label\":\"Company Name\",\"required\":\"0\",\"size\":\"medium\",\"placeholder\":\"Your company\"},\"5\":{\"id\":\"5\",\"type\":\"select\",\"label\":\"Service Needed\",\"required\":\"0\",\"choices\":{\"1\":{\"label\":\"\\u2014 Select a service \\u2014\",\"value\":\"\",\"default\":\"1\"},\"2\":{\"label\":\"Temperature Mapping\",\"value\":\"Temperature Mapping\",\"default\":\"\"},\"3\":{\"label\":\"Validation & Qualification\",\"value\":\"Validation & Qualification\",\"default\":\"\"},\"4\":{\"label\":\"GDP Compliance\",\"value\":\"GDP Compliance\",\"default\":\"\"},\"5\":{\"label\":\"Pharma Consulting\",\"value\":\"Pharma Consulting\",\"default\":\"\"},\"6\":{\"label\":\"Cold Storage Compliance\",\"value\":\"Cold Storage Compliance\",\"default\":\"\"},\"7\":{\"label\":\"Pharma QMS\",\"value\":\"Pharma QMS\",\"default\":\"\"},\"8\":{\"label\":\"Thermal Packaging\",\"value\":\"Thermal Packaging\",\"default\":\"\"},\"9\":{\"label\":\"Computer System Validation\",\"value\":\"CSV\",\"default\":\"\"},\"10\":{\"label\":\"Cold Chain Solutions\",\"value\":\"Cold Chain Solutions\",\"default\":\"\"},\"11\":{\"label\":\"General Enquiry\",\"value\":\"General Enquiry\",\"default\":\"\"}}},\"6\":{\"id\":\"6\",\"type\":\"textarea\",\"label\":\"Message\",\"required\":\"0\",\"size\":\"medium\",\"placeholder\":\"Tell us about your facility, project, or requirement\\u2026\",\"rows\":5}},\"settings\":{\"form_title\":\"Contact HYDRA\",\"form_desc\":\"\",\"submit_text\":\"Send enquiry \\u2192\",\"submit_text_processing\":\"Sending\\u2026\",\"ajax_submit\":\"1\",\"form_class\":\"hydra-contact-form\",\"notification_enable\":\"1\",\"notifications\":{\"1\":{\"notification_name\":\"Admin Notification\",\"email\":\"info@hydratl.com\",\"subject\":\"New enquiry \\u2014 {field_id=\\\"5\\\"} \\u2014 {field_id=\\\"1\\\"}\",\"sender_name\":\"HYDRA Website\",\"sender_address\":\"{admin_email}\",\"replyto\":\"{field_id=\\\"2\\\"}\",\"message\":\"{all_fields}\"}},\"confirmations\":{\"1\":{\"name\":\"Default Confirmation\",\"type\":\"message\",\"message\":\"<p>Thank you. We\'ll be in touch within 24 hours.<\\/p>\",\"message_scroll\":\"1\"}}},\"meta\":{\"template\":\"blank\"},\"payments\":[]}','HYDRA Contact Form','','publish','closed','closed','','hydra-contact-form','','','2026-05-14 14:07:23','2026-05-14 14:07:23','',0,'http://hydra-compliance.local/?post_type=wpforms&p=59',0,'wpforms','',0),(60,0,'2026-05-14 14:07:23','2026-05-14 14:07:23','<!-- wp:group {\"align\":\"full\",\"style\":{\"color\":{\"background\":\"#ffffff\"},\"spacing\":{\"padding\":{\"top\":\"72px\",\"bottom\":\"72px\",\"left\":\"24px\",\"right\":\"24px\"}}},\"layout\":{\"type\":\"constrained\",\"contentSize\":\"1100px\"}} -->\n<div class=\"wp-block-group alignfull has-white-background-color has-background\" style=\"background-color:#ffffff;padding-top:72px;padding-bottom:72px;padding-left:24px;padding-right:24px\">\n\n<!-- wp:columns {\"isStackedOnMobile\":true,\"style\":{\"spacing\":{\"blockGap\":\"64px\"}}} -->\n<div class=\"wp-block-columns\">\n\n<!-- LEFT COLUMN: contact info + map -->\n<!-- wp:column {\"width\":\"50%\"} -->\n<div class=\"wp-block-column\" style=\"flex-basis:50%\">\n\n<!-- wp:heading {\"level\":1,\"style\":{\"color\":{\"text\":\"#0C1E28\"},\"typography\":{\"fontSize\":\"clamp(32px,4vw,48px)\",\"fontFamily\":\"\'DM Serif Display\',serif\",\"fontWeight\":\"400\",\"lineHeight\":\"1.15\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"12px\"}}}} -->\n<h1 class=\"wp-block-heading\" style=\"color:#0C1E28;font-family:\'DM Serif Display\',serif;font-size:clamp(32px,4vw,48px);font-weight:400;line-height:1.15;margin-top:0;margin-bottom:12px\">Get in touch</h1>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#5E7580\"},\"typography\":{\"fontSize\":\"16px\",\"lineHeight\":\"1.6\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"40px\"}}}} -->\n<p style=\"color:#5E7580;font-size:16px;line-height:1.6;margin-top:0;margin-bottom:40px\">Free consultation. Response within 24 hours.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:html -->\n<ul class=\"hydra-contact-page-list\">\n  <li>\n    <span class=\"hydra-contact-icon\">📍</span>\n    <div>\n      <strong>Head Office</strong>\n      <span>3rd Floor, Alnankeel Business Center<br>Alhmra District, Jeddah, Saudi Arabia</span>\n    </div>\n  </li>\n  <li>\n    <span class=\"hydra-contact-icon\">📞</span>\n    <div>\n      <strong>Phone / WhatsApp</strong>\n      <span><a href=\"tel:+966\">+966 — — — — —</a></span>\n    </div>\n  </li>\n  <li>\n    <span class=\"hydra-contact-icon\">✉️</span>\n    <div>\n      <strong>Email</strong>\n      <span><a href=\"mailto:info@hydratl.com\">info@hydratl.com</a></span>\n    </div>\n  </li>\n  <li>\n    <span class=\"hydra-contact-icon\">🌐</span>\n    <div>\n      <strong>Website</strong>\n      <span><a href=\"https://hydracompliance.com\">hydracompliance.com</a></span>\n    </div>\n  </li>\n  <li>\n    <span class=\"hydra-contact-icon\">🗺️</span>\n    <div>\n      <strong>Regions served</strong>\n      <span>KSA &nbsp;·&nbsp; UAE</span>\n    </div>\n  </li>\n  <li>\n    <span class=\"hydra-contact-icon\">⏱</span>\n    <div>\n      <strong>Office hours</strong>\n      <span>Sunday–Thursday, 08:00–17:00 AST</span>\n    </div>\n  </li>\n</ul>\n<!-- /wp:html -->\n\n<!-- wp:spacer {\"height\":\"32px\"} --><div style=\"height:32px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div><!-- /wp:spacer -->\n\n<!-- wp:html -->\n<div class=\"hydra-map-wrap\">\n  <iframe\n    src=\"https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3710.5448739393066!2d39.17061051501!3d21.54330959083!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x15c3d01fb1137e29%3A0xa9e4a1011c973c6b!2sAl%20Hamra%2C%20Jeddah%20Saudi%20Arabia!5e0!3m2!1sen!2ssa!4v1715000000000!5m2!1sen!2ssa\"\n    width=\"100%\"\n    height=\"260\"\n    style=\"border:0;border-radius:10px;\"\n    allowfullscreen=\"\"\n    loading=\"lazy\"\n    referrerpolicy=\"no-referrer-when-downgrade\"\n    title=\"HYDRA Quality &amp; Compliance — Jeddah, Saudi Arabia\">\n  </iframe>\n</div>\n<!-- /wp:html -->\n\n</div>\n<!-- /wp:column -->\n\n<!-- RIGHT COLUMN: contact form -->\n<!-- wp:column {\"width\":\"50%\",\"className\":\"hydra-contact-form-col\"} -->\n<div class=\"wp-block-column hydra-contact-form-col\" style=\"flex-basis:50%\">\n\n<!-- wp:group {\"className\":\"hydra-contact-form-card\",\"style\":{\"color\":{\"background\":\"#ffffff\"},\"border\":{\"radius\":\"14px\",\"color\":\"#E0EAF0\",\"style\":\"solid\",\"width\":\"1px\"},\"spacing\":{\"padding\":{\"top\":\"36px\",\"bottom\":\"36px\",\"left\":\"36px\",\"right\":\"36px\"}},\"shadow\":\"0 8px 40px rgba(12,30,40,0.08)\"}} -->\n<div class=\"wp-block-group hydra-contact-form-card has-white-background-color has-background\" style=\"background-color:#ffffff;border-radius:14px;border:1px solid #E0EAF0;padding:36px;box-shadow:0 8px 40px rgba(12,30,40,0.08)\">\n\n<!-- wp:heading {\"level\":3,\"style\":{\"color\":{\"text\":\"#0C1E28\"},\"typography\":{\"fontSize\":\"22px\",\"fontFamily\":\"\'DM Serif Display\',serif\",\"fontWeight\":\"400\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"6px\"}}}} -->\n<h3 class=\"wp-block-heading\" style=\"color:#0C1E28;font-family:\'DM Serif Display\',serif;font-size:22px;font-weight:400;margin-top:0;margin-bottom:6px\">Send us an enquiry</h3>\n<!-- /wp:heading -->\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#5E7580\"},\"typography\":{\"fontSize\":\"14px\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"24px\"}}}} -->\n<p style=\"color:#5E7580;font-size:14px;margin-top:0;margin-bottom:24px\">We\'ll respond within 24 hours. All enquiries are treated confidentially.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:shortcode -->[wpforms id=\"59\"]<!-- /wp:shortcode -->\n\n</div>\n<!-- /wp:group -->\n\n</div>\n<!-- /wp:column -->\n\n</div>\n<!-- /wp:columns -->\n</div>\n<!-- /wp:group -->\n\n<!-- CTA BANNER -->\n<!-- wp:group {\"align\":\"full\",\"style\":{\"color\":{\"background\":\"#016B7A\"},\"spacing\":{\"padding\":{\"top\":\"64px\",\"bottom\":\"64px\",\"left\":\"24px\",\"right\":\"24px\"}}},\"layout\":{\"type\":\"constrained\",\"contentSize\":\"800px\"}} -->\n<div class=\"wp-block-group alignfull has-background\" style=\"background-color:#016B7A;padding-top:64px;padding-bottom:64px;padding-left:24px;padding-right:24px;text-align:center\">\n<!-- wp:heading {\"level\":2,\"textAlign\":\"center\",\"style\":{\"color\":{\"text\":\"#ffffff\"},\"typography\":{\"fontSize\":\"clamp(22px,3.5vw,34px)\",\"fontFamily\":\"\'DM Serif Display\',serif\",\"fontWeight\":\"400\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"10px\"}}}} -->\n<h2 class=\"wp-block-heading has-text-align-center\" style=\"color:#ffffff;font-family:\'DM Serif Display\',serif;font-size:clamp(22px,3.5vw,34px);font-weight:400;margin-top:0;margin-bottom:10px\">Need a quick answer?</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"color\":{\"text\":\"rgba(255,255,255,0.8)\"},\"typography\":{\"fontSize\":\"15px\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"28px\"}}}} -->\n<p class=\"has-text-align-center\" style=\"color:rgba(255,255,255,0.8);font-size:15px;margin-top:0;margin-bottom:28px\">WhatsApp or email — we respond within 24 hours, every working day.</p>\n<!-- /wp:paragraph -->\n<!-- wp:buttons {\"layout\":{\"type\":\"flex\",\"justifyContent\":\"center\"},\"style\":{\"spacing\":{\"blockGap\":\"12px\"}}} -->\n<div class=\"wp-block-buttons\">\n<!-- wp:button {\"style\":{\"color\":{\"background\":\"#ffffff\",\"text\":\"#016B7A\"},\"border\":{\"radius\":\"6px\"},\"spacing\":{\"padding\":{\"top\":\"14px\",\"bottom\":\"14px\",\"left\":\"32px\",\"right\":\"32px\"}},\"typography\":{\"fontWeight\":\"700\",\"fontSize\":\"15px\"}}} -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"mailto:info@hydratl.com\" style=\"background-color:#fff;color:#016B7A;border-radius:6px;padding:14px 32px;font-weight:700;font-size:15px\">Email us →</a></div>\n<!-- /wp:button -->\n</div>\n<!-- /wp:buttons -->\n</div>\n<!-- /wp:group -->','Contact','','inherit','closed','closed','','16-revision-v1','','','2026-05-14 14:07:23','2026-05-14 14:07:23','',16,'http://hydra-compliance.local/?p=60',0,'revision','',0),(61,0,'2026-05-14 14:07:23','2026-05-14 14:07:23','@import url(\'https://fonts.googleapis.com/css2?family=DM+Sans:wght@400;500;600;700&family=DM+Serif+Display:ital@0;1&display=swap\');\n\n:root {\n  --hc-teal:    #016B7A;\n  --hc-dark:    #014F59;\n  --hc-gold:    #C8922A;\n  --hc-navy:    #0C1E28;\n  --hc-muted:   #5E7580;\n  --hc-offwhite:#F5F8F9;\n  --hc-border:  #E0EAF0;\n}\n\n/* ── Global ── */\nbody { font-family: \'DM Sans\', sans-serif; color: var(--hc-navy); }\nh1,h2,h3,h4,h5,h6 { font-family: \'DM Serif Display\', serif; }\n.hydra-gold-italic { color: var(--hc-gold); font-style: italic; }\n\n/* ── Pill tag ── */\n.hydra-pill {\n  display: inline-flex;\n  align-items: center;\n  gap: 8px;\n  background: rgba(200,146,42,0.15);\n  color: var(--hc-gold);\n  border: 1px solid rgba(200,146,42,0.3);\n  border-radius: 100px;\n  padding: 6px 16px;\n  font-size: 13px;\n  font-weight: 500;\n  letter-spacing: 0.02em;\n}\n.hydra-dot {\n  width: 8px;\n  height: 8px;\n  background: var(--hc-gold);\n  border-radius: 50%;\n  flex-shrink: 0;\n  animation: hydra-pulse 2s ease-in-out infinite;\n}\n@keyframes hydra-pulse {\n  0%,100% { box-shadow: 0 0 0 0 rgba(200,146,42,0.6); }\n  50%      { box-shadow: 0 0 0 6px rgba(200,146,42,0); }\n}\n\n/* ── Hero badges ── */\n.hydra-badges {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 8px;\n}\n.hydra-badges span {\n  border: 1px solid rgba(255,255,255,0.2);\n  color: rgba(255,255,255,0.65);\n  border-radius: 4px;\n  padding: 4px 12px;\n  font-size: 12px;\n  letter-spacing: 0.04em;\n}\n\n/* ── Services grid ── */\n.hydra-services-grid {\n  display: grid;\n  grid-template-columns: repeat(3, 1fr);\n  gap: 24px;\n}\n@media (max-width: 768px) {\n  .hydra-services-grid { grid-template-columns: 1fr; }\n}\n@media (min-width: 769px) and (max-width: 1024px) {\n  .hydra-services-grid { grid-template-columns: repeat(2, 1fr); }\n}\n.hydra-card {\n  background: #fff;\n  border: 1px solid var(--hc-border);\n  border-radius: 12px;\n  padding: 28px;\n  transition: box-shadow 0.2s ease, border-color 0.2s ease;\n}\n.hydra-card:hover {\n  border-color: var(--hc-teal);\n  box-shadow: 0 8px 32px rgba(1,107,122,0.1);\n}\n.hydra-card-icon {\n  font-size: 32px;\n  line-height: 1;\n  margin-bottom: 14px;\n}\n.hydra-card h3 {\n  font-family: \'DM Serif Display\', serif;\n  font-size: 18px;\n  font-weight: 400;\n  color: var(--hc-navy);\n  margin: 0 0 8px;\n  line-height: 1.3;\n}\n.hydra-card p {\n  font-size: 14px;\n  color: var(--hc-muted);\n  line-height: 1.6;\n  margin: 0 0 16px;\n}\n.hydra-card a {\n  font-size: 14px;\n  font-weight: 600;\n  color: var(--hc-teal);\n  text-decoration: none;\n}\n.hydra-card a:hover { color: var(--hc-dark); }\n\n/* ── Industries ── */\n.hydra-industries {\n  display: grid;\n  grid-template-columns: repeat(6, 1fr);\n  gap: 16px;\n}\n@media (max-width: 768px) {\n  .hydra-industries { grid-template-columns: repeat(3, 1fr); }\n}\n@media (max-width: 480px) {\n  .hydra-industries { grid-template-columns: repeat(2, 1fr); }\n}\n.hydra-industry {\n  background: rgba(1,107,122,0.08);\n  border: 1px solid rgba(1,79,89,0.15);\n  border-radius: 10px;\n  padding: 20px 16px;\n  text-align: center;\n  transition: background 0.2s;\n}\n.hydra-industry:hover { background: rgba(1,107,122,0.14); }\n.hydra-industry span { font-size: 28px; display: block; margin-bottom: 8px; }\n.hydra-industry p { font-size: 13px; font-weight: 600; color: var(--hc-dark); margin: 0; }\n\n/* ── FAQ ── */\n.wp-block-details summary {\n  list-style: none;\n  font-size: 16px;\n  font-weight: 600;\n  color: var(--hc-navy);\n  cursor: pointer;\n  display: flex;\n  justify-content: space-between;\n  align-items: center;\n}\n.wp-block-details summary::after {\n  content: \'+\';\n  font-size: 20px;\n  color: var(--hc-teal);\n  font-weight: 300;\n  transition: transform 0.2s;\n}\n.wp-block-details[open] summary::after { content: \'−\'; }\n\n/* ── Header logo ── */\n.hydra-logo-hy {\n  font-family: \'DM Serif Display\', serif;\n  font-size: 22px;\n  color: var(--hc-gold);\n  font-style: italic;\n}\n.hydra-logo-text {\n  font-family: \'DM Sans\', sans-serif;\n  font-size: 20px;\n  font-weight: 700;\n  color: var(--hc-navy);\n  letter-spacing: -0.02em;\n}\n.hydra-footer-logo { display: flex; align-items: baseline; gap: 2px; }\n.hydra-footer-logo .hydra-logo-hy { color: var(--hc-gold); }\n.hydra-footer-logo .hydra-logo-text { color: #fff; }\n\n/* ── Footer ── */\n.hydra-footer-links {\n  list-style: none;\n  padding: 0;\n  margin: 0;\n}\n.hydra-footer-links li { margin-bottom: 10px; }\n.hydra-footer-links a {\n  color: rgba(255,255,255,0.6);\n  font-size: 14px;\n  text-decoration: none;\n  transition: color 0.15s;\n}\n.hydra-footer-links a:hover { color: #fff; }\n.hydra-footer-bar {\n  border-top: 1px solid rgba(255,255,255,0.08);\n  padding: 20px 0;\n  display: flex;\n  gap: 32px;\n  flex-wrap: wrap;\n  font-size: 13px;\n  color: rgba(255,255,255,0.35);\n}\n\n/* ── Kadence header overrides ── */\n.site-header .header-navigation .nav-menu > li > a {\n  font-family: \'DM Sans\', sans-serif;\n  font-size: 14px;\n  font-weight: 500;\n  color: var(--hc-navy);\n}\n.site-header {\n  border-bottom: 1px solid var(--hc-border);\n}\n\n/* ── Button outline fix ── */\n.wp-block-button.is-style-outline .wp-block-button__link {\n  background: transparent !important;\n}\n/* ── Site logo text fallback (if SVG does not render) ── */\n.custom-logo-link { text-decoration: none; }\n.site-branding { display: flex; align-items: center; }\n\n/* ── Fullwidth page: remove default padding ── */\n.content-style-unboxed .entry-content > * { max-width: none !important; padding-left: 0 !important; padding-right: 0 !important; }\n.page-template-default.page .entry-content .alignfull { margin-left: calc(-1 * var(--wp--style--root--padding-left, 0px)); margin-right: calc(-1 * var(--wp--style--root--padding-right, 0px)); width: calc(100% + var(--wp--style--root--padding-left, 0px) + var(--wp--style--root--padding-right, 0px)); }\n\n/* ── Remove Kadence default page hero/title area ── */\n.hide-title .entry-header { display: none; }\n\n/* ══ SERVICE PAGE STYLES ══════════════════════════════════════════════════ */\n\n/* Breadcrumb bar */\n.hydra-breadcrumb-bar .breadcrumbs,\n.hydra-breadcrumb-bar .rank-math-breadcrumb {\n  font-size: 13px;\n  color: rgba(255,255,255,0.5);\n  padding: 0;\n}\n.hydra-breadcrumb-bar .breadcrumbs a,\n.hydra-breadcrumb-bar .rank-math-breadcrumb a {\n  color: rgba(255,255,255,0.6);\n  text-decoration: none;\n}\n.hydra-breadcrumb-bar .breadcrumbs a:hover,\n.hydra-breadcrumb-bar .rank-math-breadcrumb a:hover { color: #fff; }\n\n/* Checkmark list */\n.hydra-checklist {\n  list-style: none;\n  padding: 0;\n  margin: 0 0 24px;\n}\n.hydra-checklist li {\n  position: relative;\n  padding-left: 24px;\n  font-size: 15px;\n  color: #3D5460;\n  line-height: 1.7;\n  margin-bottom: 8px;\n}\n.hydra-checklist li::before {\n  content: \'✓\';\n  position: absolute;\n  left: 0;\n  top: 0;\n  color: #016B7A;\n  font-weight: 700;\n}\n\n/* Process ordered list */\n.hydra-process-list {\n  padding-left: 0;\n  margin: 0 0 24px;\n  counter-reset: process-step;\n  list-style: none;\n}\n.hydra-process-list li {\n  counter-increment: process-step;\n  position: relative;\n  padding-left: 44px;\n  font-size: 15px;\n  color: #3D5460;\n  line-height: 1.7;\n  margin-bottom: 16px;\n}\n.hydra-process-list li::before {\n  content: counter(process-step);\n  position: absolute;\n  left: 0;\n  top: 0;\n  width: 28px;\n  height: 28px;\n  background: #016B7A;\n  color: #fff;\n  border-radius: 50%;\n  font-size: 13px;\n  font-weight: 700;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  line-height: 1;\n}\n.hydra-process-list li strong { color: #0C1E28; }\n\n/* Quote card */\n.hydra-quote-card {\n  position: sticky;\n  top: 100px;\n}\n.hydra-quote-card .wpforms-form .wpforms-field-label {\n  font-size: 13px;\n  font-weight: 600;\n  color: #5E7580;\n  margin-bottom: 4px;\n}\n.hydra-quote-card .wpforms-form input[type=\"text\"],\n.hydra-quote-card .wpforms-form input[type=\"email\"],\n.hydra-quote-card .wpforms-form select {\n  width: 100%;\n  border: 1px solid #E0EAF0;\n  border-radius: 6px;\n  padding: 10px 12px;\n  font-size: 14px;\n  font-family: \'DM Sans\', sans-serif;\n  color: #0C1E28;\n  background: #F5F8F9;\n  transition: border-color 0.15s;\n}\n.hydra-quote-card .wpforms-form input:focus,\n.hydra-quote-card .wpforms-form select:focus {\n  border-color: #016B7A;\n  outline: none;\n  background: #fff;\n}\n.hydra-quote-card .wpforms-form .wpforms-submit-container {\n  margin-top: 16px;\n}\n.hydra-quote-card .wpforms-form button[type=\"submit\"],\n.hydra-quote-card .wpforms-form .wpforms-submit {\n  width: 100%;\n  background: #C8922A;\