ices grid */\n.hydra-related-grid {\n  display: grid;\n  grid-template-columns: repeat(3, 1fr);\n  gap: 24px;\n}\n@media (max-width: 768px) {\n  .hydra-related-grid { grid-template-columns: 1fr; }\n}\n.hydra-related-card {\n  background: #F5F8F9;\n  border: 1px solid #E0EAF0;\n  border-radius: 12px;\n  padding: 24px;\n  transition: border-color 0.2s, box-shadow 0.2s;\n}\n.hydra-related-card:hover {\n  border-color: #016B7A;\n  box-shadow: 0 4px 20px rgba(1,107,122,0.08);\n}\n.hydra-related-icon { font-size: 28px; margin-bottom: 10px; }\n.hydra-related-card h3 {\n  font-family: \'DM Serif Display\', serif;\n  font-size: 17px;\n  font-weight: 400;\n  color: #0C1E28;\n  margin: 0 0 6px;\n}\n.hydra-related-card p {\n  font-size: 13px;\n  color: #5E7580;\n  line-height: 1.6;\n  margin: 0 0 12px;\n}\n.hydra-related-card a {\n  font-size: 13px;\n  font-weight: 600;\n  color: #016B7A;\n  text-decoration: none;\n}\n.hydra-related-card a:hover { color: #014F59; }\n\n/* Sidebar sticky on desktop */\n@media (min-width: 768px) {\n  .hydra-svc-sidebar { position: sticky; top: 90px; align-self: flex-start; }\n}\n/* ══ ABOUT PAGE ══════════════════════════════════════════════════════════ */\n.hydra-creds-grid {\n  display: grid;\n  grid-template-columns: repeat(3, 1fr);\n  gap: 28px;\n}\n@media (max-width: 768px) {\n  .hydra-creds-grid { grid-template-columns: 1fr; }\n}\n.hydra-cred-card {\n  border: 1px solid #E0EAF0;\n  border-radius: 12px;\n  padding: 32px 28px;\n  text-align: center;\n  background: #fff;\n  transition: box-shadow 0.2s;\n}\n.hydra-cred-card:hover { box-shadow: 0 8px 32px rgba(1,107,122,0.08); }\n.hydra-cred-number {\n  font-family: \'DM Serif Display\', serif;\n  font-size: 40px;\n  color: #016B7A;\n  margin-bottom: 12px;\n  line-height: 1;\n}\n.hydra-cred-card h3 {\n  font-family: \'DM Serif Display\', serif;\n  font-size: 18px;\n  font-weight: 400;\n  color: #0C1E28;\n  margin: 0 0 10px;\n}\n.hydra-cred-card p { font-size: 14px; color: #5E7580; line-height: 1.7; margin: 0; }\n\n/* Certifications */\n.hydra-cert-row {\n  display: flex;\n  flex-wrap: wrap;\n  justify-content: center;\n  gap: 12px;\n}\n.hydra-cert {\n  background: rgba(1,107,122,0.1);\n  border: 1px solid rgba(1,79,89,0.2);\n  color: #014F59;\n  border-radius: 100px;\n  padding: 8px 20px;\n  font-size: 13px;\n  font-weight: 600;\n  letter-spacing: 0.03em;\n}\n\n/* Why HYDRA grid */\n.hydra-why-grid {\n  display: grid;\n  grid-template-columns: repeat(2, 1fr);\n  gap: 32px;\n}\n@media (max-width: 640px) {\n  .hydra-why-grid { grid-template-columns: 1fr; }\n}\n.hydra-why-item { display: flex; flex-direction: column; gap: 10px; }\n.hydra-why-icon { font-size: 28px; }\n.hydra-why-item h3 {\n  font-family: \'DM Serif Display\', serif;\n  font-size: 20px;\n  font-weight: 400;\n  color: #0C1E28;\n  margin: 0;\n}\n.hydra-why-item p { font-size: 15px; color: #5E7580; line-height: 1.7; margin: 0; }\n/* ══ CONTACT PAGE ════════════════════════════════════════════════════════ */\n.hydra-contact-page-list {\n  list-style: none;\n  padding: 0;\n  margin: 0 0 8px;\n}\n.hydra-contact-page-list li {\n  display: flex;\n  align-items: flex-start;\n  gap: 14px;\n  padding: 14px 0;\n  border-bottom: 1px solid #F0F5F7;\n}\n.hydra-contact-page-list li:first-child { padding-top: 0; }\n.hydra-contact-page-list li:last-child { border-bottom: none; }\n.hydra-contact-icon { font-size: 20px; flex-shrink: 0; margin-top: 2px; }\n.hydra-contact-page-list strong {\n  display: block;\n  font-size: 12px;\n  font-weight: 700;\n  text-transform: uppercase;\n  letter-spacing: 0.08em;\n  color: #5E7580;\n  margin-bottom: 2px;\n}\n.hydra-contact-page-list span {\n  font-size: 15px;\n  color: #0C1E28;\n  line-height: 1.5;\n}\n.hydra-contact-page-list a {\n  color: #016B7A;\n  text-decoration: none;\n}\n.hydra-contact-page-list a:hover { color: #014F59; }\n.hydra-map-wrap { border-radius: 10px; overflow: hidden; }\n\n/* Contact form card */\n.hydra-contact-form-card .wpforms-form .wpforms-field-label {\n  font-size: 13px;\n  font-weight: 600;\n  color: #5E7580;\n  margin-bottom: 5px;\n}\n.hydra-contact-form-card .wpforms-form input[type=\"text\"],\n.hydra-contact-form-card .wpforms-form input[type=\"email\"],\n.hydra-contact-form-card .wpforms-form select,\n.hydra-contact-form-card .wpforms-form textarea {\n  width: 100%;\n  border: 1px solid #E0EAF0;\n  border-radius: 6px;\n  padding: 10px 12px;\n  font-size: 14px;\n  font-family: \'DM Sans\', sans-serif;\n  color: #0C1E28;\n  background: #F5F8F9;\n  transition: border-color 0.15s;\n  resize: vertical;\n}\n.hydra-contact-form-card .wpforms-form input:focus,\n.hydra-contact-form-card .wpforms-form select:focus,\n.hydra-contact-form-card .wpforms-form textarea:focus {\n  border-color: #016B7A;\n  outline: none;\n  background: #fff;\n}\n.hydra-contact-form-card .wpforms-submit-container { margin-top: 16px; }\n.hydra-contact-form-card .wpforms-submit,\n.hydra-contact-form-card button[type=\"submit\"] {\n  width: 100%;\n  background: #016B7A;\n  color: #fff;\n  border: none;\n  border-radius: 6px;\n  padding: 14px 20px;\n  font-size: 15px;\n  font-weight: 700;\n  font-family: \'DM Sans\', sans-serif;\n  cursor: pointer;\n  transition: background 0.2s;\n}\n.hydra-contact-form-card .wpforms-submit:hover,\n.hydra-contact-form-card button[type=\"submit\"]:hover { background: #014F59; }\n\n@media (min-width: 768px) {\n  .hydra-contact-form-col { position: sticky; top: 90px; align-self: flex-start; }\n}\n/* ══ SITEWIDE HEADER ══════════════════════════════════════════════════════ */\n\n/* ── Sticky + base ── */\n#masthead,\n.site-header {\n  position: sticky !important;\n  top: 0 !important;\n  z-index: 9999 !important;\n  background: #ffffff !important;\n  box-shadow: 0 1px 12px rgba(0,0,0,0.05) !important;\n  border-bottom: 1px solid rgba(0,0,0,0.08) !important;\n}\n\n/* ── Row height ── */\n#masthead .kadence-inner-row-layout-wrap,\n#masthead .header-main-inner-wrap,\n.site-header .kadence-header-inner-wrap,\n.site-header .header-inner-wrap {\n  min-height: 64px;\n  display: flex;\n  align-items: center;\n}\n\n/* ── Logo (SVG / img) ── */\n.custom-logo-link { display: inline-flex; align-items: center; text-decoration: none; }\n.custom-logo      { height: 36px; width: auto; display: block; }\n\n/* Fallback text logo (if custom-logo img not loaded) */\n.site-title { font-family: \'DM Sans\', sans-serif; font-size: 18px; font-weight: 700; color: #0C1E28; margin: 0; }\n.site-title a { text-decoration: none; color: inherit; }\n\n/* ── Primary navigation ── */\n.header-navigation .nav-menu,\n.kadence-navigation .nav-menu,\n#primary-menu {\n  display: flex;\n  align-items: center;\n  gap: 4px;\n  list-style: none;\n  margin: 0;\n  padding: 0;\n}\n\n/* Top-level items */\n.header-navigation .nav-menu > li > a,\n.kadence-navigation .nav-menu > li > a,\n#primary-menu > li > a {\n  font-family: \'DM Sans\', sans-serif !important;\n  font-size: 14px !important;\n  font-weight: 500 !important;\n  color: #5E7580 !important;\n  text-decoration: none;\n  padding: 6px 10px;\n  border-radius: 4px;\n  transition: color 0.15s;\n  display: block;\n}\n.header-navigation .nav-menu > li > a:hover,\n.kadence-navigation .nav-menu > li > a:hover,\n#primary-menu > li > a:hover,\n.header-navigation .nav-menu > li.current-menu-item > a,\n.header-navigation .nav-menu > li.current-page-ancestor > a {\n  color: #016B7A !important;\n}\n\n/* Dropdown arrow */\n.header-navigation .nav-menu > li.menu-item-has-children > a::after,\n#primary-menu > li.menu-item-has-children > a::after {\n  content: \'\';\n  display: inline-block;\n  width: 0;\n  height: 0;\n  border-left: 4px solid transparent;\n  border-right: 4px solid transparent;\n  border-top: 4px solid currentColor;\n  margin-left: 5px;\n  vertical-align: middle;\n  opacity: 0.6;\n}\n\n/* Sub-menu (dropdown) */\n.header-navigation .nav-menu .sub-menu,\n#primary-menu .sub-menu {\n  position: absolute;\n  top: calc(100% + 8px);\n  left: 0;\n  background: #ffffff;\n  border: 1px solid rgba(0,0,0,0.08);\n  border-radius: 10px;\n  box-shadow: 0 8px 32px rgba(0,0,0,0.10);\n  padding: 8px;\n  min-width: 230px;\n  list-style: none;\n  margin: 0;\n  opacity: 0;\n  visibility: hidden;\n  transform: translateY(4px);\n  transition: opacity 0.15s, transform 0.15s;\n  z-index: 100;\n}\n.header-navigation .nav-menu > li:hover > .sub-menu,\n#primary-menu > li:hover > .sub-menu {\n  opacity: 1;\n  visibility: visible;\n  transform: translateY(0);\n}\n.header-navigation .nav-menu .sub-menu li,\n#primary-menu .sub-menu li { position: relative; }\n.header-navigation .nav-menu .sub-menu li a,\n#primary-menu .sub-menu li a {\n  font-size: 13px !important;\n  font-weight: 400 !important;\n  color: #3D5460 !important;\n  padding: 8px 12px !important;\n  border-radius: 6px;\n  display: block;\n  transition: background 0.1s, color 0.1s;\n}\n.header-navigation .nav-menu .sub-menu li a:hover,\n#primary-menu .sub-menu li a:hover {\n  background: #F5F8F9;\n  color: #016B7A !important;\n}\n\n/* ── CTA Button ── */\n.header-button-wrap a,\n.header-button-wrap .kt-button,\n.kadence-header-button a,\na.header-button {\n  display: inline-flex !important;\n  align-items: center;\n  background: #016B7A !important;\n  color: #ffffff !important;\n  padding: 9px 20px !important;\n  border-radius: 6px !important;\n  font-family: \'DM Sans\', sans-serif !important;\n  font-size: 13px !important;\n  font-weight: 600 !important;\n  text-decoration: none !important;\n  border: none;\n  cursor: pointer;\n  transition: background 0.2s;\n  white-space: nowrap;\n  margin-left: 12px;\n}\n.header-button-wrap a:hover,\n.header-button-wrap .kt-button:hover,\n.kadence-header-button a:hover {\n  background: #014F59 !important;\n  color: #fff !important;\n}\n\n/* ── Mobile toggle ── */\n.mobile-trigger,\n.kadence-mobile-nav-toggle,\nbutton.menu-toggle {\n  background: none !important;\n  border: none !important;\n  color: #0C1E28 !important;\n  font-size: 22px !important;\n  cursor: pointer;\n  padding: 4px 8px;\n  display: flex;\n  align-items: center;\n}\n\n/* ── Mobile drawer ── */\n@media (max-width: 768px) {\n  .header-navigation.header-navigation-main { display: none !important; }\n  .header-button-wrap                       { display: none !important; }\n\n  .kadence-mobile-nav-wrap,\n  .mobile-navigation-wrap {\n    background: #fff;\n    border-top: 1px solid rgba(0,0,0,0.06);\n    padding: 8px 0 16px;\n  }\n  .kadence-mobile-nav-wrap .nav-menu,\n  .mobile-navigation-wrap .nav-menu {\n    flex-direction: column;\n    align-items: flex-start;\n    gap: 0;\n    padding: 0 16px;\n  }\n  .kadence-mobile-nav-wrap .nav-menu li,\n  .mobile-navigation-wrap .nav-menu li { width: 100%; }\n  .kadence-mobile-nav-wrap .nav-menu li a,\n  .mobile-navigation-wrap .nav-menu li a {\n    font-size: 15px !important;\n    color: #0C1E28 !important;\n    padding: 12px 4px;\n    border-bottom: 1px solid #F0F5F7;\n    display: block;\n  }\n  .kadence-mobile-nav-wrap .nav-menu .sub-menu,\n  .mobile-navigation-wrap .nav-menu .sub-menu {\n    position: static;\n    opacity: 1;\n    visibility: visible;\n    transform: none;\n    box-shadow: none;\n    border: none;\n    background: #F5F8F9;\n    border-radius: 6px;\n    padding: 4px 8px;\n    margin: 4px 0;\n  }\n}\n\n/* ── admin-bar offset ── */\n.admin-bar #masthead,\n.admin-bar .site-header { top: 32px !important; }\n@media (max-width: 782px) {\n  .admin-bar #masthead,\n  .admin-bar .site-header { top: 46px !important; }\n}\n','Custom CSS','','inherit','closed','closed','','40-revision-v1','','','2026-05-14 18:01:33','2026-05-14 18:01:33','',40,'http://hydra-compliance.local/?p=63',0,'revision','',0),(64,0,'2026-05-14 18:12:46','2026-05-14 18:12:46','@import url(\'https://fonts.googleapis.com/css2?family=DM+Sans:wght@400;500;600;700&family=DM+Serif+Display:ital@0;1&display=swap\');\n\n:root {\n  --hc-teal:    #016B7A;\n  --hc-dark:    #014F59;\n  --hc-gold:    #C8922A;\n  --hc-navy:    #0C1E28;\n  --hc-muted:   #5E7580;\n  --hc-offwhite:#F5F8F9;\n  --hc-border:  #E0EAF0;\n}\n\n/* ── Global ── */\nbody { font-family: \'DM Sans\', sans-serif; color: var(--hc-navy); }\nh1,h2,h3,h4,h5,h6 { font-family: \'DM Serif Display\', serif; }\n.hydra-gold-italic { color: var(--hc-gold); font-style: italic; }\n\n/* ── Pill tag ── */\n.hydra-pill {\n  display: inline-flex;\n  align-items: center;\n  gap: 8px;\n  background: rgba(200,146,42,0.15);\n  color: var(--hc-gold);\n  border: 1px solid rgba(200,146,42,0.3);\n  border-radius: 100px;\n  padding: 6px 16px;\n  font-size: 13px;\n  font-weight: 500;\n  letter-spacing: 0.02em;\n}\n.hydra-dot {\n  width: 8px;\n  height: 8px;\n  background: var(--hc-gold);\n  border-radius: 50%;\n  flex-shrink: 0;\n  animation: hydra-pulse 2s ease-in-out infinite;\n}\n@keyframes hydra-pulse {\n  0%,100% { box-shadow: 0 0 0 0 rgba(200,146,42,0.6); }\n  50%      { box-shadow: 0 0 0 6px rgba(200,146,42,0); }\n}\n\n/* ── Hero badges ── */\n.hydra-badges {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 8px;\n}\n.hydra-badges span {\n  border: 1px solid rgba(255,255,255,0.2);\n  color: rgba(255,255,255,0.65);\n  border-radius: 4px;\n  padding: 4px 12px;\n  font-size: 12px;\n  letter-spacing: 0.04em;\n}\n\n/* ── Services grid ── */\n.hydra-services-grid {\n  display: grid;\n  grid-template-columns: repeat(3, 1fr);\n  gap: 24px;\n}\n@media (max-width: 768px) {\n  .hydra-services-grid { grid-template-columns: 1fr; }\n}\n@media (min-width: 769px) and (max-width: 1024px) {\n  .hydra-services-grid { grid-template-columns: repeat(2, 1fr); }\n}\n.hydra-card {\n  background: #fff;\n  border: 1px solid var(--hc-border);\n  border-radius: 12px;\n  padding: 28px;\n  transition: box-shadow 0.2s ease, border-color 0.2s ease;\n}\n.hydra-card:hover {\n  border-color: var(--hc-teal);\n  box-shadow: 0 8px 32px rgba(1,107,122,0.1);\n}\n.hydra-card-icon {\n  font-size: 32px;\n  line-height: 1;\n  margin-bottom: 14px;\n}\n.hydra-card h3 {\n  font-family: \'DM Serif Display\', serif;\n  font-size: 18px;\n  font-weight: 400;\n  color: var(--hc-navy);\n  margin: 0 0 8px;\n  line-height: 1.3;\n}\n.hydra-card p {\n  font-size: 14px;\n  color: var(--hc-muted);\n  line-height: 1.6;\n  margin: 0 0 16px;\n}\n.hydra-card a {\n  font-size: 14px;\n  font-weight: 600;\n  color: var(--hc-teal);\n  text-decoration: none;\n}\n.hydra-card a:hover { color: var(--hc-dark); }\n\n/* ── Industries ── */\n.hydra-industries {\n  display: grid;\n  grid-template-columns: repeat(6, 1fr);\n  gap: 16px;\n}\n@media (max-width: 768px) {\n  .hydra-industries { grid-template-columns: repeat(3, 1fr); }\n}\n@media (max-width: 480px) {\n  .hydra-industries { grid-template-columns: repeat(2, 1fr); }\n}\n.hydra-industry {\n  background: rgba(1,107,122,0.08);\n  border: 1px solid rgba(1,79,89,0.15);\n  border-radius: 10px;\n  padding: 20px 16px;\n  text-align: center;\n  transition: background 0.2s;\n}\n.hydra-industry:hover { background: rgba(1,107,122,0.14); }\n.hydra-industry span { font-size: 28px; display: block; margin-bottom: 8px; }\n.hydra-industry p { font-size: 13px; font-weight: 600; color: var(--hc-dark); margin: 0; }\n\n/* ── FAQ ── */\n.wp-block-details summary {\n  list-style: none;\n  font-size: 16px;\n  font-weight: 600;\n  color: var(--hc-navy);\n  cursor: pointer;\n  display: flex;\n  justify-content: space-between;\n  align-items: center;\n}\n.wp-block-details summary::after {\n  content: \'+\';\n  font-size: 20px;\n  color: var(--hc-teal);\n  font-weight: 300;\n  transition: transform 0.2s;\n}\n.wp-block-details[open] summary::after { content: \'−\'; }\n\n/* ── Header logo ── */\n.hydra-logo-hy {\n  font-family: \'DM Serif Display\', serif;\n  font-size: 22px;\n  color: var(--hc-gold);\n  font-style: italic;\n}\n.hydra-logo-text {\n  font-family: \'DM Sans\', sans-serif;\n  font-size: 20px;\n  font-weight: 700;\n  color: var(--hc-navy);\n  letter-spacing: -0.02em;\n}\n.hydra-footer-logo { display: flex; align-items: baseline; gap: 2px; }\n.hydra-footer-logo .hydra-logo-hy { color: var(--hc-gold); }\n.hydra-footer-logo .hydra-logo-text { color: #fff; }\n\n/* ── Footer ── */\n.hydra-footer-links {\n  list-style: none;\n  padding: 0;\n  margin: 0;\n}\n.hydra-footer-links li { margin-bottom: 10px; }\n.hydra-footer-links a {\n  color: rgba(255,255,255,0.6);\n  font-size: 14px;\n  text-decoration: none;\n  transition: color 0.15s;\n}\n.hydra-footer-links a:hover { color: #fff; }\n.hydra-footer-bar {\n  border-top: 1px solid rgba(255,255,255,0.08);\n  padding: 20px 0;\n  display: flex;\n  gap: 32px;\n  flex-wrap: wrap;\n  font-size: 13px;\n  color: rgba(255,255,255,0.35);\n}\n\n/* ── Kadence header overrides ── */\n.site-header .header-navigation .nav-menu > li > a {\n  font-family: \'DM Sans\', sans-serif;\n  font-size: 14px;\n  font-weight: 500;\n  color: var(--hc-navy);\n}\n.site-header {\n  border-bottom: 1px solid var(--hc-border);\n}\n\n/* ── Button outline fix ── */\n.wp-block-button.is-style-outline .wp-block-button__link {\n  background: transparent !important;\n}\n/* ── Site logo text fallback (if SVG does not render) ── */\n.custom-logo-link { text-decoration: none; }\n.site-branding { display: flex; align-items: center; }\n\n/* ── Fullwidth page: remove default padding ── */\n.content-style-unboxed .entry-content > * { max-width: none !important; padding-left: 0 !important; padding-right: 0 !important; }\n.page-template-default.page .entry-content .alignfull { margin-left: calc(-1 * var(--wp--style--root--padding-left, 0px)); margin-right: calc(-1 * var(--wp--style--root--padding-right, 0px)); width: calc(100% + var(--wp--style--root--padding-left, 0px) + var(--wp--style--root--padding-right, 0px)); }\n\n/* ── Remove Kadence default page hero/title area ── */\n.hide-title .entry-header { display: none; }\n\n/* ══ SERVICE PAGE STYLES ══════════════════════════════════════════════════ */\n\n/* Breadcrumb bar */\n.hydra-breadcrumb-bar .breadcrumbs,\n.hydra-breadcrumb-bar .rank-math-breadcrumb {\n  font-size: 13px;\n  color: rgba(255,255,255,0.5);\n  padding: 0;\n}\n.hydra-breadcrumb-bar .breadcrumbs a,\n.hydra-breadcrumb-bar .rank-math-breadcrumb a {\n  color: rgba(255,255,255,0.6);\n  text-decoration: none;\n}\n.hydra-breadcrumb-bar .breadcrumbs a:hover,\n.hydra-breadcrumb-bar .rank-math-breadcrumb a:hover { color: #fff; }\n\n/* Checkmark list */\n.hydra-checklist {\n  list-style: none;\n  padding: 0;\n  margin: 0 0 24px;\n}\n.hydra-checklist li {\n  position: relative;\n  padding-left: 24px;\n  font-size: 15px;\n  color: #3D5460;\n  line-height: 1.7;\n  margin-bottom: 8px;\n}\n.hydra-checklist li::before {\n  content: \'✓\';\n  position: absolute;\n  left: 0;\n  top: 0;\n  color: #016B7A;\n  font-weight: 700;\n}\n\n/* Process ordered list */\n.hydra-process-list {\n  padding-left: 0;\n  margin: 0 0 24px;\n  counter-reset: process-step;\n  list-style: none;\n}\n.hydra-process-list li {\n  counter-increment: process-step;\n  position: relative;\n  padding-left: 44px;\n  font-size: 15px;\n  color: #3D5460;\n  line-height: 1.7;\n  margin-bottom: 16px;\n}\n.hydra-process-list li::before {\n  content: counter(process-step);\n  position: absolute;\n  left: 0;\n  top: 0;\n  width: 28px;\n  height: 28px;\n  background: #016B7A;\n  color: #fff;\n  border-radius: 50%;\n  font-size: 13px;\n  font-weight: 700;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  line-height: 1;\n}\n.hydra-process-list li strong { color: #0C1E28; }\n\n/* Quote card */\n.hydra-quote-card {\n  position: sticky;\n  top: 100px;\n}\n.hydra-quote-card .wpforms-form .wpforms-field-label {\n  font-size: 13px;\n  font-weight: 600;\n  color: #5E7580;\n  margin-bottom: 4px;\n}\n.hydra-quote-card .wpforms-form input[type=\"text\"],\n.hydra-quote-card .wpforms-form input[type=\"email\"],\n.hydra-quote-card .wpforms-form select {\n  width: 100%;\n  border: 1px solid #E0EAF0;\n  border-radius: 6px;\n  padding: 10px 12px;\n  font-size: 14px;\n  font-family: \'DM Sans\', sans-serif;\n  color: #0C1E28;\n  background: #F5F8F9;\n  transition: border-color 0.15s;\n}\n.hydra-quote-card .wpforms-form input:focus,\n.hydra-quote-card .wpforms-form select:focus {\n  border-color: #016B7A;\n  outline: none;\n  background: #fff;\n}\n.hydra-quote-card .wpforms-form .wpforms-submit-container {\n  margin-top: 16px;\n}\n.hydra-quote-card .wpforms-form button[type=\"submit\"],\n.hydra-quote-card .wpforms-form .wpforms-submit {\n  width: 100%;\n  background: #C8922A;\n  color: #fff;\n  border: none;\n  border-radius: 6px;\n  padding: 12px 20px;\n  font-size: 14px;\n  font-weight: 700;\n  font-family: \'DM Sans\', sans-serif;\n  cursor: pointer;\n  transition: background 0.2s;\n}\n.hydra-quote-card .wpforms-form button[type=\"submit\"]:hover,\n.hydra-quote-card .wpforms-form .wpforms-submit:hover { background: #b07a22; }\n\n/* Contact card */\n.hydra-contact-list {\n  list-style: none;\n  padding: 0;\n  margin: 0;\n}\n.hydra-contact-list li {\n  display: flex;\n  align-items: flex-start;\n  gap: 10px;\n  font-size: 14px;\n  color: #3D5460;\n  line-height: 1.6;\n  margin-bottom: 10px;\n}\n.hydra-contact-list li:last-child { margin-bottom: 0; }\n.hydra-contact-list li span { font-size: 16px; flex-shrink: 0; margin-top: 1px; }\n\n/* Related services grid */\n.hydra-related-grid {\n  display: grid;\n  grid-template-columns: repeat(3, 1fr);\n  gap: 24px;\n}\n@media (max-width: 768px) {\n  .hydra-related-grid { grid-template-columns: 1fr; }\n}\n.hydra-related-card {\n  background: #F5F8F9;\n  border: 1px solid #E0EAF0;\n  border-radius: 12px;\n  padding: 24px;\n  transition: border-color 0.2s, box-shadow 0.2s;\n}\n.hydra-related-card:hover {\n  border-color: #016B7A;\n  box-shadow: 0 4px 20px rgba(1,107,122,0.08);\n}\n.hydra-related-icon { font-size: 28px; margin-bottom: 10px; }\n.hydra-related-card h3 {\n  font-family: \'DM Serif Display\', serif;\n  font-size: 17px;\n  font-weight: 400;\n  color: #0C1E28;\n  margin: 0 0 6px;\n}\n.hydra-related-card p {\n  font-size: 13px;\n  color: #5E7580;\n  line-height: 1.6;\n  margin: 0 0 12px;\n}\n.hydra-related-card a {\n  font-size: 13px;\n  font-weight: 600;\n  color: #016B7A;\n  text-decoration: none;\n}\n.hydra-related-card a:hover { color: #014F59; }\n\n/* Sidebar sticky on desktop */\n@media (min-width: 768px) {\n  .hydra-svc-sidebar { position: sticky; top: 90px; align-self: flex-start; }\n}\n/* ══ ABOUT PAGE ══════════════════════════════════════════════════════════ */\n.hydra-creds-grid {\n  display: grid;\n  grid-template-columns: repeat(3, 1fr);\n  gap: 28px;\n}\n@media (max-width: 768px) {\n  .hydra-creds-grid { grid-template-columns: 1fr; }\n}\n.hydra-cred-card {\n  border: 1px solid #E0EAF0;\n  border-radius: 12px;\n  padding: 32px 28px;\n  text-align: center;\n  background: #fff;\n  transition: box-shadow 0.2s;\n}\n.hydra-cred-card:hover { box-shadow: 0 8px 32px rgba(1,107,122,0.08); }\n.hydra-cred-number {\n  font-family: \'DM Serif Display\', serif;\n  font-size: 40px;\n  color: #016B7A;\n  margin-bottom: 12px;\n  line-height: 1;\n}\n.hydra-cred-card h3 {\n  font-family: \'DM Serif Display\', serif;\n  font-size: 18px;\n  font-weight: 400;\n  color: #0C1E28;\n  margin: 0 0 10px;\n}\n.hydra-cred-card p { font-size: 14px; color: #5E7580; line-height: 1.7; margin: 0; }\n\n/* Certifications */\n.hydra-cert-row {\n  display: flex;\n  flex-wrap: wrap;\n  justify-content: center;\n  gap: 12px;\n}\n.hydra-cert {\n  background: rgba(1,107,122,0.1);\n  border: 1px solid rgba(1,79,89,0.2);\n  color: #014F59;\n  border-radius: 100px;\n  padding: 8px 20px;\n  font-size: 13px;\n  font-weight: 600;\n  letter-spacing: 0.03em;\n}\n\n/* Why HYDRA grid */\n.hydra-why-grid {\n  display: grid;\n  grid-template-columns: repeat(2, 1fr);\n  gap: 32px;\n}\n@media (max-width: 640px) {\n  .hydra-why-grid { grid-template-columns: 1fr; }\n}\n.hydra-why-item { display: flex; flex-direction: column; gap: 10px; }\n.hydra-why-icon { font-size: 28px; }\n.hydra-why-item h3 {\n  font-family: \'DM Serif Display\', serif;\n  font-size: 20px;\n  font-weight: 400;\n  color: #0C1E28;\n  margin: 0;\n}\n.hydra-why-item p { font-size: 15px; color: #5E7580; line-height: 1.7; margin: 0; }\n/* ══ CONTACT PAGE ════════════════════════════════════════════════════════ */\n.hydra-contact-page-list {\n  list-style: none;\n  padding: 0;\n  margin: 0 0 8px;\n}\n.hydra-contact-page-list li {\n  display: flex;\n  align-items: flex-start;\n  gap: 14px;\n  padding: 14px 0;\n  border-bottom: 1px solid #F0F5F7;\n}\n.hydra-contact-page-list li:first-child { padding-top: 0; }\n.hydra-contact-page-list li:last-child { border-bottom: none; }\n.hydra-contact-icon { font-size: 20px; flex-shrink: 0; margin-top: 2px; }\n.hydra-contact-page-list strong {\n  display: block;\n  font-size: 12px;\n  font-weight: 700;\n  text-transform: uppercase;\n  letter-spacing: 0.08em;\n  color: #5E7580;\n  margin-bottom: 2px;\n}\n.hydra-contact-page-list span {\n  font-size: 15px;\n  color: #0C1E28;\n  line-height: 1.5;\n}\n.hydra-contact-page-list a {\n  color: #016B7A;\n  text-decoration: none;\n}\n.hydra-contact-page-list a:hover { color: #014F59; }\n.hydra-map-wrap { border-radius: 10px; overflow: hidden; }\n\n/* Contact form card */\n.hydra-contact-form-card .wpforms-form .wpforms-field-label {\n  font-size: 13px;\n  font-weight: 600;\n  color: #5E7580;\n  margin-bottom: 5px;\n}\n.hydra-contact-form-card .wpforms-form input[type=\"text\"],\n.hydra-contact-form-card .wpforms-form input[type=\"email\"],\n.hydra-contact-form-card .wpforms-form select,\n.hydra-contact-form-card .wpforms-form textarea {\n  width: 100%;\n  border: 1px solid #E0EAF0;\n  border-radius: 6px;\n  padding: 10px 12px;\n  font-size: 14px;\n  font-family: \'DM Sans\', sans-serif;\n  color: #0C1E28;\n  background: #F5F8F9;\n  transition: border-color 0.15s;\n  resize: vertical;\n}\n.hydra-contact-form-card .wpforms-form input:focus,\n.hydra-contact-form-card .wpforms-form select:focus,\n.hydra-contact-form-card .wpforms-form textarea:focus {\n  border-color: #016B7A;\n  outline: none;\n  background: #fff;\n}\n.hydra-contact-form-card .wpforms-submit-container { margin-top: 16px; }\n.hydra-contact-form-card .wpforms-submit,\n.hydra-contact-form-card button[type=\"submit\"] {\n  width: 100%;\n  background: #016B7A;\n  color: #fff;\n  border: none;\n  border-radius: 6px;\n  padding: 14px 20px;\n  font-size: 15px;\n  font-weight: 700;\n  font-family: \'DM Sans\', sans-serif;\n  cursor: pointer;\n  transition: background 0.2s;\n}\n.hydra-contact-form-card .wpforms-submit:hover,\n.hydra-contact-form-card button[type=\"submit\"]:hover { background: #014F59; }\n\n@media (min-width: 768px) {\n  .hydra-contact-form-col { position: sticky; top: 90px; align-self: flex-start; }\n}\n/* ══ SITEWIDE HEADER ══════════════════════════════════════════════════════ */\n\n/* ── Sticky + base ── */\n#masthead,\n.site-header {\n  position: sticky !important;\n  top: 0 !important;\n  z-index: 9999 !important;\n  background: #ffffff !important;\n  box-shadow: 0 1px 12px rgba(0,0,0,0.05) !important;\n  border-bottom: 1px solid rgba(0,0,0,0.08) !important;\n}\n\n/* ── Row height ── */\n#masthead .kadence-inner-row-layout-wrap,\n#masthead .header-main-inner-wrap,\n.site-header .kadence-header-inner-wrap,\n.site-header .header-inner-wrap {\n  min-height: 64px;\n  display: flex;\n  align-items: center;\n}\n\n/* ── Logo (SVG / img) ── */\n.custom-logo-link { display: inline-flex; align-items: center; text-decoration: none; }\n.custom-logo      { height: 36px; width: auto; display: block; }\n\n/* Fallback text logo (if custom-logo img not loaded) */\n.site-title { font-family: \'DM Sans\', sans-serif; font-size: 18px; font-weight: 700; color: #0C1E28; margin: 0; }\n.site-title a { text-decoration: none; color: inherit; }\n\n/* ── Primary navigation ── */\n.header-navigation .nav-menu,\n.kadence-navigation .nav-menu,\n#primary-menu {\n  display: flex;\n  align-items: center;\n  gap: 4px;\n  list-style: none;\n  margin: 0;\n  padding: 0;\n}\n\n/* Top-level items */\n.header-navigation .nav-menu > li > a,\n.kadence-navigation .nav-menu > li > a,\n#primary-menu > li > a {\n  font-family: \'DM Sans\', sans-serif !important;\n  font-size: 14px !important;\n  font-weight: 500 !important;\n  color: #5E7580 !important;\n  text-decoration: none;\n  padding: 6px 10px;\n  border-radius: 4px;\n  transition: color 0.15s;\n  display: block;\n}\n.header-navigation .nav-menu > li > a:hover,\n.kadence-navigation .nav-menu > li > a:hover,\n#primary-menu > li > a:hover,\n.header-navigation .nav-menu > li.current-menu-item > a,\n.header-navigation .nav-menu > li.current-page-ancestor > a {\n  color: #016B7A !important;\n}\n\n/* Dropdown arrow */\n.header-navigation .nav-menu > li.menu-item-has-children > a::after,\n#primary-menu > li.menu-item-has-children > a::after {\n  content: \'\';\n  display: inline-block;\n  width: 0;\n  height: 0;\n  border-left: 4px solid transparent;\n  border-right: 4px solid transparent;\n  border-top: 4px solid currentColor;\n  margin-left: 5px;\n  vertical-align: middle;\n  opacity: 0.6;\n}\n\n/* Sub-menu (dropdown) */\n.header-navigation .nav-menu .sub-menu,\n#primary-menu .sub-menu {\n  position: absolute;\n  top: calc(100% + 8px);\n  left: 0;\n  background: #ffffff;\n  border: 1px solid rgba(0,0,0,0.08);\n  border-radius: 10px;\n  box-shadow: 0 8px 32px rgba(0,0,0,0.10);\n  padding: 8px;\n  min-width: 230px;\n  list-style: none;\n  margin: 0;\n  opacity: 0;\n  visibility: hidden;\n  transform: translateY(4px);\n  transition: opacity 0.15s, transform 0.15s;\n  z-index: 100;\n}\n.header-navigation .nav-menu > li:hover > .sub-menu,\n#primary-menu > li:hover > .sub-menu {\n  opacity: 1;\n  visibility: visible;\n  transform: translateY(0);\n}\n.header-navigation .nav-menu .sub-menu li,\n#primary-menu .sub-menu li { position: relative; }\n.header-navigation .nav-menu .sub-menu li a,\n#primary-menu .sub-menu li a {\n  font-size: 13px !important;\n  font-weight: 400 !important;\n  color: #3D5460 !important;\n  padding: 8px 12px !important;\n  border-radius: 6px;\n  display: block;\n  transition: background 0.1s, color 0.1s;\n}\n.header-navigation .nav-menu .sub-menu li a:hover,\n#primary-menu .sub-menu li a:hover {\n  background: #F5F8F9;\n  color: #016B7A !important;\n}\n\n/* ── CTA Button ── */\n.header-button-wrap a,\n.header-button-wrap .kt-button,\n.kadence-header-button a,\na.header-button {\n  display: inline-flex !important;\n  align-items: center;\n  background: #016B7A !important;\n  color: #ffffff !important;\n  padding: 9px 20px !important;\n  border-radius: 6px !important;\n  font-family: \'DM Sans\', sans-serif !important;\n  font-size: 13px !important;\n  font-weight: 600 !important;\n  text-decoration: none !important;\n  border: none;\n  cursor: pointer;\n  transition: background 0.2s;\n  white-space: nowrap;\n  margin-left: 12px;\n}\n.header-button-wrap a:hover,\n.header-button-wrap .kt-button:hover,\n.kadence-header-button a:hover {\n  background: #014F59 !important;\n  color: #fff !important;\n}\n\n/* ── Mobile toggle ── */\n.mobile-trigger,\n.kadence-mobile-nav-toggle,\nbutton.menu-toggle {\n  background: none !important;\n  border: none !important;\n  color: #0C1E28 !important;\n  font-size: 22px !important;\n  cursor: pointer;\n  padding: 4px 8px;\n  display: flex;\n  align-items: center;\n}\n\n/* ── Mobile drawer ── */\n@media (max-width: 768px) {\n  .header-navigation.header-navigation-main { display: none !important; }\n  .header-button-wrap                       { display: none !important; }\n\n  .kadence-mobile-nav-wrap,\n  .mobile-navigation-wrap {\n    background: #fff;\n    border-top: 1px solid rgba(0,0,0,0.06);\n    padding: 8px 0 16px;\n  }\n  .kadence-mobile-nav-wrap .nav-menu,\n  .mobile-navigation-wrap .nav-menu {\n    flex-direction: column;\n    align-items: flex-start;\n    gap: 0;\n    padding: 0 16px;\n  }\n  .kadence-mobile-nav-wrap .nav-menu li,\n  .mobile-navigation-wrap .nav-menu li { width: 100%; }\n  .kadence-mobile-nav-wrap .nav-menu li a,\n  .mobile-navigation-wrap .nav-menu li a {\n    font-size: 15px !important;\n    color: #0C1E28 !important;\n    padding: 12px 4px;\n    border-bottom: 1px solid #F0F5F7;\n    display: block;\n  }\n  .kadence-mobile-nav-wrap .nav-menu .sub-menu,\n  .mobile-navigation-wrap .nav-menu .sub-menu {\n    position: static;\n    opacity: 1;\n    visibility: visible;\n    transform: none;\n    box-shadow: none;\n    border: none;\n    background: #F5F8F9;\n    border-radius: 6px;\n    padding: 4px 8px;\n    margin: 4px 0;\n  }\n}\n\n/* ── admin-bar offset ── */\n.admin-bar #masthead,\n.admin-bar .site-header { top: 32px !important; }\n@media (max-width: 782px) {\n  .admin-bar #masthead,\n  .admin-bar .site-header { top: 46px !important; }\n}\n/* ══ HOME PAGE — Full layout fix ════════════════════════════════════════════ */\n\n/* ── Shared section wrapper ── */\nbody.page-id-5 .entry-content > .wp-block-group.alignfull {\n  margin-left: calc(-1 * var(--wp--style--root--padding-left, 0px)) !important;\n  margin-right: calc(-1 * var(--wp--style--root--padding-right, 0px)) !important;\n  width: 100vw !important;\n  max-width: 100vw !important;\n}\n\n/* ── HERO ── */\n.hydra-hero {\n  background: #0C1E28 !important;\n  padding: 96px 24px 80px !important;\n  position: relative;\n  overflow: hidden;\n}\n.hydra-hero::before {\n  content: \'\';\n  position: absolute;\n  inset: 0;\n  background: radial-gradient(ellipse 60% 60% at 70% 40%, rgba(1,107,122,0.22) 0%, transparent 70%);\n  pointer-events: none;\n}\n.hydra-hero .wp-block-group__inner-container {\n  max-width: 1100px;\n  margin: 0 auto;\n  position: relative;\n  z-index: 1;\n}\n\n/* Pill tag */\n.hydra-pill {\n  display: inline-flex;\n  align-items: center;\n  gap: 6px;\n  background: rgba(255,255,255,0.08) !important;\n  border: 1px solid rgba(255,255,255,0.14) !important;\n  color: rgba(255,255,255,0.80) !important;\n  border-radius: 100px;\n  padding: 5px 14px 5px 10px;\n  font-size: 12px;\n  font-weight: 500;\n  letter-spacing: 0.4px;\n  text-transform: uppercase;\n  margin-bottom: 20px;\n}\n.hydra-dot {\n  width: 6px;\n  height: 6px;\n  background: #C8922A;\n  border-radius: 50%;\n  display: inline-block;\n}\n\n/* Hero heading */\n.hydra-hero h1,\n.hydra-hero .wp-block-heading {\n  font-family: \'DM Serif Display\', Georgia, serif !important;\n  font-size: clamp(34px, 5vw, 58px) !important;\n  font-weight: 400 !important;\n  color: #ffffff !important;\n  line-height: 1.12 !important;\n  letter-spacing: -0.5px;\n  margin: 0 0 20px !important;\n  max-width: 700px;\n}\n.hydra-hero h1 em { color: #C8922A; font-style: italic; }\n\n/* Hero subtext */\n.hydra-hero p {\n  font-size: 17px !important;\n  color: rgba(255,255,255,0.72) !important;\n  line-height: 1.65 !important;\n  max-width: 560px;\n  margin: 0 0 32px !important;\n}\n\n/* Hero badges */\n.hydra-badges {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 10px;\n  margin-top: 36px;\n}\n.hydra-badge {\n  display: inline-flex;\n  align-items: center;\n  gap: 6px;\n  background: rgba(255,255,255,0.06);\n  border: 1px solid rgba(255,255,255,0.12);\n  border-radius: 8px;\n  padding: 8px 14px;\n  font-size: 12px;\n  color: rgba(255,255,255,0.75);\n  font-weight: 500;\n}\n\n/* Hero CTA buttons */\n.hydra-hero .wp-block-buttons { margin-top: 32px; gap: 12px; }\n.hydra-hero .wp-block-button__link {\n  border-radius: 8px !important;\n  font-family: \'DM Sans\', sans-serif !important;\n  font-size: 14px !important;\n  font-weight: 600 !important;\n  padding: 12px 24px !important;\n  transition: background 0.2s, color 0.2s, transform 0.15s !important;\n}\n.hydra-hero .wp-block-button__link:hover { transform: translateY(-1px); }\n\n/* ── STATS BAR ── */\n.hydra-stats-bar {\n  background: #ffffff !important;\n  padding: 40px 24px !important;\n  border-bottom: 1px solid #EDF1F3;\n}\n.hydra-stats-bar .wp-block-group__inner-container {\n  max-width: 1100px;\n  margin: 0 auto;\n}\n.hydra-stats-bar .wp-block-columns {\n  gap: 0 !important;\n}\n.hydra-stats-bar .wp-block-column {\n  text-align: center;\n  padding: 16px 8px;\n  border-right: 1px solid #EDF1F3;\n}\n.hydra-stats-bar .wp-block-column:last-child { border-right: none; }\n\n/* Stat numbers — override inline font-size:44px */\n.hydra-stats-bar h3 {\n  font-family: \'DM Serif Display\', Georgia, serif !important;\n  font-size: 28px !important;\n  font-weight: 400 !important;\n  color: #016B7A !important;\n  margin: 0 0 4px !important;\n  line-height: 1.1;\n}\n/* Stat labels */\n.hydra-stats-bar p {\n  font-size: 11px !important;\n  font-weight: 500 !important;\n  color: #8FA6B2 !important;\n  text-transform: uppercase !important;\n  letter-spacing: 0.6px !important;\n  margin: 0 !important;\n}\n\n@media (max-width: 768px) {\n  .hydra-stats-bar .wp-block-columns { flex-wrap: wrap; }\n  .hydra-stats-bar .wp-block-column  { min-width: 50%; border-right: none; border-bottom: 1px solid #EDF1F3; }\n}\n\n/* ── SERVICES GRID ── */\n.hydra-services-grid-section {\n  background: #F5F8F9 !important;\n  padding: 80px 24px !important;\n}\n.hydra-services-grid-section .wp-block-group__inner-container {\n  max-width: 1100px;\n  margin: 0 auto;\n}\n.hydra-services-grid-section > .wp-block-group__inner-container > .wp-block-heading,\n.hydra-services-grid-section h2 {\n  font-family: \'DM Serif Display\', Georgia, serif !important;\n  font-size: clamp(26px, 3.5vw, 38px) !important;\n  font-weight: 400 !important;\n  color: #0C1E28 !important;\n  text-align: center;\n  margin: 0 0 8px !important;\n}\n.hydra-services-grid-section > .wp-block-group__inner-container > p {\n  text-align: center;\n  font-size: 15px !important;\n  color: #5E7580 !important;\n  margin: 0 0 48px !important;\n}\n\n.hydra-services-grid {\n  display: grid !important;\n  grid-template-columns: repeat(3, 1fr) !important;\n  gap: 20px !important;\n  list-style: none;\n  padding: 0;\n  margin: 0;\n}\n\n.hydra-card {\n  background: #ffffff !important;\n  border: 1px solid #E4ECF0 !important;\n  border-radius: 14px !important;\n  padding: 28px 24px !important;\n  transition: box-shadow 0.2s, transform 0.2s !important;\n  text-decoration: none !important;\n  display: block;\n  color: inherit;\n}\n.hydra-card:hover {\n  box-shadow: 0 8px 28px rgba(0,0,0,0.09) !important;\n  transform: translateY(-2px) !important;\n  text-decoration: none !important;\n}\n.hydra-card-icon {\n  font-size: 24px;\n  margin-bottom: 14px;\n  display: block;\n}\n.hydra-card h3 {\n  font-family: \'DM Sans\', sans-serif !important;\n  font-size: 16px !important;\n  font-weight: 700 !important;\n  color: #0C1E28 !important;\n  margin: 0 0 8px !important;\n  line-height: 1.3;\n}\n.hydra-card p {\n  font-size: 13px !important;\n  color: #5E7580 !important;\n  line-height: 1.55 !important;\n  margin: 0 !important;\n}\n\n@media (max-width: 900px) {\n  .hydra-services-grid { grid-template-columns: repeat(2, 1fr) !important; }\n}\n@media (max-width: 560px) {\n  .hydra-services-grid { grid-template-columns: 1fr !important; }\n}\n\n/* ── INDUSTRIES ── */\n.hydra-industries-section {\n  background: #E0F4F7 !important;\n  padding: 64px 24px !important;\n}\n.hydra-industries-section .wp-block-group__inner-container {\n  max-width: 1100px;\n  margin: 0 auto;\n  text-align: center;\n}\n.hydra-industries-section h2 {\n  font-family: \'DM Serif Display\', Georgia, serif !important;\n  font-size: clamp(22px, 3vw, 32px) !important;\n  font-weight: 400 !important;\n  color: #0C1E28 !important;\n  margin: 0 0 32px !important;\n}\n\n.hydra-industries {\n  display: grid !important;\n  grid-template-columns: repeat(6, 1fr) !important;\n  gap: 12px !important;\n  justify-items: center;\n}\n.hydra-industry {\n  background: #ffffff !important;\n  border: 1px solid rgba(1,107,122,0.15) !important;\n  border-radius: 100px !important;\n  padding: 10px 20px !important;\n  font-size: 13px !important;\n  font-weight: 500 !important;\n  color: #016B7A !important;\n  text-align: center;\n  white-space: nowrap;\n  transition: background 0.15s, color 0.15s;\n}\n.hydra-industry:hover {\n  background: #016B7A !important;\n  color: #ffffff !important;\n}\n\n@media (max-width: 900px) {\n  .hydra-industries { grid-template-columns: repeat(3, 1fr) !important; }\n  .hydra-industry   { white-space: normal; border-radius: 10px !important; }\n}\n@media (max-width: 560px) {\n  .hydra-industries { grid-template-columns: repeat(2, 1fr) !important; }\n}\n\n/* ── FAQ ── */\n.hydra-faq-section {\n  background: #ffffff !important;\n  padding: 80px 24px !important;\n}\n.hydra-faq-section .wp-block-group__inner-container {\n  max-width: 760px;\n  margin: 0 auto;\n}\n.hydra-faq-section h2 {\n  font-family: \'DM Serif Display\', Georgia, serif !important;\n  font-size: clamp(24px, 3vw, 36px) !important;\n  font-weight: 400 !important;\n  color: #0C1E28 !important;\n  text-align: center;\n  margin: 0 0 48px !important;\n}\n\n/* FAQ items — details/summary */\n.hydra-faq-section .wp-block-details,\n.hydra-faq-section details {\n  border: 1px solid #E4ECF0;\n  border-radius: 12px;\n  margin-bottom: 10px;\n  overflow: hidden;\n  background: #ffffff;\n  transition: box-shadow 0.2s;\n}\n.hydra-faq-section .wp-block-details[open],\n.hydra-faq-section details[open] {\n  box-shadow: 0 4px 16px rgba(0,0,0,0.07);\n}\n.hydra-faq-section .wp-block-details summary,\n.hydra-faq-section details summary {\n  list-style: none;\n  cursor: pointer;\n  padding: 18px 52px 18px 20px;\n  font-family: \'DM Sans\', sans-serif !important;\n  font-size: 15px !important;\n  font-weight: 600 !important;\n  color: #0C1E28 !important;\n  position: relative;\n  user-select: none;\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n}\n.hydra-faq-section .wp-block-details summary::-webkit-details-marker,\n.hydra-faq-section details summary::-webkit-details-marker { display: none; }\n\n/* Custom arrow via JS-injected span */\n.hydra-faq-arrow {\n  position: absolute;\n  right: 20px;\n  top: 50%;\n  transform: translateY(-50%) rotate(0deg);\n  width: 18px;\n  height: 18px;\n  transition: transform 0.25s ease;\n  flex-shrink: 0;\n}\n.hydra-faq-arrow::before,\n.hydra-faq-arrow::after {\n  content: \'\';\n  position: absolute;\n  background: #016B7A;\n  border-radius: 2px;\n  transition: transform 0.25s ease;\n}\n.hydra-faq-arrow::before { width: 10px; height: 2px; top: 8px; left: 4px; }\n.hydra-faq-arrow::after  { width: 2px;  height: 10px; top: 4px; left: 8px; }\n\n.wp-block-details[open] .hydra-faq-arrow::after,\ndetails[open] .hydra-faq-arrow::after {\n  transform: rotate(90deg);\n}\n\n.hydra-faq-section .wp-block-details > *:not(summary),\n.hydra-faq-section details > *:not(summary) {\n  padding: 0 20px 18px;\n  font-size: 14px !important;\n  color: #5E7580 !important;\n  line-height: 1.65 !important;\n  margin: 0 !important;\n}\n\n/* ── CTA BANNER ── */\n.hydra-cta-banner {\n  background: #016B7A !important;\n  padding: 72px 24px !important;\n  text-align: center;\n}\n.hydra-cta-banner .wp-block-group__inner-container {\n  max-width: 800px;\n  margin: 0 auto;\n}\n.hydra-cta-banner h2 {\n  font-family: \'DM Serif Display\', Georgia, serif !important;\n  font-size: clamp(26px, 4vw, 42px) !important;\n  font-weight: 400 !important;\n  color: #ffffff !important;\n  margin: 0 0 16px !important;\n  line-height: 1.15;\n}\n.hydra-cta-banner p {\n  font-size: 16px !important;\n  color: rgba(255,255,255,0.82) !important;\n  margin: 0 0 32px !important;\n  line-height: 1.6;\n}\n.hydra-cta-banner .wp-block-buttons { justify-content: center; gap: 12px; }\n.hydra-cta-banner .wp-block-button__link {\n  border-radius: 8px !important;\n  font-family: \'DM Sans\', sans-serif !important;\n  font-size: 14px !important;\n  font-weight: 600 !important;\n  padding: 13px 28px !important;\n  transition: background 0.2s, color 0.2s !important;\n}\n/* Primary button in CTA = white with teal text */\n.hydra-cta-banner .wp-block-button:first-child .wp-block-button__link {\n  background: #ffffff !important;\n  color: #016B7A !important;\n  border: 2px solid #ffffff !important;\n}\n.hydra-cta-banner .wp-block-button:first-child .wp-block-button__link:hover {\n  background: #F0FAFB !important;\n  color: #014F59 !important;\n}\n/* Secondary / outline button */\n.hydra-cta-banner .wp-block-button:not(:first-child) .wp-block-button__link {\n  background: transparent !important;\n  color: rgba(255,255,255,0.90) !important;\n  border: 2px solid rgba(255,255,255,0.45) !important;\n}\n.hydra-cta-banner .wp-block-button:not(:first-child) .wp-block-button__link:hover {\n  border-color: #ffffff !important;\n  color: #ffffff !important;\n}\n\n/* ── FOOTER ── */\n.hydra-footer {\n  background: #0C1E28 !important;\n  padding: 56px 24px 32px !important;\n}\n.hydra-footer .wp-block-group__inner-container {\n  max-width: 1100px;\n  margin: 0 auto;\n}\n.hydra-footer .wp-block-columns {\n  gap: 40px !important;\n  margin-bottom: 40px;\n}\n.hydra-footer h3 {\n  font-family: \'DM Sans\', sans-serif !important;\n  font-size: 12px !important;\n  font-weight: 700 !important;\n  color: rgba(255,255,255,0.40) !important;\n  text-transform: uppercase !important;\n  letter-spacing: 1px !important;\n  margin: 0 0 16px !important;\n}\n.hydra-footer p,\n.hydra-footer li {\n  font-size: 13px !important;\n  color: rgba(255,255,255,0.60) !important;\n  line-height: 1.7 !important;\n  margin: 0 0 4px !important;\n}\n.hydra-footer a {\n  color: rgba(255,255,255,0.60) !important;\n  text-decoration: none !important;\n  transition: color 0.15s;\n}\n.hydra-footer a:hover { color: #ffffff !important; }\n.hydra-footer ul { list-style: none; padding: 0; margin: 0; }\n.hydra-footer ul li { margin-bottom: 8px; }\n\n/* Footer logo / brand */\n.hydra-footer .site-title,\n.hydra-footer strong {\n  font-family: \'DM Sans\', sans-serif !important;\n  font-size: 18px !important;\n  font-weight: 700 !important;\n  color: #ffffff !important;\n}\n\n/* Footer bottom bar */\n.hydra-footer-bottom,\n.hydra-footer .wp-block-separator + p,\n.hydra-footer hr ~ p {\n  border-top: 1px solid rgba(255,255,255,0.08);\n  padding-top: 20px;\n  margin-top: 0 !important;\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  flex-wrap: wrap;\n  gap: 8px;\n  font-size: 12px !important;\n  color: rgba(255,255,255,0.35) !important;\n}\n.hydra-footer .wp-block-separator {\n  border-color: rgba(255,255,255,0.08) !important;\n  margin: 0 0 20px !important;\n}\n\n/* Scroll shadow on header when page is scrolled */\n#masthead.scrolled,\n.site-header.scrolled {\n  box-shadow: 0 2px 20px rgba(0,0,0,0.12) !important;\n}\n','Custom CSS','','inherit','closed','closed','','40-revision-v1','','','2026-05-14 18:12:46','2026-05-14 18:12:46','',40,'http://hydra-compliance.local/?p=64',0,'revision','',0),(65,0,'2026-05-14 18:12:46','2026-05-14 18:12:46','<!-- wp:group {\"align\":\"full\",\"className\":\"hydra-hero\",\"style\":{\"color\":{\"background\":\"#0C1E28\"},\"spacing\":{\"padding\":{\"top\":\"100px\",\"bottom\":\"100px\",\"left\":\"24px\",\"right\":\"24px\"}}},\"layout\":{\"type\":\"constrained\",\"contentSize\":\"1100px\"}} -->\n<div class=\"wp-block-group alignfull hydra-hero has-background\" style=\"background-color:#0C1E28;padding-top:100px;padding-bottom:100px;padding-left:24px;padding-right:24px\">\n<!-- wp:html --><div class=\"hydra-pill\"><span class=\"hydra-dot\"></span> Jeddah · Riyadh · All of KSA</div><!-- /wp:html -->\n<!-- wp:heading {\"level\":1,\"style\":{\"color\":{\"text\":\"#ffffff\"},\"typography\":{\"fontSize\":\"clamp(36px,5vw,56px)\",\"lineHeight\":\"1.2\",\"fontWeight\":\"400\"},\"spacing\":{\"margin\":{\"top\":\"32px\",\"bottom\":\"20px\"}}}} -->\n<h1 class=\"wp-block-heading\" style=\"color:#ffffff;font-size:clamp(36px,5vw,56px);font-weight:400;line-height:1.2;margin-top:32px;margin-bottom:20px\">Saudi Arabia&#8217;s pharma <em class=\"hydra-gold-italic\">quality &amp; compliance</em> partner</h1>\n<!-- /wp:heading -->\n<!-- wp:paragrap