height=\"34\" rx=\"3\"/><rect x=\"17\" y=\"4\" width=\"14\" height=\"7\" rx=\"2\"/><path d=\"M17 22l3.5 3.5L29 17\"/><path d=\"M17 32l3.5 3.5L29 27\"/></svg>      </div>\n      <div class=\"hydra-sp-body\">\n        <h3>Validation &amp; Qualification</h3>\n        <div class=\"hydra-sp-chips\">\n          <span class=\"hydra-chip hydra-chip--h1\"><span class=\"hydra-chip-dot\"></span>validation and qualification services Saudi Arabia</span>\n          <span class=\"hydra-chip hydra-chip--h2\"><span class=\"hydra-chip-dot hydra-chip-dot--gray\"></span>cold chain validation services</span>\n        </div>\n        <p>IQ/OQ/PQ for cold storage, pharma equipment and warehouses.</p>\n        <span class=\"hydra-sp-cta\">View page &rarr;</span>\n      </div>\n    </a>\n\n    <!-- Card 3: GDP & Regulatory Compliance -->\n    <a href=\"/services/gdp-compliance-saudi-arabia/\" class=\"hydra-sp-card\">\n      <div class=\"hydra-sp-img\" style=\"background:#E8EEF8\">\n        <svg width=\"48\" height=\"48\" viewBox=\"0 0 48 48\" fill=\"none\" stroke=\"#185FA5\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M24 4 L40 14 L40 34 Q40 42 24 44 Q8 42 8 34 L8 14 Z\"/><path d=\"M17 24l4.5 4.5L32 18\"/></svg>      </div>\n      <div class=\"hydra-sp-body\">\n        <h3>GDP &amp; Regulatory Compliance</h3>\n        <div class=\"hydra-sp-chips\">\n          <span class=\"hydra-chip hydra-chip--h1\"><span class=\"hydra-chip-dot\"></span>GDP compliance Saudi Arabia</span>\n          <span class=\"hydra-chip hydra-chip--h2\"><span class=\"hydra-chip-dot hydra-chip-dot--gray\"></span>SFDA GDP compliance</span>\n        </div>\n        <p>SFDA GDP audit readiness, gap assessment and regulatory consulting.</p>\n        <span class=\"hydra-sp-cta\">View page &rarr;</span>\n      </div>\n    </a>\n\n    <!-- Card 4: Monitoring & Data Loggers -->\n    <a href=\"/services/pharmaceutical-consulting-saudi-arabia/\" class=\"hydra-sp-card\">\n      <div class=\"hydra-sp-img\" style=\"background:#FDF3E3\">\n        <svg width=\"48\" height=\"48\" viewBox=\"0 0 48 48\" fill=\"none\" stroke=\"#C8922A\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M9 20 Q24 8 39 20\" stroke-linecap=\"round\"/><path d=\"M14 26 Q24 16 34 26\" stroke-linecap=\"round\"/><rect x=\"17\" y=\"30\" width=\"14\" height=\"11\" rx=\"2\"/><line x1=\"24\" y1=\"30\" x2=\"24\" y2=\"41\"/><line x1=\"14\" y1=\"38\" x2=\"34\" y2=\"38\"/></svg>      </div>\n      <div class=\"hydra-sp-body\">\n        <h3>Monitoring &amp; Data Loggers</h3>\n        <div class=\"hydra-sp-chips\">\n          <span class=\"hydra-chip hydra-chip--h1\"><span class=\"hydra-chip-dot\"></span>real time temperature monitoring system</span>\n          <span class=\"hydra-chip hydra-chip--h2\"><span class=\"hydra-chip-dot hydra-chip-dot--gray\"></span>cold chain monitoring system</span>\n        </div>\n        <p>SFDA-compliant RTMS, IoT monitoring and pharma data loggers.</p>\n        <span class=\"hydra-sp-cta\">View page &rarr;</span>\n      </div>\n    </a>\n\n    <!-- Card 5: Calibration Services -->\n    <a href=\"/services/cold-storage-compliance/\" class=\"hydra-sp-card\">\n      <div class=\"hydra-sp-img\" style=\"background:#FDE8EE\">\n        <svg width=\"48\" height=\"48\" viewBox=\"0 0 48 48\" fill=\"none\" stroke=\"#C0392B\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><circle cx=\"24\" cy=\"27\" r=\"14\"/><path d=\"M24 27 L31 16\"/><line x1=\"24\" y1=\"15\" x2=\"24\" y2=\"13\"/><line x1=\"10\" y1=\"27\" x2=\"12\" y2=\"27\"/><line x1=\"36\" y1=\"27\" x2=\"38\" y2=\"27\"/><line x1=\"14\" y1=\"17\" x2=\"15.5\" y2=\"18.5\"/><line x1=\"34\" y1=\"17\" x2=\"32.5\" y2=\"18.5\"/></svg>      </div>\n      <div class=\"hydra-sp-body\">\n        <h3>Calibration Services</h3>\n        <div class=\"hydra-sp-chips\">\n          <span class=\"hydra-chip hydra-chip--h1\"><span class=\"hydra-chip-dot\"></span>calibration services Saudi Ar