s-background\" style=\"background-color:#0C1E28;padding-top:64px;padding-bottom:0;padding-left:24px;padding-right:24px\">\n<!-- wp:columns {\"style\":{\"spacing\":{\"blockGap\":\"48px\",\"margin\":{\"bottom\":\"48px\"}}}} -->\n<div class=\"wp-block-columns\">\n<!-- wp:column {\"width\":\"40%\"} -->\n<div class=\"wp-block-column\" style=\"flex-basis:40%\">\n<!-- wp:html --><div class=\"hydra-footer-logo\"><span class=\"hydra-logo-hy\">hy</span><span class=\"hydra-logo-text\">Hydra.</span></div><!-- /wp:html -->\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"rgba(255,255,255,0.45)\"},\"typography\":{\"fontSize\":\"13px\",\"lineHeight\":\"1.7\"},\"spacing\":{\"margin\":{\"top\":\"12px\"}}}} -->\n<p style=\"color:rgba(255,255,255,0.45);font-size:13px;line-height:1.7;margin-top:12px\">© 2026 HYDRA Quality &amp; Compliance<br>Jeddah, Saudi Arabia</p>\n<!-- /wp:paragraph -->\n</div><!-- /wp:column -->\n<!-- wp:column {\"width\":\"30%\"} -->\n<div class=\"wp-block-column\" style=\"flex-basis:30%\">\n<!-- wp:heading {\"level\":4,\"style\":{\"color\":{\"text\":\"rgba(255,255,255,0.5)\"},\"typography\":{\"fontSize\":\"11px\",\"fontWeight\":\"700\",\"letterSpacing\":\"0.1em\",\"textTransform\":\"uppercase\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"16px\"}}}} --><h4 class=\"wp-block-heading\" style=\"color:rgba(255,255,255,0.5);font-size:11px;font-weight:700;letter-spacing:0.1em;text-transform:uppercase;margin-top:0;margin-bottom:16px\">Services</h4><!-- /wp:heading -->\n<!-- wp:html -->\n<ul class=\"hydra-footer-links\">\n<li><a href=\"/services/temperature-mapping-saudi-arabia/\">Temperature Mapping</a></li>\n<li><a href=\"/services/validation-qualification-services/\">Validation &amp; Qualification</a></li>\n<li><a href=\"/services/gdp-compliance-saudi-arabia/\">GDP Compliance</a></li>\n<li><a href=\"/services/pharmaceutical-consulting-saudi-arabia/\">Pharma Consulting</a></li>\n<li><a href=\"/services/cold-storage-compliance/\">Cold Storage Compliance</a></li>\n<li><a href=\"/services/pharmaceutical-quality-management-system/\">Pharma QMS</a></li>\n<li><a href=\"/services/thermal-packaging-validation/\">Thermal Packaging</a></li>\n<li><a href=\"/services/computer-system-validation-saudi-arabia/\">Computer System Validation</a></li>\n<li><a href=\"/services/cold-chain-solutions-saudi-arabia/\">Cold Chain Solutions</a></li>\n</ul>\n<!-- /wp:html -->\n</div><!-- /wp:column -->\n<!-- wp:column {\"width\":\"30%\"} -->\n<div class=\"wp-block-column\" style=\"flex-basis:30%\">\n<!-- wp:heading {\"level\":4,\"style\":{\"color\":{\"text\":\"rgba(255,255,255,0.5)\"},\"typography\":{\"fontSize\":\"11px\",\"fontWeight\":\"700\",\"letterSpacing\":\"0.1em\",\"textTransform\":\"uppercase\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"16px\"}}}} --><h4 class=\"wp-block-heading\" style=\"color:rgba(255,255,255,0.5);font-size:11px;font-weight:700;letter-spacing:0.1em;text-transform:uppercase;margin-top:0;margin-bottom:16px\">Company</h4><!-- /wp:heading -->\n<!-- wp:html -->\n<ul class=\"hydra-footer-links\">\n<li><a href=\"/about/\">About</a></li>\n<li><a href=\"/contact/\">Contact</a></li>\n</ul>\n<!-- /wp:html -->\n</div><!-- /wp:column -->\n</div><!-- /wp:columns -->\n<!-- wp:html -->\n<div class=\"hydra-footer-bar\">\n<span>hydracompliance.com</span><span>info@hydratl.com</span><span>+966 — — — — —</span>\n</div>\n<!-- /wp:html -->\n</div>\n<!-- /wp:group -->\n\n<!-- wp:html -->\n<script type=\"application/ld+json\">\n{\n  \"@context\":\"https://schema.org\",\n  \"@type\":\"ProfessionalService\",\n  \"@id\":\"https://hydracompliance.com/#organization\",\n  \"name\":\"HYDRA Quality & Compliance\",\n  \"url\":\"https://hydracompliance.com\",\n  \"telephone\":\"+966\",\n  \"email\":\"info@hydratl.com\",\n  \"logo\":\"https://hydracompliance.com/wp-content/uploads/hydra-logo.svg\",\n  \"image\":\"https://hydracompliance.com/wp-content/uploads/hydra-logo.svg\",\n  \"address\":{\n    \"@type\":\"PostalAddress\",\n    \"streetAddress\":\"3rd Floor, Alnankeel Business Center, Alhmra District\",\n    \"addressLocality\":\"Jeddah\",\n    \"addressRegion\":\"Makkah Province\",\n    \"addressCountry\":\"SA\"\n  },\n  \"geo\":{\n    \"@type\":\"GeoCoordinates\",\n    \"latitude\":21.5433,\n    \"longitude\":39.1728\n  },\n  \"openingHoursSpecification\":[{\n    \"@type\":\"OpeningHoursSpecification\",\n    \"dayOfWeek\":[\"Sunday\",\"Monday\",\"Tuesday\",\"Wednesday\",\"Thursday\"],\n    \"opens\":\"08:00\",\n    \"closes\":\"17:00\"\n  }],\n  \"sameAs\":[\"https://hydracompliance.com\"],\n  \"areaServed\":{\n    \"@type\":\"Country\",\n    \"name\":\"Saudi Arabia\"\n  },\n  \"knowsAbout\":[\"Pharmaceutical Compliance\",\"GDP\",\"GMP\",\"Temperature Mapping\",\"SFDA\",\"WHO GDP\",\"Cold Chain\",\"Validation\",\"QMS\"]\n}\n</script>\n<!-- /wp:html -->\n\n<!-- wp:html -->\n<script type=\"application/ld+json\">\n{\n  \"@context\":\"https://schema.org\",\n  \"@type\":\"FAQPage\",\n  \"mainEntity\":[\n    {\n      \"@type\":\"Question\",\n      \"name\":\"What is temperature mapping and why do I need it?\",\n      \"acceptedAnswer\":{\"@type\":\"Answer\",\"text\":\"Temperature mapping is a validated study that proves your storage or transport environment stays within required limits (typically 2–8 °C or 15–25 °C) under real-world conditions. SFDA and WHO GDP require mapped, qualified storage for all pharmaceutical products.\"}\n    },\n    {\n      \"@type\":\"Question\",\n      \"name\":\"How long does a temperature mapping study take?\",\n      \"acceptedAnswer\":{\"@type\":\"Answer\",\"text\":\"A standard warehouse study takes 5–15 days of data collection plus 3–5 days for the report. Chamber mapping is typically 3–7 days. HYDRA delivers a complete validated report ready for SFDA submission.\"}\n    },\n    {\n      \"@type\":\"Question\",\n      \"name\":\"Do you serve companies outside Jeddah?\",\n      \"acceptedAnswer\":{\"@type\":\"Answer\",\"text\":\"Yes. HYDRA operates across all of Saudi Arabia — Riyadh, Dammam, Mecca, Medina, and all regions. We also serve UAE-based companies with KSA operations.\"}\n    },\n    {\n      \"@type\":\"Question\",\n      \"name\":\"What is the difference between GDP and GMP?\",\n      \"acceptedAnswer\":{\"@type\":\"Answer\",\"text\":\"GMP (Good Manufacturing Practice) covers pharmaceutical manufacturing. GDP (Good Distribution Practice) covers storage, handling, and transport of finished pharmaceutical products. HYDRA specialises in GDP.\"}\n    },\n    {\n      \"@type\":\"Question\",\n      \"name\":\"How quickly can you start?\",\n      \"acceptedAnswer\":{\"@type\":\"Answer\",\"text\":\"We typically respond to enquiries within 24 hours and can mobilise within 3–5 business days. Contact us for an urgent requirement.\"}\n    }\n  ]\n}\n</script>\n<!-- /wp:html -->','Home','','inherit','closed','closed','','5-revision-v1','','','2026-05-14 19:40:02','2026-05-14 19:40:02','',5,'http://hydra-compliance.local/?p=85',0,'revision','',0),(86,0,'2026-05-14 19:40:02','2026-05-14 19:40:02','@import url(\'https://fonts.googleapis.com/css2?family=DM+Sans:wght@400;500;600;700&family=DM+Serif+Display:ital@0;1&display=swap\');\n\n:root {\n  --hc-teal:    #016B7A;\n  --hc-dark:    #014F59;\n  --hc-gold:    #C8922A;\n  --hc-navy:    #0C1E28;\n  --hc-muted:   #5E7580;\n  --hc-offwhite:#F5F8F9;\n  --hc-border:  #E0EAF0;\n}\n\n/* ── Global ── */\nbody { font-family: \'DM Sans\', sans-serif; color: var(--hc-navy); }\nh1,h2,h3,h4,h5,h6 { font-family: \'DM Serif Display\', serif; }\n.hydra-gold-italic { color: var(--hc-gold); font-style: italic; }\n\n/* ── Pill tag ── */\n.hydra-pill {\n  display: inline-flex;\n  align-items: center;\n  gap: 8px;\n  background: rgba(200,146,42,0.15);\n  color: var(--hc-gold);\n  border: 1px solid rgba(200,146,42,0.3);\n  border-radius: 100px;\n  padding: 6px 16px;\n  font-size: 13px;\n  font-weight: 500;\n  letter-spacing: 0.02em;\n}\n.hydra-dot {\n  width: 8px;\n  height: 8px;\n  background: var(--hc-gold);\n  border-radius: 50%;\n  flex-shrink: 0;\n  animation: hydra-pulse 2s ease-in-out infinite;\n}\n@keyframes hydra-pulse {\n  0%,100% { box-shadow: 0 0 0 0 rgba(200,146,42,0.6); }\n  50%      { box-shadow: 0 0 0 6px rgba(200,146,42,0); }\n}\n\n/* ── Hero badges ── */\n.hydra-badges {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 8px;\n}\n.hydra-badges span {\n  border: 1px solid rgba(255,255,255,0.2);\n  color: rgba(255,255,255,0.65);\n  border-radius: 4px;\n  padding: 4px 12px;\n  font-size: 12px;\n  letter-spacing: 0.04em;\n}\n\n/* ── Services grid ── */\n.hydra-services-grid {\n  display: grid;\n  grid-template-columns: repeat(3, 1fr);\n  gap: 24px;\n}\n@media (max-width: 768px) {\n  .hydra-services-grid { grid-template-columns: 1fr; }\n}\n@media (min-width: 769px) and (max-width: 1024px) {\n  .hydra-services-grid { grid-template-columns: repeat(2, 1fr); }\n}\n.hydra-card {\n  background: #fff;\n  border: 1px solid var(--hc-border);\n  border-radius: 12px;\n  padding: 28px;\n  transition: box-shadow 0.2s ease, border-color 0.2s ease;\n}\n.hydra-card:hover {\n  border-color: var(--hc-teal);\n  box-shadow: 0 8px 32px rgba(1,107,122,0.1);\n}\n.hydra-card-icon {\n  font-size: 32px;\n  line-height: 1;\n  margin-bottom: 14px;\n}\n.hydra-card h3 {\n  font-family: \'DM Serif Display\', serif;\n  font-size: 18px;\n  font-weight: 400;\n  color: var(--hc-navy);\n  margin: 0 0 8px;\n  line-height: 1.3;\n}\n.hydra-card p {\n  font-size: 14px;\n  color: var(--hc-muted);\n  line-height: 1.6;\n  margin: 0 0 16px;\n}\n.hydra-card a {\n  font-size: 14px;\n  font-weight: 600;\n  color: var(--hc-teal);\n  text-decoration: none;\n}\n.hydra-card a:hover { color: var(--hc-dark); }\n\n/* ── Industries ── */\n.hydra-industries {\n  display: grid;\n  grid-template-columns: repeat(6, 1fr);\n  gap: 16px;\n}\n@media (max-width: 768px) {\n  .hydra-industries { grid-template-columns: repeat(3, 1fr); }\n}\n@media (max-width: 480px) {\n  .hydra-industries { grid-template-columns: repeat(2, 1fr); }\n}\n.hydra-industry {\n  background: rgba(1,107,122,0.08);\n  border: 1px solid rgba(1,79,89,0.15);\n  border-radius: 10px;\n  padding: 20px 16px;\n  text-align: center;\n  transition: background 0.2s;\n}\n.hydra-industry:hover { background: rgba(1,107,122,0.14); }\n.hydra-industry span { font-size: 28px; display: block; margin-bottom: 8px; }\n.hydra-industry p { font-size: 13px; font-weight: 600; color: var(--hc-dark); margin: 0; }\n\n/* ── FAQ ── */\n.wp-block-details summary {\n  list-style: none;\n  font-size: 16px;\n  font-weight: 600;\n  color: var(--hc-navy);\n  cursor: pointer;\n  display: flex;\n  justify-content: space-between;\n  align-items: center;\n}\n.wp-block-details summary::after {\n  content: \'+\';\n  font-size: 20px;\n  color: var(--hc-teal);\n  font-weight: 300;\n  transition: transform 0.2s;\n}\n.wp-block-details[open] summary::after { content: \'−\'; }\n\n/* ── Header logo ── */\n.hydra-logo-hy {\n  font-family: \'DM Serif Display\', serif;\n  font-size: 22px;\n  color: var(--hc-gold);\n  font-style: italic;\n}\n.hydra-logo-text {\n  font-family: \'DM Sans\', sans-serif;\n  font-size: 20px;\n  font-weight: 700;\n  color: var(--hc-navy);\n  letter-spacing: -0.02em;\n}\n.hydra-footer-logo { display: flex; align-items: baseline; gap: 2px; }\n.hydra-footer-logo .hydra-logo-hy { color: var(--hc-gold); }\n.hydra-footer-logo .hydra-logo-text { color: #fff; }\n\n/* ── Footer ── */\n.hydra-footer-links {\n  list-style: none;\n  padding: 0;\n  margin: 0;\n}\n.hydra-footer-links li { margin-bottom: 10px; }\n.hydra-footer-links a {\n  color: rgba(255,255,255,0.6);\n  font-size: 14px;\n  text-decoration: none;\n  transition: color 0.15s;\n}\n.hydra-footer-links a:hover { color: #fff; }\n.hydra-footer-bar {\n  border-top: 1px solid rgba(255,255,255,0.08);\n  padding: 20px 0;\n  display: flex;\n  gap: 32px;\n  flex-wrap: wrap;\n  font-size: 13px;\n  color: rgba(255,255,255,0.35);\n}\n\n/* ── Kadence header overrides ── */\n.site-header .header-navigation .nav-menu > li > a {\n  font-family: \'DM Sans\', sans-serif;\n  font-size: 14px;\n  font-weight: 500;\n  color: var(--hc-navy);\n}\n.site-header {\n  border-bottom: 1px solid var(--hc-border);\n}\n\n/* ── Button outline fix ── */\n.wp-block-button.is-style-outline .wp-block-button__link {\n  background: transparent !important;\n}\n/* ── Site logo text fallback (if SVG does not render) ── */\n.custom-logo-link { text-decoration: none; }\n.site-branding { display: flex; align-items: center; }\n\n/* ── Fullwidth page: remove default padding ── */\n.content-style-unboxed .entry-content > * { max-width: none !important; padding-left: 0 !important; padding-right: 0 !important; }\n.page-template-default.page .entry-content .alignfull { margin-left: calc(-1 * var(--wp--style--root--padding-left, 0px)); margin-right: calc(-1 * var(--wp--style--root--padding-right, 0px)); width: calc(100% + var(--wp--style--root--padding-left, 0px) + var(--wp--style--root--padding-right, 0px)); }\n\n/* ── Remove Kadence default page hero/title area ── */\n.hide-title .entry-header { display: none; }\n\n/* ══ SERVICE PAGE STYLES ══════════════════════════════════════════════════ */\n\n/* Breadcrumb bar */\n.hydra-breadcrumb-bar .breadcrumbs,\n.hydra-breadcrumb-bar .rank-math-breadcrumb {\n  font-size: 13px;\n  color: rgba(255,255,255,0.5);\n  padding: 0;\n}\n.hydra-breadcrumb-bar .breadcrumbs a,\n.hydra-breadcrumb-bar .rank-math-breadcrumb a {\n  color: rgba(255,255,255,0.6);\n  text-decoration: none;\n}\n.hydra-breadcrumb-bar .breadcrumbs a:hover,\n.hydra-breadcrumb-bar .rank-math-breadcrumb a:hover { color: #fff; }\n\n/* Checkmark list */\n.hydra-checklist {\n  list-style: none;\n  padding: 0;\n  margin: 0 0 24px;\n}\n.hydra-checklist li {\n  position: relative;\n  padding-left: 24px;\n  font-size: 15px;\n  color: #3D5460;\n  line-height: 1.7;\n  margin-bottom: 8px;\n}\n.hydra-checklist li::before {\n  content: \'✓\';\n  position: absolute;\n  left: 0;\n  top: 0;\n  color: #016B7A;\n  font-weight: 700;\n}\n\n/* Process ordered list */\n.hydra-process-list {\n  padding-left: 0;\n  margin: 0 0 24px;\n  counter-reset: process-step;\n  list-style: none;\n}\n.hydra-process-list li {\n  counter-increment: process-step;\n  position: relative;\n  padding-left: 44px;\n  font-size: 15px;\n  color: #3D5460;\n  line-height: 1.7;\n  margin-bottom: 16px;\n}\n.hydra-process-list li::before {\n  content: counter(process-step);\n  position: absolute;\n  left: 0;\n  top: 0;\n  width: 28px;\n  height: 28px;\n  background: #016B7A;\n  color: #fff;\n  border-radius: 50%;\n  font-size: 13px;\n  font-weight: 700;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  line-height: 1;\n}\n.hydra-process-list li strong { color: #0C1E28; }\n\n/* Quote card */\n.hydra-quote-card {\n  position: sticky;\n  top: 100px;\n}\n.hydra-quote-card .wpforms-form .wpforms-field-label {\n  font-size: 13px;\n  font-weight: 600;\n  color: #5E7580;\n  margin-bottom: 4px;\n}\n.hydra-quote-card .wpforms-form input[type=\"text\"],\n.hydra-quote-card .wpforms-form input[type=\"email\"],\n.hydra-quote-card .wpforms-form select {\n  width: 100%;\n  border: 1px solid #E0EAF0;\n  border-radius: 6px;\n  padding: 10px 12px;\n  font-size: 14px;\n  font-family: \'DM Sans\', sans-serif;\n  color: #0C1E28;\n  background: #F5F8F9;\n  transition: border-color 0.15s;\n}\n.hydra-quote-card .wpforms-form input:focus,\n.hydra-quote-card .wpforms-form select:focus {\n  border-color: #016B7A;\n  outline: none;\n  background: #fff;\n}\n.hydra-quote-card .wpforms-form .wpforms-submit-container {\n  margin-top: 16px;\n}\n.hydra-quote-card .wpforms-form button[type=\"submit\"],\n.hydra-quote-card .wpforms-form .wpforms-submit {\n  width: 100%;\n  background: #C8922A;\n  color: #fff;\n  border: none;\n  border-radius: 6px;\n  padding: 12px 20px;\n  font-size: 14px;\n  font-weight: 700;\n  font-family: \'DM Sans\', sans-serif;\n  cursor: pointer;\n  transition: background 0.2s;\n}\n.hydra-quote-card .wpforms-form button[type=\"submit\"]:hover,\n.hydra-quote-card .wpforms-form .wpforms-submit:hover { background: #b07a22; }\n\n/* Contact card */\n.hydra-contact-list {\n  list-style: none;\n  padding: 0;\n  margin: 0;\n}\n.hydra-contact-list li {\n  display: flex;\n  align-items: flex-start;\n  gap: 10px;\n  font-size: 14px;\n  color: #3D5460;\n  line-height: 1.6;\n  margin-bottom: 10px;\n}\n.hydra-contact-list li:last-child { margin-bottom: 0; }\n.hydra-contact-list li span { font-size: 16px; flex-shrink: 0; margin-top: 1px; }\n\n/* Related services grid */\n.hydra-related-grid {\n  display: grid;\n  grid-template-columns: repeat(3, 1fr);\n  gap: 24px;\n}\n@media (max-width: 768px) {\n  .hydra-related-grid { grid-template-columns: 1fr; }\n}\n.hydra-related-card {\n  background: #F5F8F9;\n  border: 1px solid #E0EAF0;\n  border-radius: 12px;\n  padding: 24px;\n  transition: border-color 0.2s, box-shadow 0.2s;\n}\n.hydra-related-card:hover {\n  border-color: #016B7A;\n  box-shadow: 0 4px 20px rgba(1,107,122,0.08);\n}\n.hydra-related-icon { font-size: 28px; margin-bottom: 10px; }\n.hydra-related-card h3 {\n  font-family: \'DM Serif Display\', serif;\n  font-size: 17px;\n  font-weight: 400;\n  color: #0C1E28;\n  margin: 0 0 6px;\n}\n.hydra-related-card p {\n  font-size: 13px;\n  color: #5E7580;\n  line-height: 1.6;\n  margin: 0 0 12px;\n}\n.hydra-related-card a {\n  font-size: 13px;\n  font-weight: 600;\n  color: #016B7A;\n  text-decoration: none;\n}\n.hydra-related-card a:hover { color: #014F59; }\n\n/* Sidebar sticky on desktop */\n@media (min-width: 768px) {\n  .hydra-svc-sidebar { position: sticky; top: 90px; align-self: flex-start; }\n}\n/* ══ ABOUT PAGE ══════════════════════════════════════════════════════════ */\n.hydra-creds-grid {\n  display: grid;\n  grid-template-columns: repeat(3, 1fr);\n  gap: 28px;\n}\n@media (max-width: 768px) {\n  .hydra-creds-grid { grid-template-columns: 1fr; }\n}\n.hydra-cred-card {\n  border: 1px solid #E0EAF0;\n  border-radius: 12px;\n  padding: 32px 28px;\n  text-align: center;\n  background: #fff;\n  transition: box-shadow 0.2s;\n}\n.hydra-cred-card:hover { box-shadow: 0 8px 32px rgba(1,107,122,0.08); }\n.hydra-cred-number {\n  font-family: \'DM Serif Display\', serif;\n  font-size: 40px;\n  color: #016B7A;\n  margin-bottom: 12px;\n  line-height: 1;\n}\n.hydra-cred-card h3 {\n  font-family: \'DM Serif Display\', serif;\n  font-size: 18px;\n  font-weight: 400;\n  color: #0C1E28;\n  margin: 0 0 10px;\n}\n.hydra-cred-card p { font-size: 14px; color: #5E7580; line-height: 1.7; margin: 0; }\n\n/* Certifications */\n.hydra-cert-row {\n  display: flex;\n  flex-wrap: wrap;\n  justify-content: center;\n  gap: 12px;\n}\n.hydra-cert {\n  background: rgba(1,107,122,0.1);\n  border: 1px solid rgba(1,79,89,0.2);\n  color: #014F59;\n  border-radius: 100px;\n  padding: 8px 20px;\n  font-size: 13px;\n  font-weight: 600;\n  letter-spacing: 0.03em;\n}\n\n/* Why HYDRA grid */\n.hydra-why-grid {\n  display: grid;\n  grid-template-columns: repeat(2, 1fr);\n  gap: 32px;\n}\n@media (max-width: 640px) {\n  .hydra-why-grid { grid-template-columns: 1fr; }\n}\n.hydra-why-item { display: flex; flex-direction: column; gap: 10px; }\n.hydra-why-icon { font-size: 28px; }\n.hydra-why-item h3 {\n  font-family: \'DM Serif Display\', serif;\n  font-size: 20px;\n  font-weight: 400;\n  color: #0C1E28;\n  margin: 0;\n}\n.hydra-why-item p { font-size: 15px; color: #5E7580; line-height: 1.7; margin: 0; }\n/* ══ CONTACT PAGE ════════════════════════════════════════════════════════ */\n.hydra-contact-page-list {\n  list-style: none;\n  padding: 0;\n  margin: 0 0 8px;\n}\n.hydra-contact-page-list li {\n  display: flex;\n  align-items: flex-start;\n  gap: 14px;\n  padding: 14px 0;\n  border-bottom: 1px solid #F0F5F7;\n}\n.hydra-contact-page-list li:first-child { padding-top: 0; }\n.hydra-contact-page-list li:last-child { border-bottom: none; }\n.hydra-contact-icon { font-size: 20px; flex-shrink: 0; margin-top: 2px; }\n.hydra-contact-page-list strong {\n  display: block;\n  font-size: 12px;\n  font-weight: 700;\n  text-transform: uppercase;\n  letter-spacing: 0.08em;\n  color: #5E7580;\n  margin-bottom: 2px;\n}\n.hydra-contact-page-list span {\n  font-size: 15px;\n  color: #0C1E28;\n  line-height: 1.5;\n}\n.hydra-contact-page-list a {\n  color: #016B7A;\n  text-decoration: none;\n}\n.hydra-contact-page-list a:hover { color: #014F59; }\n.hydra-map-wrap { border-radius: 10px; overflow: hidden; }\n\n/* Contact form card */\n.hydra-contact-form-card .wpforms-form .wpforms-field-label {\n  font-size: 13px;\n  font-weight: 600;\n  color: #5E7580;\n  margin-bottom: 5px;\n}\n.hydra-contact-form-card .wpforms-form input[type=\"text\"],\n.hydra-contact-form-card .wpforms-form input[type=\"email\"],\n.hydra-contact-form-card .wpforms-form select,\n.hydra-contact-form-card .wpforms-form textarea {\n  width: 100%;\n  border: 1px solid #E0EAF0;\n  border-radius: 6px;\n  padding: 10px 12px;\n  font-size: 14px;\n  font-family: \'DM Sans\', sans-serif;\n  color: #0C1E28;\n  background: #F5F8F9;\n  transition: border-color 0.15s;\n  resize: vertical;\n}\n.hydra-contact-form-card .wpforms-form input:focus,\n.hydra-contact-form-card .wpforms-form select:focus,\n.hydra-contact-form-card .wpforms-form textarea:focus {\n  border-color: #016B7A;\n  outline: none;\n  background: #fff;\n}\n.hydra-contact-form-card .wpforms-submit-container { margin-top: 16px; }\n.hydra-contact-form-card .wpforms-submit,\n.hydra-contact-form-card button[type=\"submit\"] {\n  width: 100%;\n  background: #016B7A;\n  color: #fff;\n  border: none;\n  border-radius: 6px;\n  padding: 14px 20px;\n  font-size: 15px;\n  font-weight: 700;\n  font-family: \'DM Sans\', sans-serif;\n  cursor: pointer;\n  transition: background 0.2s;\n}\n.hydra-contact-form-card .wpforms-submit:hover,\n.hydra-contact-form-card button[type=\"submit\"]:hover { background: #014F59; }\n\n@media (min-width: 768px) {\n  .hydra-contact-form-col { position: sticky; top: 90px; align-self: flex-start; }\n}\n/* ══ HOME PAGE — Full layout fix ════════════════════════════════════════════ */\n\n/* ── Shared section wrapper ── */\nbody.page-id-5 .entry-content > .wp-block-group.alignfull {\n  margin-left: calc(-1 * var(--wp--style--root--padding-left, 0px)) !important;\n  margin-right: calc(-1 * var(--wp--style--root--padding-right, 0px)) !important;\n  width: 100vw !important;\n  max-width: 100vw !important;\n}\n\n/* ── HERO ── */\n.hydra-hero {\n  background: #0C1E28 !important;\n  padding: 96px 24px 80px !important;\n  position: relative;\n  overflow: hidden;\n}\n.hydra-hero::before {\n  content: \'\';\n  position: absolute;\n  inset: 0;\n  background: radial-gradient(ellipse 60% 60% at 70% 40%, rgba(1,107,122,0.22) 0%, transparent 70%);\n  pointer-events: none;\n}\n.hydra-hero .wp-block-group__inner-container {\n  max-width: 1100px;\n  margin: 0 auto;\n  position: relative;\n  z-index: 1;\n}\n\n/* Pill tag */\n.hydra-pill {\n  display: inline-flex;\n  align-items: center;\n  gap: 6px;\n  background: rgba(255,255,255,0.08) !important;\n  border: 1px solid rgba(255,255,255,0.14) !important;\n  color: rgba(255,255,255,0.80) !important;\n  border-radius: 100px;\n  padding: 5px 14px 5px 10px;\n  font-size: 12px;\n  font-weight: 500;\n  letter-spacing: 0.4px;\n  text-transform: uppercase;\n  margin-bottom: 20px;\n}\n.hydra-dot {\n  width: 6px;\n  height: 6px;\n  background: #C8922A;\n  border-radius: 50%;\n  display: inline-block;\n}\n\n/* Hero heading */\n.hydra-hero h1,\n.hydra-hero .wp-block-heading {\n  font-family: \'DM Serif Display\', Georgia, serif !important;\n  font-size: clamp(34px, 5vw, 58px) !important;\n  font-weight: 400 !important;\n  color: #ffffff !important;\n  line-height: 1.12 !important;\n  letter-spacing: -0.5px;\n  margin: 0 0 20px !important;\n  max-width: 700px;\n}\n.hydra-hero h1 em { color: #C8922A; font-style: italic; }\n\n/* Hero subtext */\n.hydra-hero p {\n  font-size: 17px !important;\n  color: rgba(255,255,255,0.72) !important;\n  line-height: 1.65 !important;\n  max-width: 560px;\n  margin: 0 0 32px !important;\n}\n\n/* Hero badges */\n.hydra-badges {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 10px;\n  margin-top: 36px;\n}\n.hydra-badge {\n  display: inline-flex;\n  align-items: center;\n  gap: 6px;\n  background: rgba(255,255,255,0.06);\n  border: 1px solid rgba(255,255,255,0.12);\n  border-radius: 8px;\n  padding: 8px 14px;\n  font-size: 12px;\n  color: rgba(255,255,255,0.75);\n  font-weight: 500;\n}\n\n/* Hero CTA buttons */\n.hydra-hero .wp-block-buttons { margin-top: 32px; gap: 12px; }\n.hydra-hero .wp-block-button__link {\n  border-radius: 8px !important;\n  font-family: \'DM Sans\', sans-serif !important;\n  font-size: 14px !important;\n  font-weight: 600 !important;\n  padding: 12px 24px !important;\n  transition: background 0.2s, color 0.2s, transform 0.15s !important;\n}\n.hydra-hero .wp-block-button__link:hover { transform: translateY(-1px); }\n\n/* ── STATS BAR ── */\n.hydra-stats-bar {\n  background: #ffffff !important;\n  padding: 40px 24px !important;\n  border-bottom: 1px solid #EDF1F3;\n}\n.hydra-stats-bar .wp-block-group__inner-container {\n  max-width: 1100px;\n  margin: 0 auto;\n}\n.hydra-stats-bar .wp-block-columns {\n  gap: 0 !important;\n}\n.hydra-stats-bar .wp-block-column {\n  text-align: center;\n  padding: 16px 8px;\n  border-right: 1px solid #EDF1F3;\n}\n.hydra-stats-bar .wp-block-column:last-child { border-right: none; }\n\n/* Stat numbers — override inline font-size:44px */\n.hydra-stats-bar h3 {\n  font-family: \'DM Serif Display\', Georgia, serif !important;\n  font-size: 28px !important;\n  font-weight: 400 !important;\n  color: #016B7A !important;\n  margin: 0 0 4px !important;\n  line-height: 1.1;\n}\n/* Stat labels */\n.hydra-stats-bar p {\n  font-size: 11px !important;\n  font-weight: 500 !important;\n  color: #8FA6B2 !important;\n  text-transform: uppercase !important;\n  letter-spacing: 0.6px !important;\n  margin: 0 !important;\n}\n\n@media (max-width: 768px) {\n  .hydra-stats-bar .wp-block-columns { flex-wrap: wrap; }\n  .hydra-stats-bar .wp-block-column  { min-width: 50%; border-right: none; border-bottom: 1px solid #EDF1F3; }\n}\n\n/* ── SERVICES GRID ── */\n.hydra-services-grid-section {\n  background: #F5F8F9 !important;\n  padding: 80px 24px !important;\n}\n.hydra-services-grid-section .wp-block-group__inner-container {\n  max-width: 1100px;\n  margin: 0 auto;\n}\n.hydra-services-grid-section > .wp-block-group__inner-container > .wp-block-heading,\n.hydra-services-grid-section h2 {\n  font-family: \'DM Serif Display\', Georgia, serif !important;\n  font-size: clamp(26px, 3.5vw, 38px) !important;\n  font-weight: 400 !important;\n  color: #0C1E28 !important;\n  text-align: center;\n  margin: 0 0 8px !important;\n}\n.hydra-services-grid-section > .wp-block-group__inner-container > p {\n  text-align: center;\n  font-size: 15px !important;\n  color: #5E7580 !important;\n  margin: 0 0 48px !important;\n}\n\n.hydra-services-grid {\n  display: grid !important;\n  grid-template-columns: repeat(3, 1fr) !important;\n  gap: 20px !important;\n  list-style: none;\n  padding: 0;\n  margin: 0;\n}\n\n.hydra-card {\n  background: #ffffff !important;\n  border: 1px solid #E4ECF0 !important;\n  border-radius: 14px !important;\n  padding: 28px 24px !important;\n  transition: box-shadow 0.2s, transform 0.2s !important;\n  text-decoration: none !important;\n  display: block;\n  color: inherit;\n}\n.hydra-card:hover {\n  box-shadow: 0 8px 28px rgba(0,0,0,0.09) !important;\n  transform: translateY(-2px) !important;\n  text-decoration: none !important;\n}\n.hydra-card-icon {\n  font-size: 24px;\n  margin-bottom: 14px;\n  display: block;\n}\n.hydra-card h3 {\n  font-family: \'DM Sans\', sans-serif !important;\n  font-size: 16px !important;\n  font-weight: 700 !important;\n  color: #0C1E28 !important;\n  margin: 0 0 8px !important;\n  line-height: 1.3;\n}\n.hydra-card p {\n  font-size: 13px !important;\n  color: #5E7580 !important;\n  line-height: 1.55 !important;\n  margin: 0 !important;\n}\n\n@media (max-width: 900px) {\n  .hydra-services-grid { grid-template-columns: repeat(2, 1fr) !important; }\n}\n@media (max-width: 560px) {\n  .hydra-services-grid { grid-template-columns: 1fr !important; }\n}\n\n/* ── INDUSTRIES ── */\n.hydra-industries-section {\n  background: #E0F4F7 !important;\n  padding: 64px 24px !important;\n}\n.hydra-industries-section .wp-block-group__inner-container {\n  max-width: 1100px;\n  margin: 0 auto;\n  text-align: center;\n}\n.hydra-industries-section h2 {\n  font-family: \'DM Serif Display\', Georgia, serif !important;\n  font-size: clamp(22px, 3vw, 32px) !important;\n  font-weight: 400 !important;\n  color: #0C1E28 !important;\n  margin: 0 0 32px !important;\n}\n\n.hydra-industries {\n  display: grid !important;\n  grid-template-columns: repeat(6, 1fr) !important;\n  gap: 12px !important;\n  justify-items: center;\n}\n.hydra-industry {\n  background: #ffffff !important;\n  border: 1px solid rgba(1,107,122,0.15) !important;\n  border-radius: 100px !important;\n  padding: 10px 20px !important;\n  font-size: 13px !important;\n  font-weight: 500 !important;\n  color: #016B7A !important;\n  text-align: center;\n  white-space: nowrap;\n  transition: background 0.15s, color 0.15s;\n}\n.hydra-industry:hover {\n  background: #016B7A !important;\n  color: #ffffff !important;\n}\n\n@media (max-width: 900px) {\n  .hydra-industries { grid-template-columns: repeat(3, 1fr) !important; }\n  .hydra-industry   { white-space: normal; border-radius: 10px !important; }\n}\n@media (max-width: 560px) {\n  .hydra-industries { grid-template-columns: repeat(2, 1fr) !important; }\n}\n\n/* ── FAQ ── */\n.hydra-faq-section {\n  background: #ffffff !important;\n  padding: 80px 24px !important;\n}\n.hydra-faq-section .wp-block-group__inner-container {\n  max-width: 760px;\n  margin: 0 auto;\n}\n.hydra-faq-section h2 {\n  font-family: \'DM Serif Display\', Georgia, serif !important;\n  font-size: clamp(24px, 3vw, 36px) !important;\n  font-weight: 400 !important;\n  color: #0C1E28 !important;\n  text-align: center;\n  margin: 0 0 48px !important;\n}\n\n/* FAQ items — details/summary */\n.hydra-faq-section .wp-block-details,\n.hydra-faq-section details {\n  border: 1px solid #E4ECF0;\n  border-radius: 12px;\n  margin-bottom: 10px;\n  overflow: hidden;\n  background: #ffffff;\n  transition: box-shadow 0.2s;\n}\n.hydra-faq-section .wp-block-details[open],\n.hydra-faq-section details[open] {\n  box-shadow: 0 4px 16px rgba(0,0,0,0.07);\n}\n.hydra-faq-section .wp-block-details summary,\n.hydra-faq-section details summary {\n  list-style: none;\n  cursor: pointer;\n  padding: 18px 52px 18px 20px;\n  font-family: \'DM Sans\', sans-serif !important;\n  font-size: 15px !important;\n  font-weight: 600 !important;\n  color: #0C1E28 !important;\n  position: relative;\n  user-select: none;\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n}\n.hydra-faq-section .wp-block-details summary::-webkit-details-marker,\n.hydra-faq-section details summary::-webkit-details-marker { display: none; }\n\n/* Custom arrow via JS-injected span */\n.hydra-faq-arrow {\n  position: absolute;\n  right: 20px;\n  top: 50%;\n  transform: translateY(-50%) rotate(0deg);\n  width: 18px;\n  height: 18px;\n  transition: transform 0.25s ease;\n  flex-shrink: 0;\n}\n.hydra-faq-arrow::before,\n.hydra-faq-arrow::after {\n  content: \'\';\n  position: absolute;\n  background: #016B7A;\n  border-radius: 2px;\n  transition: transform 0.25s ease;\n}\n.hydra-faq-arrow::before { width: 10px; height: 2px; top: 8px; left: 4px; }\n.hydra-faq-arrow::after  { width: 2px;  height: 10px; top: 4px; left: 8px; }\n\n.wp-block-details[open] .hydra-faq-arrow::after,\ndetails[open] .hydra-faq-arrow::after {\n  transform: rotate(90deg);\n}\n\n.hydra-faq-section .wp-block-details > *:not(summary),\n.hydra-faq-section details > *:not(summary) {\n  padding: 0 20px 18px;\n  font-size: 14px !important;\n  color: #5E7580 !important;\n  line-height: 1.65 !important;\n  margin: 0 !important;\n}\n\n/* ── CTA BANNER ── */\n.hydra-cta-banner {\n  background: #016B7A !important;\n  padding: 72px 24px !important;\n  text-align: center;\n}\n.hydra-cta-banner .wp-block-group__inner-container {\n  max-width: 800px;\n  margin: 0 auto;\n}\n.hydra-cta-banner h2 {\n  font-family: \'DM Serif Display\', Georgia, serif !important;\n  font-size: clamp(26px, 4vw, 42px) !important;\n  font-weight: 400 !important;\n  color: #ffffff !important;\n  margin: 0 0 16px !important;\n  line-height: 1.15;\n}\n.hydra-cta-banner p {\n  font-size: 16px !important;\n  color: rgba(255,255,255,0.82) !important;\n  margin: 0 0 32px !important;\n  line-height: 1.6;\n}\n.hydra-cta-banner .wp-block-buttons { justify-content: center; gap: 12px; }\n.hydra-cta-banner .wp-block-button__link {\n  border-radius: 8px !important;\n  font-family: \'DM Sans\', sans-serif !important;\n  font-size: 14px !important;\n  font-weight: 600 !important;\n  padding: 13px 28px !important;\n  transition: background 0.2s, color 0.2s !important;\n}\n/* Primary button in CTA = white with teal text */\n.hydra-cta-banner .wp-block-button:first-child .wp-block-button__link {\n  background: #ffffff !important;\n  color: #016B7A !important;\n  border: 2px solid #ffffff !important;\n}\n.hydra-cta-banner .wp-block-button:first-child .wp-block-button__link:hover {\n  background: #F0FAFB !important;\n  color: #014F59 !important;\n}\n/* Secondary / outline button */\n.hydra-cta-banner .wp-block-button:not(:first-child) .wp-block-button__link {\n  background: transparent !important;\n  color: rgba(255,255,255,0.90) !important;\n  border: 2px solid rgba(255,255,255,0.45) !important;\n}\n.hydra-cta-banner .wp-block-button:not(:first-child) .wp-block-button__link:hover {\n  border-color: #ffffff !important;\n  color: #ffffff !important;\n}\n\n/* ── FOOTER ── */\n.hydra-footer {\n  background: #0C1E28 !important;\n  padding: 56px 24px 32px !important;\n}\n.hydra-footer .wp-block-group__inner-container {\n  max-width: 1100px;\n  margin: 0 auto;\n}\n.hydra-footer .wp-block-columns {\n  gap: 40px !important;\n  margin-bottom: 40px;\n}\n.hydra-footer h3 {\n  font-family: \'DM Sans\', sans-serif !important;\n  font-size: 12px !important;\n  font-weight: 700 !important;\n  color: rgba(255,255,255,0.40) !important;\n  text-transform: uppercase !important;\n  letter-spacing: 1px !important;\n  margin: 0 0 16px !important;\n}\n.hydra-footer p,\n.hydra-footer li {\n  font-size: 13px !important;\n  color: rgba(255,255,255,0.60) !important;\n  line-height: 1.7 !important;\n  margin: 0 0 4px !important;\n}\n.hydra-footer a {\n  color: rgba(255,255,255,0.60) !important;\n  text-decoration: none !important;\n  transition: color 0.15s;\n}\n.hydra-footer a:hover { color: #ffffff !important; }\n.hydra-footer ul { list-style: none; padding: 0; margin: 0; }\n.hydra-footer ul li { margin-bottom: 8px; }\n\n/* Footer logo / brand */\n.hydra-footer .site-title,\n.hydra-footer strong {\n  font-family: \'DM Sans\', sans-serif !important;\n  font-size: 18px !important;\n  font-weight: 700 !important;\n  color: #ffffff !important;\n}\n\n/* Footer bottom bar */\n.hydra-footer-bottom,\n.hydra-footer .wp-block-separator + p,\n.hydra-footer hr ~ p {\n  border-top: 1px solid rgba(255,255,255,0.08);\n  padding-top: 20px;\n  margin-top: 0 !important;\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  flex-wrap: wrap;\n  gap: 8px;\n  font-size: 12px !important;\n  color: rgba(255,255,255,0.35) !important;\n}\n.hydra-footer .wp-block-separator {\n  border-color: rgba(255,255,255,0.08) !important;\n  margin: 0 0 20px !important;\n}\n\n/* Scroll shadow on header when page is scrolled */\n#masthead.scrolled,\n.site-header.scrolled {\n  box-shadow: 0 2px 20px rgba(0,0,0,0.12) !important;\n}\n/* ══ HYDRA HEADER ════════════════════════════════════════════════════════════ */\n\n/* ── Base: sticky, white, shadow, border ── */\n#masthead,\n.site-header {\n  position: sticky !important;\n  top: 0 !important;\n  z-index: 9999 !important;\n  background: #ffffff !important;\n  box-shadow: 0 1px 12px rgba(0,0,0,0.05) !important;\n  border-bottom: 1px solid rgba(0,0,0,0.08) !important;\n  transition: box-shadow 0.2s;\n}\n#masthead.scrolled,\n.site-header.scrolled {\n  box-shadow: 0 2px 20px rgba(0,0,0,0.10) !important;\n}\n\n/* Admin-bar offsets */\n.admin-bar #masthead,\n.admin-bar .site-header { top: 32px !important; }\n@media (max-width: 782px) {\n  .admin-bar #masthead,\n  .admin-bar .site-header { top: 46px !important; }\n}\n@media (max-width: 600px) {\n  .admin-bar #masthead,\n  .admin-bar .site-header { top: 0 !important; }\n}\n\n/* ── Row height: 64px ── */\n.site-main-header-inner-wrap,\n#masthead .kadence-header-inner-wrap,\n#masthead .header-inner-wrap {\n  min-height: 64px !important;\n  display: flex;\n  align-items: center;\n}\n\n/* ── Hide site title text ── */\n.site-title,\n.site-title-wrap,\n.site-branding .site-title,\np.site-title {\n  display: none !important;\n}\n\n/* ── Logo ── */\n.site-branding a.brand,\n.custom-logo-link {\n  display: inline-flex;\n  align-items: center;\n  text-decoration: none !important;\n}\n.custom-logo,\n.site-branding img.custom-logo,\n.site-branding img.svg-logo-image {\n  height: 32px !important;\n  width: auto !important;\n  max-width: 110px !important;\n  display: block;\n}\n\n/* ── Center nav column ── */\n.site-header-main-section-center {\n  flex: 1;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n}\n\n/* ── Primary navigation ── */\n.main-navigation .primary-menu-container > ul,\n.header-navigation .nav-menu,\n#primary-menu {\n  display: flex !important;\n  align-items: center !important;\n  gap: 2px !important;\n  list-style: none !important;\n  margin: 0 !important;\n  padding: 0 !important;\n  flex-wrap: nowrap;\n}\n\n/* Top-level links */\n.main-navigation .primary-menu-container > ul > li > a,\n.header-navigation .nav-menu > li > a,\n#primary-menu > li > a {\n  font-family: \'DM Sans\', sans-serif !important;\n  font-size: 14px !important;\n  font-weight: 400 !important;\n  color: #5E7580 !important;\n  text-decoration: none !important;\n  padding: 6px 12px !important;\n  border-radius: 5px;\n  transition: color 0.15s, background 0.15s;\n  display: block;\n  white-space: nowrap;\n}\n.main-navigation .primary-menu-container > ul > li > a:hover,\n.header-navigation .nav-menu > li > a:hover,\n#primary-menu > li > a:hover,\n.main-navigation .primary-menu-container > ul > li.current-menu-item > a,\n.main-navigation .primary-menu-container > ul > li.current-menu-ancestor > a {\n  color: #016B7A !important;\n  background: rgba(1,107,122,0.06) !important;\n}\n\n/* Dropdown chevron */\n.main-navigation .primary-menu-container > ul > li.menu-item-has-children > a::after,\n.header-navigation .nav-menu > li.menu-item-has-children > a::after {\n  content: \'\';\n  display: inline-block;\n  width: 0;\n  height: 0;\n  border-left: 3.5px solid transparent;\n  border-right: 3.5px solid transparent;\n  border-top: 4px solid currentColor;\n  margin-left: 5px;\n  vertical-align: middle;\n  opacity: 0.55;\n  transition: transform 0.2s;\n}\n.main-navigation .primary-menu-container > ul > li.menu-item-has-children:hover > a::after,\n.header-navigation .nav-menu > li.menu-item-has-children:hover > a::after {\n  transform: rotate(180deg);\n}\n\n/* ── Dropdown sub-menu ── */\n.main-navigation .primary-menu-container ul ul.sub-menu,\n.header-navigation .nav-menu .sub-menu {\n  position: absolute !important;\n  top: calc(100% + 6px) !important;\n  left: 0 !important;\n  background: #ffffff !important;\n  border: 1px solid rgba(0,0,0,0.08) !important;\n  border-radius: 10px !important;\n  box-shadow: 0 8px 32px rgba(0,0,0,0.10) !important;\n  padding: 6px !important;\n  min-width: 230px !important;\n  list-style: none !important;\n  margin: 0 !important;\n  opacity: 0;\n  visibility: hidden;\n  transform: translateY(6px);\n  transition: opacity 0.18s, transform 0.18s, visibility 0.18s;\n  z-index: 1000;\n  display: block !important;\n}\n.main-navigation .primary-menu-container > ul > li:hover > ul.sub-menu,\n.main-navigation .primary-menu-container > ul > li:focus-within > ul.sub-menu,\n.header-navigation .nav-menu > li:hover > .sub-menu,\n.header-navigation .nav-menu > li:focus-within > .sub-menu {\n  opacity: 1 !important;\n  visibility: visible !important;\n  transform: translateY(0) !important;\n}\n.main-navigation .primary-menu-container ul ul li,\n.header-navigation .nav-menu .sub-menu li {\n  position: relative;\n  border: none !important;\n  border-radius: 0 !important;\n}\n.main-navigation .primary-menu-container ul ul li a,\n.header-navigation .nav-menu .sub-menu li a {\n  font-family: \'DM Sans\', sans-serif !important;\n  font-size: 13px !important;\n  font-weight: 400 !important;\n  color: #3D5460 !important;\n  background: transparent !important;\n  padding: 9px 12px !important;\n  border-radius: 6px !important;\n  display: block;\n  width: auto !important;\n  transition: background 0.12s, color 0.12s;\n  text-decoration: none;\n  border: none !important;\n}\n.main-navigation .primary-menu-container ul ul li a:hover,\n.header-navigation .nav-menu .sub-menu li a:hover {\n  background: #F0F9FA !important;\n  color: #016B7A !important;\n}\n\n/* ── CTA Button ── */\n.header-button-wrap a,\n.header-button-wrap .kt-button,\n.kadence-header-button a,\na.header-button {\n  display: inline-flex !important;\n  align-items: center;\n  background: #016B7A !important;\n  color: #ffffff !important;\n  padding: 9px 20px !important;\n  border-radius: 6px !important;\n  font-family: \'DM Sans\', sans-serif !important;\n  font-size: 13px !important;\n  font-weight: 500 !important;\n  text-decoration: none !important;\n  border: none !important;\n  cursor: pointer;\n  transition: background 0.18s !important;\n  white-space: nowrap;\n  margin-left: 8px;\n  box-shadow: none !important;\n}\n.header-button-wrap a:hover,\n.header-button-wrap .kt-button:hover,\n.kadence-header-button a:hover {\n  background: #014F59 !important;\n  color: #ffffff !important;\n  box-shadow: none !important;\n}\n\n/* ── Mobile: under 768px ── */\n@media (max-width: 767px) {\n\n  /* Hide desktop nav and button from header row */\n  .site-header-main-section-center,\n  .header-navigation.header-navigation-main,\n  .site-header-main-section-right .header-button-wrap {\n    display: none !important;\n  }\n\n  /* Show hamburger toggle */\n  .mobile-toggle-open-container,\n  .kadence-mobile-nav-toggle,\n  .site-header-item-navgation-popup-toggle {\n    display: flex !important;\n    align-items: center;\n  }\n\n  /* Hamburger icon styling */\n  .mobile-toggle-open-container .menu-toggle-open,\n  .kadence-mobile-nav-toggle button,\n  button.menu-toggle {\n    background: none !important;\n    border: none !important;\n    color: #0C1E28 !important;\n    font-size: 22px !important;\n    padding: 6px 8px !important;\n    cursor: pointer;\n    display: flex;\n    align-items: center;\n  }\n  .mobile-toggle-open-container .menu-toggle-icon { font-size: 22px !important; }\n\n  /* Mobile drawer */\n  #mobile-drawer .mobile-navigation,\n  .kadence-mobile-nav-wrap,\n  .mobile-navigation-wrap {\n    background: #ffffff !important;\n    border-top: 1px solid rgba(0,0,0,0.07) !important;\n  }\n\n  /* Mobile nav links */\n  .mobile-navigation ul li a,\n  .kadence-mobile-nav-wrap .nav-menu li a,\n  #mobile-drawer ul li a {\n    font-family: \'DM Sans\', sans-serif !important;\n    font-size: 15px !important;\n    color: #0C1E28 !important;\n    padding: 12px 20px !important;\n    border-bottom: 1px solid rgba(0,0,0,0.05) !important;\n    display: block !important;\n  }\n  .mobile-navigation ul li a:hover,\n  .kadence-mobile-nav-wrap .nav-menu li a:hover {\n    color: #016B7A !important;\n    background: #F5FAFA !important;\n  }\n\n  /* Sub-menu in mobile */\n  .mobile-navigation ul ul.sub-menu li a,\n  #mobile-drawer ul ul li a {\n    font-size: 14px !important;\n    color: #5E7580 !important;\n    padding-left: 36px !important;\n    background: #F8FAFA !important;\n  }\n  .mobile-navigation ul li.menu-item-has-children > .drawer-nav-drop-wrap,\n  #mobile-drawer ul li.menu-item-has-children > .drawer-nav-drop-wrap {\n    color: #0C1E28 !important;\n    border-bottom: 1px solid rgba(0,0,0,0.05) !important;\n  }\n\n  /* CTA button in mobile drawer */\n  .mobile-html-content a,\n  #mobile-drawer .mobile-html a {\n    display: block !important;\n    background: #016B7A !important;\n    color: #ffffff !important;\n    text-align: center !important;\n    padding: 13px 20px !important;\n    margin: 16px 20px !important;\n    border-radius: 8px !important;\n    font-family: \'DM Sans\', sans-serif !important;\n    font-size: 14px !important;\n    font-weight: 600 !important;\n    text-decoration: none !important;\n  }\n  .mobile-html-content a:hover,\n  #mobile-drawer .mobile-html a:hover {\n    background: #014F59 !important;\n    color: #ffffff !important;\n  }\n}\n/* ══ SERVICES/PRODUCTS GRID ══════════════════════════════════════════════════ */\n\n.hydra-sp-section { background: #ffffff !important; }\n\n.hydra-sp-inner {\n  max-width: 1280px;\n  margin: 0 auto;\n}\n\n/* Section header */\n.hydra-sp-label {\n  font-family: \'DM Sans\', sans-serif;\n  font-size: 11px;\n  font-weight: 500;\n  letter-spacing: 1.5px;\n  text-transform: uppercase;\n  color: #016B7A;\n  text-align: center;\n  margin-bottom: 12px;\n}\n.hydra-sp-h2 {\n  font-family: \'DM Serif Display\', Georgia, serif;\n  font-size: clamp(26px, 3.5vw, 36px);\n  font-weight: 400;\n  color: #0C1E28;\n  text-align: center;\n  margin: 0 0 10px;\n  line-height: 1.2;\n}\n.hydra-sp-sub {\n  font-family: \'DM Sans\', sans-serif;\n  font-size: 14px;\n  color: #5E7580;\n  text-align: center;\n  margin: 0 0 48px;\n  line-height: 1.6;\n}\n\n/* Grid */\n.hydra-sp-grid {\n  display: grid;\n  grid-template-columns: repeat(3, 1fr);\n  gap: 28px;\n}\n\n/* Card */\n.hydra-sp-card {\n  display: flex;\n  flex-direction: column;\n  background: #ffffff;\n  border: 1px solid rgba(0,0,0,0.10);\n  border-radius: 12px;\n  overflow: hidden;\n  cursor: pointer;\n  text-decoration: none !important;\n  color: inherit;\n  transition: box-shadow 0.2s ease, transform 0.2s ease, border-color 0.2s ease;\n}\n.hydra-sp-card:hover {\n  box-shadow: 0 8px 32px rgba(0,0,0,0.12);\n  transform: translateY(-2px);\n  border-color: rgba(1,107,122,0.20);\n  text-decoration: none !important;\n}\n\n/* Top image area */\n.hydra-sp-img {\n  height: 140px;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  flex-shrink: 0;\n}\n.hydra-sp-img svg {\n  width: 48px;\n  height: 48px;\n  display: block;\n}\n\n/* Card body */\n.hydra-sp-body {\n  padding: 20px;\n  display: flex;\n  flex-direction: column;\n  flex: 1;\n}\n.hydra-sp-body h3 {\n  font-family: \'DM Sans\', sans-serif !important;\n  font-size: 15px !important;\n  font-weight: 600 !important;\n  color: #0C1E28 !important;\n  margin: 0 0 8px !important;\n  line-height: 1.3 !important;\n  display: flex;\n  align-items: center;\n  gap: 6px;\n}\n.hydra-sp-body p {\n  font-family: \'DM Sans\', sans-serif !important;\n  font-size: 13px !important;\n  color: #5E7580 !important;\n  line-height: 1.6 !important;\n  margin: 10px 0 0 !important;\n  flex-grow: 1;\n}\n\n/* Keyword chips */\n.hydra-sp-chips {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 5px;\n}\n.hydra-chip {\n  display: inline-flex;\n  align-items: center;\n  gap: 4px;\n  font-family: \'DM Sans\', sans-serif;\n  font-size: 11px;\n  border-radius: 4px;\n  padding: 3px 8px;\n  line-height: 1.4;\n  white-space: nowrap;\n}\n.hydra-chip--h1 {\n  background: #E0F4F7;\n  color: #014F59;\n  border: 1px solid #b0dfe5;\n}\n.hydra-chip--h2 {\n  background: #F5F8F9;\n  color: #5E7580;\n  border: 1px solid #dde5e8;\n}\n.hydra-chip-dot {\n  width: 5px;\n  height: 5px;\n  border-radius: 50%;\n  background: #016B7A;\n  flex-shrink: 0;\n  display: inline-block;\n}\n.hydra-chip-dot--gray { background: #8FA6B2; }\n\n/* View page link */\n.hydra-sp-cta {\n  display: block;\n  font-family: \'DM Sans\', sans-serif;\n  font-size: 13px;\n  font-weight: 500;\n  color: #016B7A;\n  margin-top: 14px;\n  transition: color 0.15s;\n}\n.hydra-sp-card:hover .hydra-sp-cta { color: #014F59; }\n\n/* \"New\" badge */\n.hydra-sp-badge {\n  font-family: \'DM Sans\', sans-serif;\n  font-size: 9px;\n  font-weight: 600;\n  background: #016B7A;\n  color: #ffffff;\n  padding: 2px 6px;\n  border-radius: 3px;\n  line-height: 1.3;\n  vertical-align: middle;\n  letter-spacing: 0.3px;\n}\n\n/* Responsive */\n@media (max-width: 1199px) {\n  .hydra-sp-grid { grid-template-columns: repeat(2, 1fr); gap: 20px; }\n}\n@media (max-width: 767px) {\n  .hydra-sp-grid { grid-template-columns: 1fr; gap: 16px; }\n  .hydra-sp-h2   { font-size: clamp(22px, 6vw, 28px); }\n  .hydra-sp-sub  { margin-bottom: 32px; }\n  .hydra-sp-img  { height: 110px; }\n  .hydra-chip    { white-space: normal; }\n}\n\n\n/* ══ WHY HYDRA SECTION */\n.hydra-why-inner{display:flex;align-items:flex-start;gap:48px;}\n.hydra-why-left{flex:0 0 40%;max-width:40%;}\n.hydra-why-right{flex:1 1 60%;}\n.hydra-why-tag{display:block;font-size:11px;color:#016B7A;text-transform:uppercase;letter-spacing:1.5px;font-weight:600;margin-bottom:14px;}\n.hydra-why-h2{font-family:\'DM Serif Display\',serif;font-size:36px;color:#0C1E28;line-height:1.2;font-weight:400;margin:0 0 12px;}\n.hydra-why-para{font-size:14px;color:#5E7580;line-height:1.7;margin:0;}\n.hydra-why-grid{display:grid;grid-template-columns:1fr 1fr;gap:20px;}\n.hydra-why-card{padding:4px;}\n.hydra-why-num{display:block;font-family:\'DM Serif Display\',serif;font-size:28px;color:#016B7A;margin-bottom:8px;line-height:1;}\n.hydra-why-title{display:block;font-size:14px;font-weight:600;color:#0C1E28;margin-bottom:4px;}\n.hydra-why-text{font-size:13px;color:#5E7580;line-height:1.6;margin:4px 0 0;}\n\n@media(max-width:991px){\n  .hydra-why-inner{flex-direction:column;}\n  .hydra-why-left{flex:none;max-width:100%;width:100%;}\n  .hydra-why-right{width:100%;}\n}\n@media(max-width:479px){\n  .hydra-why-h2{font-size:28px;}\n  .hydra-why-grid{grid-template-columns:1fr;}\n}\n\n/* ══ STANDARDS BAR */\n.hydra-stds-inner{display:flex;align-items:center;flex-wrap:nowrap;gap:0;}\n.hydra-stds-label{flex:0 0 auto;font-size:10px;color:rgba(255,255,255,0.35);text-transform:uppercase;letter-spacing:1.5px;margin-right:16px;white-space:nowrap;}\n.hydra-stds-pills{display:flex;flex-wrap:wrap;gap:0;overflow-x:auto;-webkit-overflow-scrolling:touch;scrollbar-width:none;-ms-overflow-style:none;}\n.hydra-stds-pills::-webkit-scrollbar{display:none;}\n.hydra-std-pill{flex:0 0 auto;background:rgba(255,255,255,0.08);border:1px solid rgba(255,255,255,0.15);color:rgba(255,255,255,0.7);border-radius:4px;font-size:11px;padding:5px 12px;margin:3px;white-space:nowrap;}\n\n@media(max-width:767px){\n  .hydra-stds-inner{flex-wrap:nowrap;}\n  .hydra-stds-pills{flex-wrap:nowrap;}\n}\n\n\n/* ══ PROBLEM 1: Hide site title and tagline from header ══ */\n.site-title,\n.site-title a,\n.site-description,\nspan.site-title,\nh1.site-title,\np.site-description {\n  display: none !important;\n  visibility: hidden !important;\n}\n\n/* ══ PROBLEM 2: Services/Products grid — force display:grid ══ */\n.hydra-sp-grid {\n  display: grid !important;\n  grid-template-columns: repeat(3, 1fr) !important;\n  gap: 24px !important;\n}\n@media (max-width: 1024px) {\n  .hydra-sp-grid { grid-template-columns: repeat(2, 1fr) !important; }\n}\n@media (max-width: 640px) {\n  .hydra-sp-grid { grid-template-columns: 1fr !important; }\n}\n\n/* ══ PROBLEM 3: Keyword chips — not links ══ */\n.hydra-chip,\n.hydra-chip--h1,\n.hydra-chip--h2 {\n  display: inline-flex !important;\n  align-items: center !important;\n  gap: 5px !important;\n  padding: 3px 8px 3px 6px !important;\n  border-radius: 4px !important;\n  font-size: 11px !important;\n  font-weight: 500 !important;\n  text-decoration: none !important;\n  margin: 2px 2px 6px !important;\n  cursor: default !important;\n  color: inherit !important;\n  border-width: 1px !important;\n  border-style: solid !important;\n}\n.hydra-chip--h1 {\n  background: #E0F4F7 !important;\n  color: #014F59 !important;\n  border-color: #b0dfe5 !important;\n}\n.hydra-chip--h2 {\n  background: #F5F8F9 !important;\n  color: #5E7580 !important;\n  border-color: #dde5e8 !important;\n}\n.hydra-chip-dot {\n  width: 6px !important;\n  height: 6px !important;\n  border-radius: 50% !important;\n  display: inline-block !important;\n  flex-shrink: 0 !important;\n  background: #016B7A !important;\n}\n.hydra-chip-dot--gray { background: #aabdc4 !important; }\n\n/* ══ PROBLEM 4: Why HYDRA grid responsive override ══ */\n.hydra-why-grid {\n  display: grid !important;\n  grid-template-columns: repeat(2, 1fr) !important;\n  gap: 20px !important;\n}\n@media (max-width: 640px) {\n  .hydra-why-grid { grid-template-columns: 1fr !important; }\n}\n\n/* ══ PROBLEM 5: Industries responsive overrides ══ */\n.hydra-industries {\n  display: grid !important;\n  grid-template-columns: repeat(6, 1fr) !important;\n  gap: 12px !important;\n}\n@media (max-width: 1024px) {\n  .hydra-industries { grid-template-columns: repeat(3, 1fr) !important; }\n}\n@media (max-width: 640px) {\n  .hydra-industries { grid-template-columns: repeat(2, 1fr) !important; }\n}\n','Custom CSS','','inherit','closed','closed','','40-revision-v1','','','2026-05-14 19:40:02','2026-05-14 19:40:02','',40,'http://hydra-compliance.local/?p=86',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (87,0,'2026-05-14 19:40:50','2026-05-14 19:40:50','<!-- wp:group {\"align\":\"full\",\"className\":\"hydra-hero\",\"style\":{\"color\":{\"background\":\"#0C1E28\"},\"spacing\":{\"padding\":{\"top\":\"100px\",\"bottom\":\"100px\",\"left\":\"24px\",\"right\":\"24px\"}}},\"layout\":{\"type\":\"constrained\",\"contentSize\":\"1100px\"}} -->\n<div class=\"wp-block-group alignfull hydra-hero has-background\" style=\"background-color:#0C1E28;padding-top:100px;padding-bottom:100px;padding-left:24px;padding-right:24px\">\n<!-- wp:html --><div class=\"hydra-pill\"><span class=\"hydra-dot\"></span> Jeddah · Riyadh · All of KSA</div><!-- /wp:html -->\n<!-- wp:heading {\"level\":1,\"style\":{\"color\":{\"text\":\"#ffffff\"},\"typography\":{\"fontSize\":\"clamp(36px,5vw,56px)\",\"lineHeight\":\"1.2\",\"fontWeight\":\"400\"},\"spacing\":{\"margin\":{\"top\":\"32px\",\"bottom\":\"20px\"}}}} -->\n<h1 class=\"wp-block-heading\" style=\"color:#ffffff;font-size:clamp(36px,5vw,56px);font-weight:400;line-height:1.2;margin-top:32px;margin-bottom:20px\">Saudi Arabia&#8217;s pharma <em class=\"hydra-gold-italic\">quality &amp; compliance</em> partner</h1>\n<!-- /wp:heading -->\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"rgba(255,255,255,0.65)\"},\"typography\":{\"fontSize\":\"15px\",\"lineHeight\":\"1.8\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"40px\"}}}} -->\n<p style=\"color:rgba(255,255,255,0.65);font-size:15px;line-height:1.8;margin-top:0;margin-bottom:40px\">Temperature mapping · GDP consulting · Validation · Cold chain · QMS — everything your SFDA compliance programme needs, from a single Jeddah-based team.</p>\n<!-- /wp:paragraph -->\n<!-- wp:buttons {\"layout\":{\"type\":\"flex\",\"justifyContent\":\"left\"},\"style\":{\"spacing\":{\"blockGap\":\"16px\",\"margin\":{\"top\":\"0\",\"bottom\":\"48px\"}}}} -->\n<div class=\"wp-block-buttons\">\n<!-- wp:button {\"style\":{\"color\":{\"background\":\"#016B7A\",\"text\":\"#ffffff\"},\"border\":{\"radius\":\"6px\"},\"spacing\":{\"padding\":{\"top\":\"14px\",\"bottom\":\"14px\",\"left\":\"32px\",\"right\":\"32px\"}}}} -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"/services/\" style=\"background-color:#016B7A;color:#fff;border-radius:6px;padding:14px 32px\">Explore our services</a></div>\n<!-- /wp:button -->\n<!-- wp:button {\"style\":{\"color\":{\"text\":\"#ffffff\"},\"border\":{\"color\":\"rgba(255,255,255,0.5)\",\"width\":\"2px\",\"radius\":\"6px\"},\"spacing\":{\"padding\":{\"top\":\"14px\",\"bottom\":\"14px\",\"left\":\"32px\",\"right\":\"32px\"}}}} -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"tel:+966\" style=\"color:#fff;border:2px solid rgba(255,255,255,0.5);border-radius:6px;padding:14px 32px;background:transparent\">Call us now</a></div>\n<!-- /wp:button -->\n</div>\n<!-- /wp:buttons -->\n<!-- wp:html --><div class=\"hydra-badges\"><span>SFDA Aligned</span><span>WHO GDP</span><span>EU GDP</span><span>ISO&nbsp;9001:2015</span><span>GAMP&nbsp;5</span></div><!-- /wp:html -->\n</div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"align\":\"full\",\"className\":\"hydra-stats-bar\",\"style\":{\"border\":{\"top\":{\"color\":\"#E0EAF0\",\"style\":\"solid\",\"width\":\"1px\"},\"bottom\":{\"color\":\"#E0EAF0\",\"style\":\"solid\",\"width\":\"1px\"}},\"spacing\":{\"padding\":{\"top\":\"56px\",\"bottom\":\"56px\",\"left\":\"24px\",\"right\":\"24px\"}}},\"backgroundColor\":\"white\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"1100px\"}} -->\n<div class=\"wp-block-group alignfull hydra-stats-bar has-white-background-color has-background\" style=\"border-top:1px solid #E0EAF0;border-bottom:1px solid #E0EAF0;padding-top:56px;padding-bottom:56px;padding-left:24px;padding-right:24px\">\n<!-- wp:columns {\"isStackedOnMobile\":true,\"style\":{\"spacing\":{\"blockGap\":\"0\"}}} -->\n<div class=\"wp-block-columns\">\n<!-- wp:column {\"style\":{\"border\":{\"right\":{\"color\":\"#E0EAF0\",\"style\":\"solid\",\"width\":\"1px\"}},\"spacing\":{\"padding\":{\"top\":\"0\",\"bottom\":\"0\",\"left\":\"0\",\"right\":\"32px\"}}}} -->\n<div class=\"wp-block-column\" style=\"border-right:1px solid #E0EAF0;padding-right:32px\">\n<!-- wp:heading {\"level\":3,\"style\":{\"color\":{\"text\":\"#016B7A\"},\"typography\":{\"fontSize\":\"44px\",\"fontFamily\":\"\'DM Serif Display\',serif\",\"fontWeight\":\"400\",\"lineHeight\":\"1\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"6px\"}}}} --><h3 class=\"wp-block-heading\" style=\"color:#016B7A;font-family:\'DM Serif Display\',serif;font-size:44px;font-weight:400;line-height:1;margin-top:0;margin-bottom:6px\">200+</h3><!-- /wp:heading -->\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#5E7580\"},\"typography\":{\"fontSize\":\"14px\"},\"spacing\":{\"margin\":{\"top\":\"0\"}}}} --><p style=\"color:#5E7580;font-size:14px;margin-top:0\">Pharma clients across KSA</p><!-- /wp:paragraph -->\n</div><!-- /wp:column -->\n<!-- wp:column {\"style\":{\"border\":{\"right\":{\"color\":\"#E0EAF0\",\"style\":\"solid\",\"width\":\"1px\"}},\"spacing\":{\"padding\":{\"top\":\"0\",\"bottom\":\"0\",\"left\":\"32px\",\"right\":\"32px\"}}}} -->\n<div class=\"wp-block-column\" style=\"border-right:1px solid #E0EAF0;padding-left:32px;padding-right:32px\">\n<!-- wp:heading {\"level\":3,\"style\":{\"color\":{\"text\":\"#016B7A\"},\"typography\":{\"fontSize\":\"44px\",\"fontFamily\":\"\'DM Serif Display\',serif\",\"fontWeight\":\"400\",\"lineHeight\":\"1\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"6px\"}}}} --><h3 class=\"wp-block-heading\" style=\"color:#016B7A;font-family:\'DM Serif Display\',serif;font-size:44px;font-weight:400;line-height:1;margin-top:0;margin-bottom:6px\">15+</h3><!-- /wp:heading -->\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#5E7580\"},\"typography\":{\"fontSize\":\"14px\"},\"spacing\":{\"margin\":{\"top\":\"0\"}}}} --><p style=\"color:#5E7580;font-size:14px;margin-top:0\">Years combined experience</p><!-- /wp:paragraph -->\n</div><!-- /wp:column -->\n<!-- wp:column {\"style\":{\"border\":{\"right\":{\"color\":\"#E0EAF0\",\"style\":\"solid\",\"width\":\"1px\"}},\"spacing\":{\"padding\":{\"top\":\"0\",\"bottom\":\"0\",\"left\":\"32px\",\"right\":\"32px\"}}}} -->\n<div class=\"wp-block-column\" style=\"border-right:1px solid #E0EAF0;padding-left:32px;padding-right:32px\">\n<!-- wp:heading {\"level\":3,\"style\":{\"color\":{\"text\":\"#016B7A\"},\"typography\":{\"fontSize\":\"44px\",\"fontFamily\":\"\'DM Serif Display\',serif\",\"fontWeight\":\"400\",\"lineHeight\":\"1\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"6px\"}}}} --><h3 class=\"wp-block-heading\" style=\"color:#016B7A;font-family:\'DM Serif Display\',serif;font-size:44px;font-weight:400;line-height:1;margin-top:0;margin-bottom:6px\">9</h3><!-- /wp:heading -->\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#5E7580\"},\"typography\":{\"fontSize\":\"14px\"},\"spacing\":{\"margin\":{\"top\":\"0\"}}}} --><p style=\"color:#5E7580;font-size:14px;margin-top:0\">Core compliance services</p><!-- /wp:paragraph -->\n</div><!-- /wp:column -->\n<!-- wp:column {\"style\":{\"spacing\":{\"padding\":{\"top\":\"0\",\"bottom\":\"0\",\"left\":\"32px\",\"right\":\"0\"}}}} -->\n<div class=\"wp-block-column\" style=\"padding-left:32px\">\n<!-- wp:heading {\"level\":3,\"style\":{\"color\":{\"text\":\"#016B7A\"},\"typography\":{\"fontSize\":\"44px\",\"fontFamily\":\"\'DM Serif Display\',serif\",\"fontWeight\":\"400\",\"lineHeight\":\"1\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"6px\"}}}} --><h3 class=\"wp-block-heading\" style=\"color:#016B7A;font-family:\'DM Serif Display\',serif;font-size:44px;font-weight:400;line-height:1;margin-top:0;margin-bottom:6px\">48hr</h3><!-- /wp:heading -->\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#5E7580\"},\"typography\":{\"fontSize\":\"14px\"},\"spacing\":{\"margin\":{\"top\":\"0\"}}}} --><p style=\"color:#5E7580;font-size:14px;margin-top:0\">Typical quote turnaround</p><!-- /wp:paragraph -->\n</div><!-- /wp:column -->\n</div><!-- /wp:columns -->\n</div>\n<!-- /wp:group -->\n\n\n<!-- wp:group {\"align\":\"full\",\"className\":\"hydra-sp-section\",\"style\":{\"color\":{\"background\":\"#ffffff\"},\"spacing\":{\"padding\":{\"top\":\"80px\",\"bottom\":\"80px\",\"left\":\"5%\",\"right\":\"5%\"}}},\"layout\":{\"type\":\"constrained\",\"contentSize\":\"1280px\"}} -->\n<div class=\"wp-block-group alignfull hydra-sp-section has-background\" style=\"background-color:#ffffff;padding-top:80px;padding-bottom:80px;padding-left:5%;padding-right:5%\">\n\n<!-- wp:html -->\n<div class=\"hydra-sp-inner\">\n\n  <div class=\"hydra-sp-label\">SERVICES &amp; PRODUCTS &mdash; 9 PAGES</div>\n\n  <h2 class=\"hydra-sp-h2\">Everything HYDRA offers</h2>\n\n  <p class=\"hydra-sp-sub\">Each page targets one primary keyword. Click any card to view the full page.</p>\n\n  <div class=\"hydra-sp-grid\">\n\n    <!-- Card 1: Temperature Mapping -->\n    <a href=\"/services/temperature-mapping-saudi-arabia/\" class=\"hydra-sp-card\">\n      <div class=\"hydra-sp-img\" style=\"background:#E8F4F8\">\n        <svg width=\"48\" height=\"48\" viewBox=\"0 0 48 48\" fill=\"none\" stroke=\"#016B7A\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><rect x=\"5\" y=\"28\" width=\"9\" height=\"13\" rx=\"1.5\"/><rect x=\"19.5\" y=\"18\" width=\"9\" height=\"23\" rx=\"1.5\"/><circle cx=\"37\" cy=\"15\" r=\"8\"/><polyline points=\"37,11 37,15 40,17\"/></svg>      </div>\n      <div class=\"hydra-sp-body\">\n        <h3>Temperature Mapping</h3>\n        <div class=\"hydra-sp-chips\">\n          <span class=\"hydra-chip hydra-chip--h1\"><span class=\"hydra-chip-dot\"></span>temperature mapping services Saudi Arabia</span>\n          <span class=\"hydra-chip hydra-chip--h2\"><span class=\"hydra-chip-dot hydra-chip-dot--gray\"></span>warehouse temperature mapping</span>\n        </div>\n        <p>Warehouse, cold room