ck-button__link wp-element-button\" href=\"tel:+966\" style=\"color:#fff;border:2px solid rgba(255,255,255,0.45);border-radius:6px;padding:12px 28px;font-size:14px;background:transparent\">+966 — — — — —</a></div>\n<!-- /wp:button -->\n</div>\n<!-- /wp:buttons -->\n</div>\n<!-- /wp:group -->\n\n<!-- ── SECTION 3: CONTENT + SIDEBAR ─────────────────────────────────────── -->\n<!-- wp:group {\"align\":\"full\",\"style\":{\"color\":{\"background\":\"#F5F8F9\"},\"spacing\":{\"padding\":{\"top\":\"64px\",\"bottom\":\"64px\",\"left\":\"24px\",\"right\":\"24px\"}}},\"layout\":{\"type\":\"constrained\",\"contentSize\":\"1100px\"}} -->\n<div class=\"wp-block-group alignfull has-background\" style=\"background-color:#F5F8F9;padding-top:64px;padding-bottom:64px;padding-left:24px;padding-right:24px\">\n<!-- wp:columns {\"isStackedOnMobile\":true,\"style\":{\"spacing\":{\"blockGap\":\"48px\"}}} -->\n<div class=\"wp-block-columns\">\n\n<!-- LEFT: main content -->\n<!-- wp:column {\"width\":\"65%\"} -->\n<div class=\"wp-block-column hydra-svc-content\" style=\"flex-basis:65%\">\n\n<!-- wp:heading {\"level\":2,\"style\":{\"color\":{\"text\":\"#0C1E28\"},\"typography\":{\"fontSize\":\"clamp(22px,3vw,30px)\",\"fontFamily\":\"\'DM Serif Display\',serif\",\"fontWeight\":\"400\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"16px\"}}}} -->\n<h2 class=\"wp-block-heading\" style=\"color:#0C1E28;font-family:\'DM Serif Display\',serif;font-size:clamp(22px,3vw,30px);font-weight:400;margin-top:0;margin-bottom:16px\">Temperature data logger Saudi Arabia</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#3D5460\"},\"typography\":{\"fontSize\":\"15px\",\"lineHeight\":\"1.8\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"20px\"}}}} -->\n<p style=\"color:#3D5460;font-size:15px;line-height:1.8;margin-top:0;margin-bottom:20px\">A temperature data logger is an electronic device that records temperature readings at set intervals and stores the data for download and analysis. For pharmaceutical companies in Saudi Arabia, SFDA and WHO GDP require temperature data loggers in all storage and transport operations — with calibration certificates traceable to national standards.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":2,\"style\":{\"color\":{\"text\":\"#0C1E28\"},\"typography\":{\"fontSize\":\"clamp(20px,2.5vw,26px)\",\"fontFamily\":\"\'DM Serif Display\',serif\",\"fontWeight\":\"400\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"16px\"}}}} -->\n<h2 class=\"wp-block-heading\" style=\"color:#0C1E28;font-family:\'DM Serif Display\',serif;font-size:clamp(20px,2.5vw,26px);font-weight:400;margin-top:0;margin-bottom:16px\">What HYDRA supplies</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#3D5460\"},\"typography\":{\"fontSize\":\"15px\",\"lineHeight\":\"1.8\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"16px\"}}}} -->\n<p style=\"color:#3D5460;font-size:15px;line-height:1.8;margin-top:0;margin-bottom:16px\">HYDRA supplies pharma-grade temperature data loggers calibrated to ISO 17025 with traceable certificates accepted by SFDA inspectors. All units come with 21 CFR Part 11 compliant PDF reports and are ready for use in GDP-regulated operations.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:html -->\n<div class=\"hydra-equip-grid\">\n  <div class=\"hydra-equip-card\"><span class=\"hydra-equip-icon\">📊</span><span class=\"hydra-equip-name\">USB Single-Use Logger</span></div>\n  <div class=\"hydra-equip-card\"><span class=\"hydra-equip-icon\">📡</span><span class=\"hydra-equip-name\">Multi-Use Wireless Logger</span></div>\n  <div class=\"hydra-equip-card\"><span class=\"hydra-equip-icon\">💧</span><span class=\"hydra-equip-name\">Humidity + Temperature Combo</span></div>\n  <div class=\"hydra-equip-card\"><span class=\"hydra-equip-icon\">📱</span><span class=\"hydra-equip-name\">Cloud-Connected Logger</span></div>\n</div>\n<!-- /wp:html -->\n\n<!-- wp:spacer {\"height\":\"20px\"} --><div style=\"height:20px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div><!-- /wp:spacer -->\n\n<!-- wp:html -->\n<ul class=\"hydra-checklist\">\n  <li>ISO 17025 calibration certificate with every unit</li>\n  <li>Temperature range: -40°C to +85°C</li>\n  <li>Accuracy: ±0.3°C / ±2% RH</li>\n  <li>21 CFR Part 11 compliant PDF alarm reports</li>\n  <li>SFDA GDP accepted documentation</li>\n  <li>Same-day calibration available in Jeddah</li>\n</ul>\n<!-- /wp:html -->\n\n<!-- wp:spacer {\"height\":\"32px\"} --><div style=\"height:32px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div><!-- /wp:spacer -->\n\n<!-- wp:heading {\"level\":2,\"style\":{\"color\":{\"text\":\"#0C1E28\"},\"typography\":{\"fontSize\":\"clamp(20px,2.5vw,26px)\",\"fontFamily\":\"\'DM Serif Display\',serif\",\"fontWeight\":\"400\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"16px\"}}}} -->\n<h2 class=\"wp-block-heading\" style=\"color:#0C1E28;font-family:\'DM Serif Display\',serif;font-size:clamp(20px,2.5vw,26px);font-weight:400;margin-top:0;margin-bottom:16px\">Pharmaceutical data logger requirements</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#3D5460\"},\"typography\":{\"fontSize\":\"15px\",\"lineHeight\":\"1.8\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"16px\"}}}} -->\n<p style=\"color:#3D5460;font-size:15px;line-height:1.8;margin-top:0;margin-bottom:16px\">SFDA GDP guidelines require that every pharmaceutical storage facility and transport vehicle uses a calibrated temperature data logger with a valid calibration certificate. Calibration must be traceable to national standards and renewed at least annually. HYDRA handles supply, initial calibration, and annual recalibration under one service contract.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:html -->\n<ul class=\"hydra-checklist\">\n  <li>Annual recalibration service available</li>\n  <li>Calibration certificate traceable to SASO standards</li>\n  <li>Full calibration history documentation</li>\n  <li>Reminder service for certificate expiry</li>\n</ul>\n<!-- /wp:html -->\n\n<!-- wp:spacer {\"height\":\"32px\"} --><div style=\"height:32px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div><!-- /wp:spacer -->\n\n<!-- wp:heading {\"level\":2,\"style\":{\"color\":{\"text\":\"#0C1E28\"},\"typography\":{\"fontSize\":\"clamp(20px,2.5vw,26px)\",\"fontFamily\":\"\'DM Serif Display\',serif\",\"fontWeight\":\"400\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"16px\"}}}} -->\n<h2 class=\"wp-block-heading\" style=\"color:#0C1E28;font-family:\'DM Serif Display\',serif;font-size:clamp(20px,2.5vw,26px);font-weight:400;margin-top:0;margin-bottom:16px\">ISO 17025 data logger calibration</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#3D5460\"},\"typography\":{\"fontSize\":\"15px\",\"lineHeight\":\"1.8\"},\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"16px\"}}}} -->\n<p style=\"color:#3D5460;font-size:15px;line-height:1.8;margin-top:0;margin-bottom:16px\">HYDRA performs ISO 17025 accredited calibration for all temperature data logger models. Calibration is carried out at our Jeddah lab or on-site at your facility — typically completed same day or within 24 hours. Certificates are issued in both Arabic and English and accepted by SFDA, NUPCO, and major hospital procurement teams.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:html -->\n<table class=\"hydra-specs-table\">\n  <tbody>\n    <tr><td>Temperature range</td><td>-40°C to +85°C</td></tr>\n    <tr><td>Humidity range</td><td>0% to 100% RH</td></tr>\n    <tr><td>Accuracy</td><td>±0.3°C / ±2% RH</td></tr>\n    <tr><td>Compliance</td><td>21 CFR Part 11, ISO 17025</td></tr>\n    <tr><td>Models</td><td>USB single-use · Multi-use wireless</td></tr>\n    <tr><td>Certificate language</td><td>Arabic &amp; English</td></tr>\n    <tr><td>Delivery</td><td>Same day in Jeddah, 1–3 days KSA-wide</td></tr>\n  </tbody>\n</table>\n<!-- /wp:html -->\n\n</div>\n<!-- /wp:column -->\n